function pickFirstString(...values) {
  for (const value of values) {
    const token = String(value || '').trim();
    if (token) return token;
  }
  return '';
}

function tryParseRoutineObject(value) {
  if (!value) return null;
  if (isPlainObject(value)) return value;
  if (typeof value !== 'string') return null;
  const raw = String(value || '').trim();
  if (!raw) return null;
  try {
    const parsed = JSON.parse(raw);
    return isPlainObject(parsed) ? parsed : null;
  } catch {
    return null;
  }
}

function hasRoutineData(profile) {
  const p = isPlainObject(profile) ? profile : {};
  const routine = tryParseRoutineObject(p.currentRoutine) || tryParseRoutineObject(p.current_routine);
  if (!routine) return false;
  const am = Array.isArray(routine.am) ? routine.am : Array.isArray(routine.am_steps) ? routine.am_steps : [];
  const pm = Array.isArray(routine.pm) ? routine.pm : Array.isArray(routine.pm_steps) ? routine.pm_steps : [];
  const hasFilled = (rows) =>
    rows.some((row) => {
      if (!row) return false;
      if (typeof row === 'string') return Boolean(String(row).trim());
      if (!isPlainObject(row)) return false;
      return Boolean(
        String(row.product || '').trim() ||
          String(row.name || '').trim() ||
          String(row.step || '').trim() ||
          String(row.ingredient || '').trim(),
      );
    });
  return hasFilled(am) || hasFilled(pm);
}

function deriveRoutineMissingFields(profile) {
  const p = isPlainObject(profile) ? profile : {};
  const routine = tryParseRoutineObject(p.currentRoutine) || tryParseRoutineObject(p.current_routine);
  if (!routine) return ['currentRoutine.am', 'currentRoutine.pm'];
  const am = Array.isArray(routine.am) ? routine.am : Array.isArray(routine.am_steps) ? routine.am_steps : [];
  const pm = Array.isArray(routine.pm) ? routine.pm : Array.isArray(routine.pm_steps) ? routine.pm_steps : [];
  const hasFilled = (rows) =>
    rows.some((row) => {
      if (!row) return false;
      if (typeof row === 'string') return Boolean(String(row).trim());
      if (!isPlainObject(row)) return false;
      return Boolean(String(row.product || '').trim() || String(row.name || '').trim() || String(row.step || '').trim());
    });
  const missing = [];
  if (!hasFilled(am)) missing.push('currentRoutine.am');
  if (!hasFilled(pm)) missing.push('currentRoutine.pm');
  return missing.length ? missing : [];
}

function normalizeRoutineIntakeSlot(rawSlot) {
  const token = String(rawSlot || '').trim().toLowerCase();
  if (!token) return 'am';
  if (['am', 'morning', 'day', 'daytime', '早', '早上'].includes(token)) return 'am';
  if (['pm', 'night', 'evening', 'bedtime', '晚', '晚上'].includes(token)) return 'pm';
  return token.includes('pm') || token.includes('night') || token.includes('evening') ? 'pm' : 'am';
}

function normalizeRoutineIntakeStep(rawStep) {
  const token = String(rawStep || '').trim().toLowerCase();
  if (!token) return 'other';
  if (/(cleanser|cleanse|wash|face wash|洁面|洗面|清洁)/i.test(token)) return 'cleanser';
  if (/(treatment|active|serum|essence|retinol|acid|bha|aha|niacinamide|vitamin c|精华|活性|酸|维a|维A|烟酰胺|壬二酸)/i.test(token)) return 'treatment';
  if (/(moistur|cream|lotion|gel|balm|面霜|乳液|保湿|修护霜|凝霜)/i.test(token)) return 'moisturizer';
  if (/(spf|sunscreen|sun screen|uv|防晒)/i.test(token)) return 'spf';
  return token;
}

function extractFirstHttpUrlFromText(rawText) {
  const text = String(rawText || '').trim();
  if (!text) return '';
  const matched = text.match(/https?:\/\/[^\s)>\]}]+/i);
  if (!matched || !matched[0]) return '';
  const normalized = String(matched[0]).trim().replace(/[),.;!?]+$/g, '');
  return /^https?:\/\/\S+/i.test(normalized) ? normalized : '';
}

function buildRoutineProductParsedHint(entry, { inputText = '', inputUrl = '', inciHint = '' } = {}) {
  const row = isPlainObject(entry) ? entry : null;
  const url = String(inputUrl || '').trim();
  const brand = pickFirstTrimmed(row?.brand, row?.brand_name, row?.brandName);
  const name = pickFirstTrimmed(row?.name, row?.display_name, row?.displayName, row?.title);
  const skuId = pickFirstTrimmed(row?.sku_id, row?.skuId);
  const productId = pickFirstTrimmed(row?.product_id, row?.productId, skuId);
  const displayName = pickFirstTrimmed(row?.display_name, row?.displayName, joinBrandAndName(brand, name), name, inputText);
  const hint = {
    ...(productId ? { product_id: productId } : {}),
    ...(skuId ? { sku_id: skuId } : {}),
    ...(brand ? { brand } : {}),
    ...(name ? { name } : {}),
    ...(displayName ? { display_name: displayName } : {}),
    ...(url ? { url } : {}),
    ...(inciHint ? { inci: String(inciHint).trim().slice(0, 1400) } : {}),
    category: 'product',
  };
  return Object.keys(hint).length > 1 ? hint : null;
}

function buildRoutineProductCandidateFromRow(row, { slot, step, rank }) {
  const rowObj = isPlainObject(row) ? row : null;
  const rawText = typeof row === 'string'
    ? row
    : pickFirstTrimmed(
      rowObj?.product,
      rowObj?.name,
      rowObj?.display_name,
      rowObj?.displayName,
      rowObj?.title,
      rowObj?.text,
      rowObj?.value,
    );
  const cleanedText = String(rawText || '').trim();
  const explicitUrl = pickFirstTrimmed(
    rowObj?.url,
    rowObj?.link,
    rowObj?.href,
    rowObj?.product_url,
    rowObj?.productUrl,
    rowObj?.purchase_path,
    rowObj?.purchasePath,
  );
  const inferredUrl = extractFirstHttpUrlFromText(cleanedText);
  const productUrl = /^https?:\/\/\S+/i.test(explicitUrl)
    ? explicitUrl
    : /^https?:\/\/\S+/i.test(inferredUrl)
      ? inferredUrl
      : '';
  const inciHint = pickFirstTrimmed(
    rowObj?.inci,
    rowObj?.ingredients,
    rowObj?.ingredient_list,
    rowObj?.ingredientList,
    rowObj?.ingredients_text,
    rowObj?.ingredientsText,
  );
  const textWithoutUrl = productUrl ? cleanedText.replace(productUrl, ' ').replace(/\s+/g, ' ').trim() : cleanedText;
  const productText = String(textWithoutUrl || cleanedText || '').trim().slice(0, 520);
  const lowerText = productText.toLowerCase();
  if (!productText && !productUrl) return null;
  if (['none', 'n/a', 'na', 'skip', '无', '没有', '不使用', '不用'].includes(lowerText)) return null;

  const parsedProductHint = buildRoutineProductParsedHint(rowObj, {
    inputText: productText || productUrl,
    inputUrl: productUrl,
    inciHint,
  });
  return {
    slot: normalizeRoutineIntakeSlot(slot),
    step: normalizeRoutineIntakeStep(step || rowObj?.step || ''),
    rank: Number.isFinite(Number(rank)) ? Math.trunc(Number(rank)) : 0,
    product_text: productText || productUrl,
    product_url: productUrl,
    inci_hint: inciHint ? String(inciHint).trim().slice(0, 1400) : '',
    parsed_product_hint: parsedProductHint,
  };
}

function extractRoutineProductCandidatesForDeepScan(routineInput, { maxTotal = AURORA_ROUTINE_PRODUCT_AUTOSCAN_TOTAL_LIMIT } = {}) {
  const routine = tryParseRoutineObject(routineInput) ||
    (isPlainObject(routineInput) ? routineInput : null);
  if (!routine) return [];

  const out = [];
  const seen = new Set();
  const slotOrder = { am: 0, pm: 1 };
  const stepOrder = {
    cleanser: 0,
    toner: 1,
    treatment: 2,
    essence: 3,
    moisturizer: 4,
    spf: 5,
    sunscreen: 5,
    other: 9,
  };

  const addCandidate = (candidate) => {
    const row = candidate && typeof candidate === 'object' ? candidate : null;
    if (!row || !row.product_text) return;
    const key = [
      row.slot || '',
      row.step || '',
      String(row.product_url || '').toLowerCase(),
      String(row.product_text || '').toLowerCase(),
    ].join('|');
    if (!key || seen.has(key)) return;
    seen.add(key);
    out.push(row);
  };

  const consumeRow = (row, { slot, step, rank }) => {
    const candidate = buildRoutineProductCandidateFromRow(row, { slot, step, rank });
    if (!candidate) return;
    addCandidate(candidate);
  };

  const consumeStepObject = (obj, { slot, baseRank = 0 }) => {
    const rowObj = isPlainObject(obj) ? obj : null;
    if (!rowObj) return;
    const keys = Object.keys(rowObj);
    const looksLikeSingleProductRow =
      keys.some((k) => ['product', 'name', 'display_name', 'displayName', 'url', 'link', 'href'].includes(String(k || ''))) ||
      keys.includes('step');
    if (looksLikeSingleProductRow) {
      consumeRow(rowObj, {
        slot,
        step: rowObj.step || rowObj.role || 'other',
        rank: baseRank,
      });
      return;
    }
    let offset = 0;
    for (const [rawStep, rawValue] of Object.entries(rowObj)) {
      if (rawValue == null) continue;
      if (typeof rawValue === 'string') {
        consumeRow({ product: rawValue }, { slot, step: rawStep, rank: baseRank + offset });
        offset += 1;
        continue;
      }
      if (Array.isArray(rawValue)) {
        rawValue.forEach((entry, idx) => {
          consumeRow(entry, { slot, step: rawStep, rank: baseRank + offset + idx });
        });
        offset += rawValue.length;
        continue;
      }
      if (isPlainObject(rawValue)) {
        consumeRow(rawValue, { slot, step: rawStep, rank: baseRank + offset });
        offset += 1;
      }
    }
  };

  const slotSources = [
    { slot: 'am', keys: ['am', 'am_steps', 'morning'] },
    { slot: 'pm', keys: ['pm', 'pm_steps', 'evening', 'night'] },
  ];
  let rankCounter = 0;
  for (const source of slotSources) {
    for (const key of source.keys) {
      const value = routine[key];
      if (value == null) continue;
      if (Array.isArray(value)) {
        value.forEach((entry, idx) => consumeRow(entry, { slot: source.slot, step: isPlainObject(entry) ? entry.step : '', rank: rankCounter + idx }));
        rankCounter += value.length;
        continue;
      }
      if (typeof value === 'string') {
        consumeRow({ product: value }, { slot: source.slot, step: 'other', rank: rankCounter });
        rankCounter += 1;
        continue;
      }
      consumeStepObject(value, { slot: source.slot, baseRank: rankCounter });
      rankCounter += 4;
    }
  }

  // Fallback: some clients may send a flat array/object outside am/pm.
  if (!out.length) {
    if (Array.isArray(routineInput)) {
      routineInput.forEach((entry, idx) => {
        const slot = isPlainObject(entry) ? entry.slot || entry.period || 'am' : 'am';
        consumeRow(entry, { slot, step: isPlainObject(entry) ? entry.step || 'other' : 'other', rank: idx });
      });
    } else if (isPlainObject(routineInput)) {
      consumeStepObject(routineInput, { slot: 'am', baseRank: 0 });
    }
  }

  const capped = out
    .sort((a, b) => {
      const slotCmp = (slotOrder[a.slot] ?? 8) - (slotOrder[b.slot] ?? 8);
      if (slotCmp !== 0) return slotCmp;
      const stepCmp = (stepOrder[a.step] ?? 9) - (stepOrder[b.step] ?? 9);
      if (stepCmp !== 0) return stepCmp;
      return (a.rank || 0) - (b.rank || 0);
    })
    .slice(0, Math.max(1, Math.min(40, Number(maxTotal) || AURORA_ROUTINE_PRODUCT_AUTOSCAN_TOTAL_LIMIT)));
  return capped;
}

function buildRoutineProductAnalysisFallbackPayload({
  language = 'EN',
  candidate = null,
  parsedProduct = null,
  reasonCodes = [],
} = {}) {
  const isCn = String(language || '').toUpperCase() === 'CN';
  const row = candidate && typeof candidate === 'object' ? candidate : {};
  const productName = String(row.product_text || '').trim();
  const missingInfo = Array.from(
    new Set([
      'routine_product_deepscan_degraded',
      'version_verification_needed',
      ...(Array.isArray(reasonCodes) ? reasonCodes : []),
    ].filter(Boolean)),
  );
  const stepLabel = normalizeRoutineIntakeStep(row.step || '');
  const slotLabel = normalizeRoutineIntakeSlot(row.slot || '');
  const timingLabel = isCn
    ? slotLabel === 'pm'
      ? '建议先在夜间低频测试。'
      : '建议先在白天小面积测试。'
    : slotLabel === 'pm'
      ? 'Start with a low-frequency PM patch test.'
      : 'Start with a small daytime patch test.';
  const actionLine = isCn
    ? `先从${stepLabel || '当前步骤'}保守用法开始：2-3 次/周，出现持续刺痛或泛红请暂停并只做修护。`
    : `Use a conservative ${stepLabel || 'current-step'} cadence first: 2-3x/week, and pause if stinging or redness persists.`;

  return {
    assessment: {
      verdict: isCn ? '未知' : 'Unknown',
      reasons: [
        isCn
          ? `暂时无法对「${productName || '该产品'}」完成完整成分判定，我先给你可执行的保守方案。`
          : `I cannot complete a full ingredient-level verdict for "${productName || 'this product'}" right now, so here is a conservative plan.`,
        actionLine,
      ],
      how_to_use: {
        timing: timingLabel,
        frequency: isCn ? '先从每周 2-3 次开始' : 'Start at 2-3 times per week',
        notes: [
          isCn
            ? '若刺痛/发红持续超过 5-10 分钟，暂停该产品并仅保留温和清洁+保湿。'
            : 'If stinging/redness lasts beyond 5-10 minutes, pause this product and keep only gentle cleansing + moisturizer.',
          isCn
            ? '产品版本可能因地区不同而变化，建议核对包装 INCI。'
            : 'Formula may vary by region/version; verify the package INCI.',
        ],
      },
      ...(parsedProduct && typeof parsedProduct === 'object' ? { anchor_product: parsedProduct } : {}),
    },
    evidence: {
      science: { key_ingredients: [], mechanisms: [], fit_notes: [], risk_notes: [] },
      social_signals: { typical_positive: [], typical_negative: [], risk_for_groups: [] },
      expert_notes: [
        isCn ? '当前为降级分析结果（证据不足）。' : 'Degraded analysis result (insufficient evidence).',
      ],
      confidence: 0.32,
      missing_info: ['evidence_missing', ...missingInfo].slice(0, 8),
    },
    confidence: 0.32,
    missing_info: missingInfo,
  };
}

async function deepScanRoutineProductCandidate({
  candidate,
  ctx,
  profileSummary,
  recentLogsSummary = [],
  logger,
  includeCard = true,
} = {}) {
  const row = candidate && typeof candidate === 'object' ? candidate : null;
  if (!row) return { card: null, backfilled: false, failure_reason: 'candidate_missing' };
  const lang = String(ctx && ctx.lang ? ctx.lang : 'EN').toUpperCase() === 'CN' ? 'CN' : 'EN';
  const inputText = String(row.product_text || '').trim();
  const productUrl = /^https?:\/\/\S+/i.test(String(row.product_url || '').trim()) ? String(row.product_url || '').trim() : '';
  if (!inputText && !productUrl) return { card: null, backfilled: false, failure_reason: 'product_input_missing' };

  const profileCtx = isPlainObject(profileSummary) ? profileSummary : {};
  const logsCtx = Array.isArray(recentLogsSummary) ? recentLogsSummary.slice(0, 7) : [];
  let parsedProduct = isPlainObject(row.parsed_product_hint) ? { ...row.parsed_product_hint } : null;
  if (!parsedProduct && productUrl) {
    parsedProduct = buildHeuristicProductFromInput({ inputText, inputUrl: productUrl });
  }
  let anchorId = pickFirstTrimmed(parsedProduct?.sku_id, parsedProduct?.product_id);

  let primaryAnchorResolution = null;
  if (!anchorId && inputText) {
    primaryAnchorResolution = await resolvePrimaryAnalyzeAnchorForProductInput({
      inputText,
      inputUrl: productUrl || null,
      parsedProduct,
      lang,
      logger,
    });
    if (primaryAnchorResolution && primaryAnchorResolution.ok && primaryAnchorResolution.product) {
      const resolvedAnchor = mapCatalogProductToAnchorProduct(primaryAnchorResolution.product, { fallbackName: inputText });
      if (resolvedAnchor) {
        parsedProduct = parsedProduct || resolvedAnchor;
        anchorId = pickFirstTrimmed(resolvedAnchor.sku_id, resolvedAnchor.product_id);
      }
    }
  }

  let catalogFallback = null;
  if (!anchorId && PRODUCT_INTEL_CATALOG_FALLBACK_ENABLED && inputText) {
    catalogFallback = await resolveCatalogProductForProductInput({
      inputText,
      inputUrl: productUrl || null,
      parsedProduct,
      lang,
      logger,
    });
    if (catalogFallback && catalogFallback.ok && catalogFallback.product) {
      const fallbackAnchor = mapCatalogProductToAnchorProduct(catalogFallback.product, { fallbackName: inputText });
      if (fallbackAnchor) {
        parsedProduct = parsedProduct || fallbackAnchor;
        anchorId = pickFirstTrimmed(fallbackAnchor.sku_id, fallbackAnchor.product_id);
      }
    }
  }

  const productDescriptor = buildProductInputText(parsedProduct, productUrl) || inputText || productUrl;
  const contextPrefix = buildContextPrefix({
    profile: profileCtx,
    recentLogs: logsCtx,
    lang,
    state: 'S4_ANALYSIS_LOADING',
    trigger_source: 'routine_autoscan',
    intent: 'routine_product_analyze',
    action_id: 'routine.autoscan.product_analyze',
  });
  const deepScanQuery =
    `${contextPrefix}Task: Deep-scan this product for suitability vs the user's profile.\n` +
    `Return ONLY a JSON object with keys: assessment, evidence, confidence (0..1), missing_info (string[]).\n` +
    `Evidence must include science/social_signals/expert_notes.\n` +
    `If product version cannot be confirmed, explicitly mention version verification is required.\n` +
    `Product: ${productDescriptor}`;

  const runDeepScan = async (queryText, timeoutMs) => {
    try {
      return await auroraChat({
        baseUrl: AURORA_DECISION_BASE_URL,
        query: queryText,
        timeoutMs,
        ...(anchorId ? { anchor_product_id: String(anchorId) } : {}),
        ...(productUrl ? { anchor_product_url: productUrl } : {}),
      });
    } catch {
      return null;
    }
  };

  let norm = { payload: null, field_missing: [] };
  let realtimeUrlNormMeta = null;
  try {
    let upstream = await runDeepScan(deepScanQuery, AURORA_ROUTINE_PRODUCT_AUTOSCAN_TIMEOUT_MS);
    norm = normalizeProductAnalysisFromUpstream(upstream);
    if (!norm.payload?.assessment) {
      const minimalPrefix = buildContextPrefix({
        lang,
        state: 'S4_ANALYSIS_LOADING',
        trigger_source: 'routine_autoscan',
        intent: 'routine_product_analyze_fallback',
        action_id: 'routine.autoscan.product_analyze_fallback',
      });
      const minimalQuery =
        `${minimalPrefix}Task: Deep-scan this product for suitability vs the user's profile.\n` +
        `Return ONLY a JSON object with keys: assessment, evidence, confidence (0..1), missing_info (string[]).\n` +
        `Evidence must include science/social_signals/expert_notes.\n` +
        `If product version cannot be confirmed, explicitly mention version verification is required.\n` +
        `Product: ${productDescriptor}`;
      const upstreamRetry = await runDeepScan(minimalQuery, Math.max(1200, AURORA_ROUTINE_PRODUCT_AUTOSCAN_TIMEOUT_MS - 600));
      const retryNorm = normalizeProductAnalysisFromUpstream(upstreamRetry);
      if (retryNorm.payload?.assessment) norm = retryNorm;
    }

    const needsUrlIngredientAnalysis = (() => {
      const assessment = isPlainObject(norm.payload?.assessment) ? norm.payload.assessment : null;
      if (!assessment) return true;
      const verdict = String(assessment.verdict || '').trim().toLowerCase();
      return !verdict || verdict === 'unknown' || verdict === '未知';
    })();
    if (PRODUCT_URL_INGREDIENT_ANALYSIS_ENABLED && needsUrlIngredientAnalysis && productUrl) {
      const urlNorm = await buildProductAnalysisFromUrlIngredients({
        productUrl,
        lang,
        profileSummary: profileCtx,
        parsedProduct,
        logger,
      });
      if (urlNorm && urlNorm.payload && urlNorm.payload.assessment) {
        realtimeUrlNormMeta = urlNorm.source_meta || null;
        const mergedMissingInfo = Array.from(
          new Set([
            ...(Array.isArray(norm?.payload?.missing_info) ? norm.payload.missing_info : []),
            ...(Array.isArray(urlNorm.payload.missing_info) ? urlNorm.payload.missing_info : []),
          ]),
        );
        const mergedInternalCodes = Array.from(
          new Set([
            ...getProductAnalysisInternalMissingCodes(norm?.payload),
            ...getProductAnalysisInternalMissingCodes(urlNorm.payload),
          ]),
        );
        norm = {
          payload: applyProductAnalysisGapContract({
            ...urlNorm.payload,
            missing_info: mergedMissingInfo,
            internal_debug_codes: mergedInternalCodes,
          }),
          field_missing: mergeFieldMissing(urlNorm.field_missing, norm.field_missing),
        };
      }
    }
  } catch (err) {
    logger?.warn(
      { err: err && err.message ? err.message : String(err), product_text: inputText.slice(0, 120) },
      'aurora bff: routine autoscan deep-scan failed',
    );
  }

  let payload = enrichProductAnalysisPayload(norm.payload, { lang, profileSummary: profileCtx });
  if (catalogFallback && catalogFallback.ok && payload && typeof payload === 'object') {
    const internalCodes = getProductAnalysisInternalMissingCodes(payload);
    payload = applyProductAnalysisGapContract({
      ...payload,
      internal_debug_codes: Array.from(new Set([...internalCodes, `catalog_anchor_fallback_${catalogFallback.source || 'used'}`])),
    });
  }
  if ((!payload || !payload.assessment) && parsedProduct && typeof parsedProduct === 'object') {
    payload = buildRoutineProductAnalysisFallbackPayload({
      language: lang,
      candidate: row,
      parsedProduct,
      reasonCodes: ['upstream_assessment_missing'],
    });
  }
  if ((!payload || !payload.assessment) && !parsedProduct) {
    payload = buildRoutineProductAnalysisFallbackPayload({
      language: lang,
      candidate: row,
      parsedProduct: null,
      reasonCodes: ['upstream_assessment_missing', 'anchor_product_missing'],
    });
  }
  if (payload && typeof payload === 'object' && parsedProduct) {
    const assessment = isPlainObject(payload.assessment) ? payload.assessment : null;
    if (assessment && !assessment.anchor_product && !assessment.anchorProduct) {
      payload = { ...payload, assessment: { ...assessment, anchor_product: parsedProduct } };
    }
  }
  payload = finalizeProductAnalysisRecoContract(payload, {
    logger,
    requestId: ctx && ctx.request_id ? ctx.request_id : 'routine_autoscan',
    mode: 'main_path',
  });
  if (realtimeUrlNormMeta && productUrl) {
    payload = applyProductAnalysisSocialProvenance(payload, {
      social_fetch_mode: 'async_refresh',
    });
  }

  const routineContext = {
    slot: normalizeRoutineIntakeSlot(row.slot),
    step: normalizeRoutineIntakeStep(row.step),
    rank: Number.isFinite(Number(row.rank)) ? Math.trunc(Number(row.rank)) : 0,
    source: 'routine_intake',
  };
  payload = {
    ...payload,
    routine_context: routineContext,
  };

  const assessmentObj = isPlainObject(payload?.assessment) ? payload.assessment : null;
  const kbBackfillAnchor =
    assessmentObj && isPlainObject(assessmentObj.anchor_product)
      ? assessmentObj.anchor_product
      : parsedProduct;
  const keyQuality = resolveProductIntelKbKeyQuality({
    productUrl,
    parsedProduct: kbBackfillAnchor,
    productHint: inputText,
    lang,
  });
  scheduleProductIntelKbBackfill({
    productUrl,
    parsedProduct: kbBackfillAnchor,
    productHint: inputText,
    payload,
    lang,
    source: 'routine_product_deepscan',
    sourceMeta: {
      key_quality: keyQuality,
      routine_slot: routineContext.slot,
      routine_step: routineContext.step,
      routine_rank: routineContext.rank,
      product_input: inputText.slice(0, 240),
      ...(realtimeUrlNormMeta && typeof realtimeUrlNormMeta === 'object' ? { url_realtime_meta: realtimeUrlNormMeta } : {}),
    },
    logger,
  });

  return {
    card: includeCard
      ? {
        card_id: `routine_product_${ctx && ctx.request_id ? ctx.request_id : Date.now()}_${Math.max(0, Number(routineContext.rank) || 0)}`,
        type: 'product_analysis',
        payload,
        ...(Array.isArray(norm.field_missing) && norm.field_missing.length ? { field_missing: norm.field_missing.slice(0, 8) } : {}),
      }
      : null,
    backfilled: true,
    key_quality: keyQuality,
    routine_context: routineContext,
  };
}

function isSkincareCategory(candidate) {
  const row = isPlainObject(candidate) ? candidate : {};
  const joined = [
    row.category,
    row.category_name,
    row.category_path,
    row.product_type,
    row.type,
    row.brand,
    row.name,
    row.title,
    row.display_name,
    row.displayName,
    row.why_match,
    row.why,
    row.tags,
  ]
    .flatMap((value) => (Array.isArray(value) ? value : [value]))
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  if (!joined) return false;
  return PRODUCT_INTEL_SKINCARE_RE.test(joined);
}

function isBlacklistedCategoryOrTitle(candidate) {
  const row = isPlainObject(candidate) ? candidate : {};
  const joined = [
    row.category,
    row.category_name,
    row.category_path,
    row.product_type,
    row.type,
    row.brand,
    row.name,
    row.title,
    row.display_name,
    row.displayName,
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  if (!joined) return false;
  return PRODUCT_INTEL_BLACKLIST_RE.test(joined);
}

function isSearchLikeUrl(url) {
  const value = String(url || '').trim();
  if (!PRODUCT_INTEL_HTTP_URL_RE.test(value)) return false;
  return PRODUCT_INTEL_SEARCH_URL_RE.test(value);
}

function isHttpsUrl(url) {
  return /^https:\/\/\S+/i.test(String(url || '').trim());
}

function buildInternalPdpUrlFromTarget({ productId, merchantId } = {}) {
  const normalizedProductId = String(productId || '').trim();
  if (!normalizedProductId || !AURORA_PIVOTA_SHOP_BASE_URL) return '';
  try {
    const url = new URL(`${AURORA_PIVOTA_SHOP_BASE_URL}/products/${encodeURIComponent(normalizedProductId)}`);
    const normalizedMerchantId = String(merchantId || '').trim();
    if (normalizedMerchantId) url.searchParams.set('merchant_id', normalizedMerchantId);
    url.searchParams.set('entry', 'aurora_chatbox');
    return url.toString();
  } catch {
    return '';
  }
}

function extractCanonicalRefFromProductGroupId(rawGroupId) {
  const groupId = String(rawGroupId || '').trim();
  if (!groupId) return null;
  const tokens = groupId
    .split(':')
    .map((token) => String(token || '').trim())
    .filter(Boolean);
  if (tokens.length < 3) return null;
  if (tokens[0].toLowerCase() !== 'pg') return null;
  const merchantId = tokens[1];
  const productId = tokens.slice(2).join(':');
  return normalizeCanonicalProductRef(
    {
      product_id: productId,
      merchant_id: merchantId,
    },
    { requireMerchant: true, allowOpaqueProductId: false },
  );
}

function deriveInternalPdpUrlFromContract(candidate) {
  const row = isPlainObject(candidate) ? candidate : {};
  const skuCandidate = isPlainObject(row.sku) ? row.sku : isPlainObject(row.product) ? row.product : null;

  const prefetchPayload = extractPdpCorePrefetchPayloadFromItem(row);
  const prefetchRef = normalizeCanonicalProductRef(prefetchPayload?.product_ref, {
    requireMerchant: true,
    allowOpaqueProductId: false,
  });
  if (prefetchRef) {
    const fromPrefetchRef = buildInternalPdpUrlFromTarget({
      productId: prefetchRef.product_id,
      merchantId: prefetchRef.merchant_id,
    });
    if (fromPrefetchRef) return fromPrefetchRef;
  }

  const prefetchSubjectGroupId = pickFirstTrimmed(
    prefetchPayload?.subject?.id,
    prefetchPayload?.subject?.product_group_id,
    prefetchPayload?.subject?.productGroupId,
  );
  const prefetchGroupRef = extractCanonicalRefFromProductGroupId(prefetchSubjectGroupId);
  if (prefetchGroupRef) {
    const fromPrefetchGroup = buildInternalPdpUrlFromTarget({
      productId: prefetchGroupRef.product_id,
      merchantId: prefetchGroupRef.merchant_id,
    });
    if (fromPrefetchGroup) return fromPrefetchGroup;
  }

  const { subjectProductGroupId, directProductRef, rawProductId, rawMerchantId } = extractRecoPdpDirectKeys(row, skuCandidate);
  if (directProductRef) {
    const fromDirectRef = buildInternalPdpUrlFromTarget({
      productId: directProductRef.product_id,
      merchantId: directProductRef.merchant_id,
    });
    if (fromDirectRef) return fromDirectRef;
  }

  const subjectGroupRef = extractCanonicalRefFromProductGroupId(subjectProductGroupId);
  if (subjectGroupRef) {
    const fromSubjectGroup = buildInternalPdpUrlFromTarget({
      productId: subjectGroupRef.product_id,
      merchantId: subjectGroupRef.merchant_id,
    });
    if (fromSubjectGroup) return fromSubjectGroup;
  }

  const fallbackRef = normalizeCanonicalProductRef(
    {
      product_id: rawProductId,
      merchant_id: rawMerchantId,
    },
    { requireMerchant: true, allowOpaqueProductId: false },
  );
  if (fallbackRef) {
    const fromFallbackRef = buildInternalPdpUrlFromTarget({
      productId: fallbackRef.product_id,
      merchantId: fallbackRef.merchant_id,
    });
    if (fromFallbackRef) return fromFallbackRef;
  }

  return '';
}

function extractCandidateOpenUrl(candidate) {
  const row = isPlainObject(candidate) ? candidate : {};
  const sku = isPlainObject(row.sku) ? row.sku : {};
  const product = isPlainObject(row.product) ? row.product : {};
  const pdpOpen = isPlainObject(row.pdp_open) ? row.pdp_open : {};
  const pdpOpenExternal = isPlainObject(pdpOpen.external) ? pdpOpen.external : {};
  const url = pickFirstString(
    row.pdp_url,
    row.url,
    row.link,
    row.product_url,
    row.purchase_path,
    row.purchasePath,
    sku.pdp_url,
    sku.url,
    sku.purchase_path,
    product.pdp_url,
    product.url,
    product.purchase_path,
    pdpOpenExternal.url,
  );
  if (!PRODUCT_INTEL_HTTP_URL_RE.test(url)) {
    const derivedInternalUrl = deriveInternalPdpUrlFromContract(row);
    if (!PRODUCT_INTEL_HTTP_URL_RE.test(derivedInternalUrl)) return '';
    return derivedInternalUrl;
  }
  return url;
}

function normalizeCandidateWithDirectUrl(candidate, directUrl) {
  const row = isPlainObject(candidate) ? { ...candidate } : {};
  const url = String(directUrl || '').trim();
  if (!PRODUCT_INTEL_HTTP_URL_RE.test(url)) return row;
  if (!PRODUCT_INTEL_HTTP_URL_RE.test(String(row.url || '').trim())) {
    row.url = url;
  }
  if (!PRODUCT_INTEL_HTTP_URL_RE.test(String(row.pdp_url || '').trim())) {
    row.pdp_url = url;
  }
  if (!PRODUCT_INTEL_HTTP_URL_RE.test(String(row.product_url || '').trim())) {
    row.product_url = url;
  }
  if (!PRODUCT_INTEL_HTTP_URL_RE.test(String(row.purchase_path || '').trim())) {
    row.purchase_path = url;
  }
  return row;
}

function hasOpenableUrl(candidate) {
  if (extractCandidateOpenUrl(candidate)) return true;
  const row = isPlainObject(candidate) ? candidate : {};
  const pdpOpen = isPlainObject(row.pdp_open) ? row.pdp_open : {};
  const path = String(pdpOpen.path || '').trim().toLowerCase();
  if (path === 'group') {
    const groupId = pickFirstString(row.subject_product_group_id, pdpOpen.product_group_id, pdpOpen.productGroupId);
    return Boolean(groupId);
  }
  if (path === 'ref' || path === 'resolve' || path === 'internal') {
    const ref = isPlainObject(pdpOpen.product_ref) ? pdpOpen.product_ref : {};
    const productId = pickFirstString(ref.product_id, ref.productId, row.product_id, row.productId);
    return Boolean(productId);
  }
  if (path === 'external') {
    const external = isPlainObject(pdpOpen.external) ? pdpOpen.external : {};
    if (PRODUCT_INTEL_HTTP_URL_RE.test(String(external.url || '').trim())) return true;
    return Boolean(String(external.query || '').trim());
  }
  return false;
}

function buildProductRelevanceDualQaPrompt(candidate) {
  const row = isPlainObject(candidate) ? candidate : {};
  const payload = {
    name: pickFirstString(row.name, row.title, row.display_name, row.displayName),
    brand: pickFirstString(row.brand),
    category: pickFirstString(row.category, row.category_name, row.product_type, row.type),
    why_match: pickFirstString(row.why_match, row.why),
    ingredient_name: pickFirstString(row.ingredient_name),
    url: extractCandidateOpenUrl(row),
  };
  return JSON.stringify(payload, null, 2);
}

function parseDualQaRelevanceDecision(obj) {
  const row = isPlainObject(obj) ? obj : {};
  const relevant = row.relevant === true;
  const category = String(row.category || '').trim().toLowerCase();
  const reason = pickFirstString(row.reason, row.rationale);
  return {
    relevant,
    category,
    reason,
  };
}

function shouldRunDualQaForCandidate({ skincareHit, blacklistHit, joined }) {
  if (blacklistHit) return false;
  const hasSkincareHints = PRODUCT_INTEL_SKINCARE_RE.test(joined);
  const hasStrongNonSkincareHints = /(fashion|apparel|clothing|jewelry|wallet|watch|bag|gift|brush|tool|lingerie)/i.test(joined);
  if (skincareHit && hasSkincareHints && !hasStrongNonSkincareHints) return false;
  return true;
}

async function evaluateIngredientCandidateWithQaMode(
  candidate,
  {
    qaMode = AURORA_PRODUCT_RELEVANCE_QA_MODE,
    singleProvider = AURORA_LLM_SINGLE_PROVIDER,
    allowOpenAiFallback = AURORA_LLM_OPENAI_FALLBACK_ENABLED,
    qaContext = null,
  } = {},
) {
  const row = isPlainObject(candidate) ? candidate : {};
  const joined = [
    row.category,
    row.category_name,
    row.product_type,
    row.type,
    row.name,
    row.title,
    row.display_name,
    row.displayName,
    row.brand,
    row.why_match,
    row.why,
    row.ingredient_name,
  ]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ');
  const voteA = isSkincareCategory(row) && !isBlacklistedCategoryOrTitle(row);
  const voteB =
    PRODUCT_INTEL_SKINCARE_RE.test(joined) &&
    !PRODUCT_INTEL_BLACKLIST_RE.test(joined) &&
    !/(fashion|apparel|clothing|jewelry|wallet|watch|bag|gift)/i.test(joined);
  const heuristicPass = voteA && voteB;
  const blacklistHit = isBlacklistedCategoryOrTitle(row);
  const mode = resolveQaMode(qaMode);
  const normalizedSingleProvider = resolveQaSingleProvider(singleProvider);
  const defaultResult = {
    pass: heuristicPass,
    qa_mode: mode,
    reject_reason: heuristicPass ? null : 'heuristic_relevance_reject',
  };

  if (mode === 'off') {
    markQaContextSkip(qaContext, 'relevance', 'qa_mode_off');
    return defaultResult;
  }
  if (!shouldRunDualQaForCandidate({ skincareHit: voteA, blacklistHit, joined })) return defaultResult;
  if (shouldSkipQaByBudget({ qaContext, stage: 'relevance' })) return defaultResult;

  const cacheKey = buildProductDualQaCacheKey(row);
  const scopedCacheKey = cacheKey ? `${mode}:${normalizedSingleProvider}:${cacheKey}` : '';
  const cached = getProductDualQaCache(scopedCacheKey);
  if (typeof cached === 'boolean') {
    return {
      pass: cached,
      qa_mode: mode,
      reject_reason: cached ? null : mode === 'dual' ? 'dual_llm_relevance_reject' : 'single_llm_relevance_reject',
    };
  }

  const providers = pickQaProvidersForMode({
    mode,
    singleProvider: normalizedSingleProvider,
    allowOpenAiFallback,
  });
  if ((mode === 'dual' && providers.length < 2) || !providers.length) {
    const failClosed = false;
    setProductDualQaCache(scopedCacheKey, failClosed);
    markQaContextSkip(qaContext, 'relevance', 'qa_provider_unavailable');
    return {
      pass: failClosed,
      qa_mode: mode,
      reject_reason: mode === 'dual' ? 'dual_llm_relevance_reject' : 'single_llm_relevance_reject',
    };
  }

  const systemPrompt =
    'You are a product relevance gate for skincare recommendations. Return strict JSON with keys: relevant(boolean), category(string), reason(string).';
  const userPrompt =
    `Task: decide if this candidate is a skincare product suitable for skincare recommendation flow.\n` +
    `Reject non-skincare products such as brushes/tools/apparel.\n` +
    `Candidate:\n${buildProductRelevanceDualQaPrompt(row)}`;

  if (mode === 'single') {
    let parsed = null;
    for (const provider of providers) {
      const vote = await callDualQaProviderImpl({
        provider,
        systemPrompt,
        userPrompt,
        timeoutMs: PRODUCT_INTEL_DUAL_QA_TIMEOUT_MS,
      });
      if (!vote || !vote.ok || !isPlainObject(vote.json)) {
        markQaContextCall(qaContext, 'relevance', provider, 'error');
        continue;
      }
      parsed = parseDualQaRelevanceDecision(vote.json);
      markQaContextCall(qaContext, 'relevance', provider, parsed && parsed.relevant === true ? 'ok' : 'reject');
      if (parsed) break;
    }
    const pass = Boolean(parsed && parsed.relevant === true && parsed.category !== 'non_skincare');
    setProductDualQaCache(scopedCacheKey, pass);
    return {
      pass,
      qa_mode: mode,
      reject_reason: pass ? null : 'single_llm_relevance_reject',
    };
  }

  const [vote1, vote2] = await Promise.all(
    providers
      .slice(0, 2)
      .map((provider) =>
        callDualQaProviderImpl({
          provider,
          systemPrompt,
          userPrompt,
          timeoutMs: PRODUCT_INTEL_DUAL_QA_TIMEOUT_MS,
        }).then((vote) => ({ provider, vote })),
      ),
  );
  const parsed1 = vote1 && vote1.vote && vote1.vote.ok ? parseDualQaRelevanceDecision(vote1.vote.json) : null;
  const parsed2 = vote2 && vote2.vote && vote2.vote.ok ? parseDualQaRelevanceDecision(vote2.vote.json) : null;
  markQaContextCall(
    qaContext,
    'relevance',
    [vote1 && vote1.provider, vote2 && vote2.provider].filter(Boolean).join(','),
    parsed1 && parsed2 ? 'ok' : 'error',
  );

  // Fail-closed by design: require dual-pass consensus.
  const pass = Boolean(
    parsed1 &&
      parsed2 &&
      parsed1.relevant === true &&
      parsed2.relevant === true &&
      parsed1.category !== 'non_skincare' &&
      parsed2.category !== 'non_skincare',
  );
  setProductDualQaCache(scopedCacheKey, pass);
  return {
    pass,
    qa_mode: mode,
    reject_reason: pass ? null : 'dual_llm_relevance_reject',
  };
}

function buildExternalSearchCta(candidate, reason = 'search_fallback') {
  const row = isPlainObject(candidate) ? candidate : {};
  const title = pickFirstString(row.name, row.title, row.display_name, row.displayName, row.product_id, 'Open search result');
  const directUrl = extractCandidateOpenUrl(row);
  const query = pickFirstString(title, row.ingredient_name, row.category, row.brand);
  const url = PRODUCT_INTEL_HTTP_URL_RE.test(directUrl) ? directUrl : buildExternalGoogleSearchUrl(query);
  const source = pickFirstString(row.source, row.brand).toLowerCase() || 'external';
  return {
    title,
    url,
    source,
    reason,
  };
}

function buildStrictFilterFallbackSearchCtas(payload, maxItems = 3) {
  const p = isPlainObject(payload) ? payload : {};
  const science = isPlainObject(p.evidence) && isPlainObject(p.evidence.science) ? p.evidence.science : {};
  const keyIngredients = Array.isArray(science.key_ingredients) ? science.key_ingredients : [];
  const goals = Array.isArray(p.profile && p.profile.goals) ? p.profile.goals : [];
  const seed = [...keyIngredients, ...goals]
    .map((value) => String(value || '').trim())
    .filter(Boolean)
    .join(' ')
    .toLowerCase();

  const queryCandidates = [];
  const pushQuery = (query) => {
    const normalized = String(query || '').trim();
    if (!normalized) return;
    if (queryCandidates.some((row) => String(row || '').toLowerCase() === normalized.toLowerCase())) return;
    queryCandidates.push(normalized);
  };

  if (/(uv|spf|sun|sunscreen|uva|uvb)/i.test(seed)) {
    pushQuery('SPF50+ broad spectrum sunscreen for sensitive skin');
  }
  if (/(barrier|ceramide|b5|panthenol|hyaluronic|dry|dehydrated)/i.test(seed)) {
    pushQuery('Ceramide barrier repair moisturizer fragrance free');
  }
  if (/(acne|texture|pore|oily|salicylic)/i.test(seed)) {
    pushQuery('Gentle salicylic acid serum for texture and pores');
  }
  if (/(tone|dark spot|pigment|niacinamide|tranexamic|ascorbic|vitamin c|uneven)/i.test(seed)) {
    pushQuery('Niacinamide or vitamin C serum for uneven tone');
  }

  if (!queryCandidates.length) {
    pushQuery('SPF50+ broad spectrum sunscreen for sensitive skin');
    pushQuery('Ceramide barrier repair moisturizer fragrance free');
    pushQuery('Gentle non-stripping cleanser sensitive skin');
  }

  return queryCandidates.slice(0, Math.max(1, Math.min(6, Number(maxItems) || 3))).map((query) => ({
    title: query,
    url: buildExternalGoogleSearchUrl(query),
    source: 'fallback',
    reason: 'strict_filter_all_dropped_fallback',
  }));
}

function tryDecodeSearchQueryFromUrl(url) {
  const raw = String(url || '').trim();
  if (!PRODUCT_INTEL_HTTP_URL_RE.test(raw)) return '';
  try {
    const parsed = new URL(raw);
    const query = pickFirstString(
      parsed.searchParams.get('q'),
      parsed.searchParams.get('query'),
      parsed.searchParams.get('k'),
      parsed.searchParams.get('keyword'),
    );
    return String(query || '').trim();
  } catch {
    return '';
  }
}

function dedupeExternalSearchCtas(ctas, maxItems = 12) {
  const list = Array.isArray(ctas) ? ctas : [];
  const out = [];
  const seen = new Set();
  for (const item of list) {
    if (!isPlainObject(item)) continue;
    const title = pickFirstString(item.title, item.name, item.query);
    const url = pickFirstString(item.url);
    if (!title && !url) continue;
    const key = `${String(title || '').trim().toLowerCase()}::${String(url || '').trim().toLowerCase()}`;
    if (seen.has(key)) continue;
    seen.add(key);
    out.push({
      title,
      ...(url ? { url } : {}),
      ...(pickFirstString(item.source) ? { source: pickFirstString(item.source).toLowerCase() } : {}),
      ...(pickFirstString(item.reason) ? { reason: pickFirstString(item.reason) } : {}),
    });
    if (out.length >= Math.max(1, Number(maxItems) || 12)) break;
  }
  return out;
}

function collectPurchasableFallbackQueries({
  payload,
  recommendationRows = [],
  externalSearchCtas = [],
  extraSeeds = [],
  maxQueries = AURORA_PURCHASABLE_FALLBACK_MAX_RECOVERY_QUERIES,
} = {}) {
  const queries = [];
  const seen = new Set();
  const pushQuery = (value) => {
    const normalized = String(value || '').trim();
    if (!normalized) return;
    const key = normalized.toLowerCase();
    if (seen.has(key)) return;
    seen.add(key);
    queries.push(normalized);
  };

  const p = isPlainObject(payload) ? payload : {};
  const science = isPlainObject(p.evidence) && isPlainObject(p.evidence.science) ? p.evidence.science : {};
  const ingredientSeeds = Array.isArray(science.key_ingredients) ? science.key_ingredients.slice(0, 3) : [];

  for (const row of Array.isArray(recommendationRows) ? recommendationRows : []) {
    if (!isPlainObject(row)) continue;
    pushQuery(pickFirstString(row.name, row.title, row.display_name, row.displayName));
    pushQuery(tryDecodeSearchQueryFromUrl(extractCandidateOpenUrl(row)));
  }

  for (const cta of Array.isArray(externalSearchCtas) ? externalSearchCtas : []) {
    if (!isPlainObject(cta)) continue;
    pushQuery(pickFirstString(cta.title, cta.query));
    pushQuery(tryDecodeSearchQueryFromUrl(cta.url));
  }

  for (const value of Array.isArray(extraSeeds) ? extraSeeds : []) {
    if (isPlainObject(value)) {
      pushQuery(pickFirstString(value.ingredient, value.ingredient_id, value.name, value.title));
      continue;
    }
    pushQuery(value);
  }

  for (const ingredient of ingredientSeeds) {
    const token = String(ingredient || '').trim();
    if (!token) continue;
    pushQuery(`${token} skincare`);
  }

  return queries.slice(0, Math.max(1, Number(maxQueries) || 4));
}

async function recoverPurchasableProductsFromQueries({
  queries = [],
  strictFilter = true,
  qaMode = AURORA_PRODUCT_RELEVANCE_QA_MODE,
  singleProvider = AURORA_LLM_SINGLE_PROVIDER,
  allowOpenAiFallback = AURORA_LLM_OPENAI_FALLBACK_ENABLED,
  qaContext = null,
  fallbackCandidateBuilder,
  allowExternalSeedSupplement = false,
  externalSeedStrategy = 'supplement_internal_first',
  logger,
  guardrailRuleId = 'reco_guardrail',
  maxProducts = AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS,
} = {}) {
  const out = {
    products: [],
    rejected: [],
    external_search_ctas: [],
    attempted_queries: [],
    selected_source_counts: {},
  };
  if (typeof fallbackCandidateBuilder !== 'function') return out;

  const seenProducts = new Set();
  const targetMax = Math.max(1, Number(maxProducts) || AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS);

  for (const query of Array.isArray(queries) ? queries : []) {
    const q = String(query || '').trim();
    if (!q) continue;
    if (out.products.length >= targetMax) break;
    out.attempted_queries.push(q);

    let fallbackOut = null;
    try {
      fallbackOut = await fallbackCandidateBuilder({
        query: q,
        limit: Math.max(2, targetMax - out.products.length),
        allowExternalSeed: allowExternalSeedSupplement === true,
        externalSeedStrategy,
        logger,
      });
    } catch (err) {
      logger?.warn?.({ err: err?.message || String(err), query: q }, 'aurora bff: purchasable fallback query failed');
      continue;
    }

    const sourceKey = String(fallbackOut?.selected_source || 'none').trim() || 'none';
    out.selected_source_counts[sourceKey] = Number(out.selected_source_counts[sourceKey] || 0) + 1;

    const products = Array.isArray(fallbackOut?.products) ? fallbackOut.products : [];
    for (const raw of products) {
      if (out.products.length >= targetMax) break;
      const normalized = normalizeRecoCatalogProduct(raw);
      if (!isPlainObject(normalized)) continue;

      const dedupeKey = `${String(normalized.product_id || '').trim()}::${String(normalized.merchant_id || '').trim()}::${String(extractCandidateOpenUrl(normalized) || '').trim().toLowerCase()}`;
      if (seenProducts.has(dedupeKey)) continue;

      const blacklistHit = isBlacklistedCategoryOrTitle(normalized);
      const skincareHit = isSkincareCategory(normalized);
      const relevanceDecision = await evaluateIngredientCandidateWithQaMode(normalized, {
        qaMode,
        singleProvider,
        allowOpenAiFallback,
        qaContext,
      });
      const directUrl = extractCandidateOpenUrl(normalized);
      const openable = hasOpenableUrl(normalized);
      const searchLike = isSearchLikeUrl(directUrl);
      const relevanceRejectReason = blacklistHit
        ? 'blacklisted_category_or_title'
        : strictFilter && !skincareHit
          ? 'non_skincare_category'
          : !(relevanceDecision && relevanceDecision.pass === true)
            ? pickFirstString(relevanceDecision && relevanceDecision.reject_reason, 'llm_relevance_reject')
            : '';

      if (relevanceRejectReason) {
        out.rejected.push({
          query: q,
          candidate_title: pickFirstString(normalized.name, normalized.title, normalized.display_name, normalized.displayName),
          candidate_url: directUrl || null,
          candidate_source: pickFirstString(normalized.source, normalized.brand).toLowerCase() || null,
          reject_reason: relevanceRejectReason,
          rule_id: guardrailRuleId,
        });
        continue;
      }
      if (searchLike) {
        out.external_search_ctas.push(buildExternalSearchCta(normalized, 'search_url_demoted'));
        continue;
      }
      if (!openable) {
        out.external_search_ctas.push(buildExternalSearchCta(normalized, 'missing_openable_url_search_fallback'));
        out.rejected.push({
          query: q,
          candidate_title: pickFirstString(normalized.name, normalized.title, normalized.display_name, normalized.displayName),
          candidate_url: directUrl || null,
          candidate_source: pickFirstString(normalized.source, normalized.brand).toLowerCase() || null,
          reject_reason: 'product_url_missing',
          rule_id: guardrailRuleId,
        });
        continue;
      }
      if (!directUrl) {
        out.external_search_ctas.push(buildExternalSearchCta(normalized, 'open_contract_only_no_direct_url'));
        continue;
      }
      if (!isHttpsUrl(directUrl)) {
        out.external_search_ctas.push(buildExternalSearchCta(normalized, 'non_https_pdp_url_demoted'));
        out.rejected.push({
          query: q,
          candidate_title: pickFirstString(normalized.name, normalized.title, normalized.display_name, normalized.displayName),
          candidate_url: directUrl || null,
          candidate_source: pickFirstString(normalized.source, normalized.brand).toLowerCase() || null,
          reject_reason: 'non_https_pdp_url',
          rule_id: guardrailRuleId,
        });
        continue;
      }

      seenProducts.add(dedupeKey);
      out.products.push(normalizeCandidateWithDirectUrl(normalized, directUrl));
    }
  }

  out.external_search_ctas = dedupeExternalSearchCtas(out.external_search_ctas, 12);
  return out;
}

function deriveProductsEmptyReason({
  keptCount = 0,
  externalSearchCount = 0,
  strictFallbackCount = 0,
  droppedCount = 0,
  missingUrlCount = 0,
  contractOnlyCount = 0,
  searchDemotedCount = 0,
  nonHttpsCount = 0,
} = {}) {
  if (Number(keptCount) > 0) return null;
  if (Number(strictFallbackCount) > 0 && Number(externalSearchCount) > 0) return 'strict_filter_fallback_only';
  if (Number(nonHttpsCount) > 0) return 'no_pdp_after_filter';
  if ((Number(missingUrlCount) + Number(contractOnlyCount) + Number(searchDemotedCount)) > 0) {
    return 'no_pdp_after_filter';
  }
  if (Number(droppedCount) > 0) return 'strict_filter_fallback_only';
  return 'no_candidate';
}

function countPurchasableProductsForTargets(targets) {
  let count = 0;
  for (const target of Array.isArray(targets) ? targets : []) {
    if (!isPlainObject(target)) continue;
    const productsNode = target.products;
    if (Array.isArray(productsNode)) {
      count += productsNode.length;
      continue;
    }
    if (isPlainObject(productsNode)) {
      for (const value of Object.values(productsNode)) {
        if (Array.isArray(value)) count += value.length;
      }
    }
    if (Array.isArray(target.candidates)) count += target.candidates.length;
    if (Array.isArray(target.items)) count += target.items.length;
  }
  return count;
}

async function sanitizeRecoCandidatesForUi(
  cards,
  {
    strictFilter,
    dualQa,
    qaMode,
    singleProvider,
    allowOpenAiFallback,
    qaContext = null,
    fallbackCandidateBuilder = null,
    allowExternalSeedSupplement = false,
    externalSeedStrategy = 'supplement_internal_first',
    logger = null,
  } = {},
) {
  const list = Array.isArray(cards) ? cards : [];
  if (!list.length) return { cards: [], rejected: [], dropped: 0, externalized: 0 };
  const effectiveQaMode = (() => {
    if (qaMode !== undefined && qaMode !== null && String(qaMode).trim()) return resolveQaMode(qaMode);
    if (dualQa === true) return 'dual';
    if (dualQa === false) return 'off';
    return resolveQaMode(AURORA_PRODUCT_RELEVANCE_QA_MODE);
  })();
  const effectiveSingleProvider = resolveQaSingleProvider(singleProvider);
  const effectiveOpenAiFallback =
    allowOpenAiFallback === undefined || allowOpenAiFallback === null
      ? AURORA_LLM_OPENAI_FALLBACK_ENABLED
      : Boolean(allowOpenAiFallback);

  let dropped = 0;
  let externalized = 0;
  const rejected = [];
  const nextCards = [];
  for (const card of list) {
    if (!isPlainObject(card)) {
      nextCards.push(card);
      continue;
    }
    const type = String(card.type || '').trim().toLowerCase();
    const payload = isPlainObject(card.payload) ? { ...card.payload } : null;
    if (!payload) {
      nextCards.push(card);
      continue;
    }

    if (type === 'recommendations') {
      const recs = Array.isArray(payload.recommendations) ? payload.recommendations : [];
      const kept = [];
      const externalSearchCtas = Array.isArray(payload.external_search_ctas) ? payload.external_search_ctas.slice(0, 6) : [];
      let droppedForCard = 0;
      let searchDemotedForCard = 0;
      let contractDemotedForCard = 0;
      let missingUrlFallbackForCard = 0;
      let strictFilterFallbackForCard = 0;
      let nonHttpsDemotedForCard = 0;
      let recoveryRecoveredForCard = 0;
      let recoveryAttemptedForCard = 0;
      for (const rec of recs) {
        const row = isPlainObject(rec) ? { ...rec } : null;
        if (!row) continue;

        const blacklistHit = isBlacklistedCategoryOrTitle(row);
        const skincareHit = isSkincareCategory(row);
        const relevanceDecision = await evaluateIngredientCandidateWithQaMode(row, {
          qaMode: effectiveQaMode,
          singleProvider: effectiveSingleProvider,
          allowOpenAiFallback: effectiveOpenAiFallback,
          qaContext,
        });
        const directUrl = extractCandidateOpenUrl(row);
        const openable = hasOpenableUrl(row);
        const searchLike = isSearchLikeUrl(directUrl);
        const relevanceRejectReason = blacklistHit
          ? 'blacklisted_category_or_title'
          : strictFilter && !skincareHit
            ? 'non_skincare_category'
            : !(relevanceDecision && relevanceDecision.pass === true)
              ? pickFirstString(relevanceDecision && relevanceDecision.reject_reason, 'llm_relevance_reject')
              : '';

        if (relevanceRejectReason) {
          dropped += 1;
          droppedForCard += 1;
          rejected.push({
            query: pickFirstString(row.name, row.title, row.display_name, row.displayName),
            candidate_title: pickFirstString(row.name, row.title, row.display_name, row.displayName),
            candidate_url: directUrl || null,
            candidate_source: pickFirstString(row.source, row.brand).toLowerCase() || null,
            reject_reason: relevanceRejectReason,
            rule_id: 'reco_guardrail',
          });
          continue;
        }

        if (searchLike) {
          externalized += 1;
          searchDemotedForCard += 1;
          externalSearchCtas.push(buildExternalSearchCta(row, 'search_url_demoted'));
          continue;
        }
        if (!openable) {
          externalized += 1;
          missingUrlFallbackForCard += 1;
          externalSearchCtas.push(buildExternalSearchCta(row, 'missing_openable_url_search_fallback'));
          rejected.push({
            query: pickFirstString(row.name, row.title, row.display_name, row.displayName),
            candidate_title: pickFirstString(row.name, row.title, row.display_name, row.displayName),
            candidate_url: directUrl || null,
            candidate_source: pickFirstString(row.source, row.brand).toLowerCase() || null,
            reject_reason: 'product_url_missing',
            rule_id: 'reco_guardrail',
          });
          continue;
        }
        if (!directUrl) {
          externalized += 1;
          contractDemotedForCard += 1;
          externalSearchCtas.push(buildExternalSearchCta(row, 'open_contract_only_no_direct_url'));
          continue;
        }
        if (!isHttpsUrl(directUrl)) {
          externalized += 1;
          nonHttpsDemotedForCard += 1;
          externalSearchCtas.push(buildExternalSearchCta(row, 'non_https_pdp_url_demoted'));
          rejected.push({
            query: pickFirstString(row.name, row.title, row.display_name, row.displayName),
            candidate_title: pickFirstString(row.name, row.title, row.display_name, row.displayName),
            candidate_url: directUrl || null,
            candidate_source: pickFirstString(row.source, row.brand).toLowerCase() || null,
            reject_reason: 'non_https_pdp_url',
            rule_id: 'reco_guardrail',
          });
          continue;
        }

        kept.push(normalizeCandidateWithDirectUrl(row, directUrl));
      }

      if (kept.length === 0 && externalSearchCtas.length === 0 && droppedForCard > 0) {
        const strictFallback = buildStrictFilterFallbackSearchCtas(payload, 3);
        if (strictFallback.length) {
          strictFilterFallbackForCard += 1;
          externalized += strictFallback.length;
          externalSearchCtas.push(...strictFallback);
        }
      }

      if (kept.length === 0 && AURORA_PURCHASABLE_FALLBACK_ENABLED && typeof fallbackCandidateBuilder === 'function') {
        const recoveryQueries = collectPurchasableFallbackQueries({
          payload,
          recommendationRows: recs,
          externalSearchCtas,
          maxQueries: AURORA_PURCHASABLE_FALLBACK_MAX_RECOVERY_QUERIES,
        });
        if (recoveryQueries.length) {
          const recovered = await recoverPurchasableProductsFromQueries({
            queries: recoveryQueries,
            strictFilter,
            qaMode: effectiveQaMode,
            singleProvider: effectiveSingleProvider,
            allowOpenAiFallback: effectiveOpenAiFallback,
            qaContext,
            fallbackCandidateBuilder,
            allowExternalSeedSupplement,
            externalSeedStrategy,
            logger,
            guardrailRuleId: 'reco_guardrail',
            maxProducts: AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS,
          });
          recoveryAttemptedForCard = recovered.attempted_queries.length;
          recoveryRecoveredForCard = recovered.products.length;
          if (recovered.products.length) {
            kept.push(...recovered.products.slice(0, AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS));
          }
          if (recovered.rejected.length) rejected.push(...recovered.rejected);
          if (recovered.external_search_ctas.length) {
            externalSearchCtas.push(...recovered.external_search_ctas);
            externalized += recovered.external_search_ctas.length;
          }
        }
      }

      const mergedFieldMissing = mergeFieldMissing(card.field_missing, [
        ...(droppedForCard > 0 ? [{ field: 'payload.recommendations', reason: 'strict_skincare_filter' }] : []),
        ...(searchDemotedForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'search_url_demoted' }] : []),
        ...(contractDemotedForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'open_contract_only_demoted' }] : []),
        ...(missingUrlFallbackForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'product_url_missing_fallback' }] : []),
        ...(strictFilterFallbackForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'strict_filter_fallback_search' }] : []),
        ...(nonHttpsDemotedForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'non_https_pdp_url_demoted' }] : []),
        ...(recoveryAttemptedForCard > 0 ? [{ field: 'payload.recommendations', reason: 'purchasable_fallback_attempted' }] : []),
        ...(recoveryRecoveredForCard > 0 ? [{ field: 'payload.recommendations', reason: 'purchasable_fallback_recovered' }] : []),
      ]);
      const finalExternalSearchCtas = AURORA_DISCOVERY_CARD_IN_LIST_ENABLED
        ? dedupeExternalSearchCtas(externalSearchCtas, 8)
        : [];
      const productsEmptyReason = deriveProductsEmptyReason({
        keptCount: kept.length,
        externalSearchCount: finalExternalSearchCtas.length,
        strictFallbackCount: strictFilterFallbackForCard,
        droppedCount: droppedForCard,
        missingUrlCount: missingUrlFallbackForCard,
        contractOnlyCount: contractDemotedForCard,
        searchDemotedCount: searchDemotedForCard,
        nonHttpsCount: nonHttpsDemotedForCard,
      });

      nextCards.push({
        ...card,
        payload: {
          ...payload,
          recommendations: kept,
          ...(finalExternalSearchCtas.length ? { external_search_ctas: finalExternalSearchCtas } : {}),
          ...(productsEmptyReason ? { products_empty_reason: productsEmptyReason } : {}),
        },
        ...(mergedFieldMissing.length ? { field_missing: mergedFieldMissing } : {}),
      });
      continue;
    }

    if (type === 'ingredient_plan_v2' || type === 'ingredient_plan') {
      const planNode = isPlainObject(payload.plan) ? { ...payload.plan } : null;
      const targets = Array.isArray(payload.targets)
        ? payload.targets
        : planNode && Array.isArray(planNode.targets)
          ? planNode.targets
          : [];
      const externalSearchCtas = Array.isArray(payload.external_search_ctas) ? payload.external_search_ctas.slice(0, 12) : [];
      const nextTargets = [];
      let droppedForCard = 0;
      let searchDemotedForCard = 0;
      let contractDemotedForCard = 0;
      let missingUrlFallbackForCard = 0;
      let nonHttpsDemotedForCard = 0;
      let recoveryRecoveredForCard = 0;
      let recoveryAttemptedForCard = 0;
      const guardrailRuleId = type === 'ingredient_plan_v2' ? 'ingredient_plan_v2_guardrail' : 'ingredient_plan_guardrail';

      const sanitizeRows = async (sourceRows) => {
        const kept = [];
        for (const product of sourceRows) {
          const row = isPlainObject(product) ? { ...product } : null;
          if (!row) continue;
          const blacklistHit = isBlacklistedCategoryOrTitle(row);
          const skincareHit = isSkincareCategory(row);
          const relevanceDecision = await evaluateIngredientCandidateWithQaMode(row, {
            qaMode: effectiveQaMode,
            singleProvider: effectiveSingleProvider,
            allowOpenAiFallback: effectiveOpenAiFallback,
            qaContext,
          });
          const directUrl = extractCandidateOpenUrl(row);
          const openable = hasOpenableUrl(row);
          const searchLike = isSearchLikeUrl(directUrl);
          const relevanceRejectReason = blacklistHit
            ? 'blacklisted_category_or_title'
            : strictFilter && !skincareHit
              ? 'non_skincare_category'
              : !(relevanceDecision && relevanceDecision.pass === true)
                ? pickFirstString(relevanceDecision && relevanceDecision.reject_reason, 'llm_relevance_reject')
                : '';

          if (relevanceRejectReason) {
            dropped += 1;
            droppedForCard += 1;
            rejected.push({
              query: pickFirstString(row.name, row.title, row.display_name, row.displayName),
              candidate_title: pickFirstString(row.name, row.title, row.display_name, row.displayName),
              candidate_url: directUrl || null,
              candidate_source: pickFirstString(row.source, row.brand).toLowerCase() || null,
              reject_reason: relevanceRejectReason,
              rule_id: guardrailRuleId,
            });
            continue;
          }
          if (searchLike) {
            externalized += 1;
            searchDemotedForCard += 1;
            externalSearchCtas.push(buildExternalSearchCta(row, 'search_url_demoted'));
            continue;
          }
          if (!openable) {
            externalized += 1;
            missingUrlFallbackForCard += 1;
            externalSearchCtas.push(buildExternalSearchCta(row, 'missing_openable_url_search_fallback'));
            rejected.push({
              query: pickFirstString(row.name, row.title, row.display_name, row.displayName),
              candidate_title: pickFirstString(row.name, row.title, row.display_name, row.displayName),
              candidate_url: directUrl || null,
              candidate_source: pickFirstString(row.source, row.brand).toLowerCase() || null,
              reject_reason: 'product_url_missing',
              rule_id: guardrailRuleId,
            });
            continue;
          }
          if (!directUrl) {
            externalized += 1;
            contractDemotedForCard += 1;
            externalSearchCtas.push(buildExternalSearchCta(row, 'open_contract_only_no_direct_url'));
            continue;
          }
          if (!isHttpsUrl(directUrl)) {
            externalized += 1;
            nonHttpsDemotedForCard += 1;
            externalSearchCtas.push(buildExternalSearchCta(row, 'non_https_pdp_url_demoted'));
            rejected.push({
              query: pickFirstString(row.name, row.title, row.display_name, row.displayName),
              candidate_title: pickFirstString(row.name, row.title, row.display_name, row.displayName),
              candidate_url: directUrl || null,
              candidate_source: pickFirstString(row.source, row.brand).toLowerCase() || null,
              reject_reason: 'non_https_pdp_url',
              rule_id: guardrailRuleId,
            });
            continue;
          }
          kept.push(normalizeCandidateWithDirectUrl(row, directUrl));
        }
        return kept;
      };

      for (const target of targets) {
        const baseTarget = isPlainObject(target) ? { ...target } : {};
        if (Array.isArray(baseTarget.products)) {
          baseTarget.products = await sanitizeRows(baseTarget.products);
        } else if (isPlainObject(baseTarget.products)) {
          const products = { ...baseTarget.products };
          const bucketNames = Object.keys(products);
          for (const bucketName of bucketNames) {
            const sourceRows = Array.isArray(products[bucketName]) ? products[bucketName] : [];
            products[bucketName] = await sanitizeRows(sourceRows);
          }
          baseTarget.products = products;
        }

        if (Array.isArray(baseTarget.candidates)) {
          baseTarget.candidates = await sanitizeRows(baseTarget.candidates);
        }
        if (Array.isArray(baseTarget.items)) {
          baseTarget.items = await sanitizeRows(baseTarget.items);
        }
        nextTargets.push(baseTarget);
      }

      let keptProductsCount = countPurchasableProductsForTargets(nextTargets);
      if (keptProductsCount === 0 && AURORA_PURCHASABLE_FALLBACK_ENABLED && typeof fallbackCandidateBuilder === 'function') {
        const recoveryQueries = collectPurchasableFallbackQueries({
          payload,
          externalSearchCtas,
          extraSeeds: nextTargets,
          maxQueries: AURORA_PURCHASABLE_FALLBACK_MAX_RECOVERY_QUERIES,
        });
        if (recoveryQueries.length) {
          const recovered = await recoverPurchasableProductsFromQueries({
            queries: recoveryQueries,
            strictFilter,
            qaMode: effectiveQaMode,
            singleProvider: effectiveSingleProvider,
            allowOpenAiFallback: effectiveOpenAiFallback,
            qaContext,
            fallbackCandidateBuilder,
            allowExternalSeedSupplement,
            externalSeedStrategy,
            logger,
            guardrailRuleId,
            maxProducts: AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS,
          });
          recoveryAttemptedForCard = recovered.attempted_queries.length;
          recoveryRecoveredForCard = recovered.products.length;
          if (recovered.rejected.length) rejected.push(...recovered.rejected);
          if (recovered.external_search_ctas.length) {
            externalSearchCtas.push(...recovered.external_search_ctas);
            externalized += recovered.external_search_ctas.length;
          }
          if (recovered.products.length) {
            if (!nextTargets.length) {
              nextTargets.push({
                ingredient: 'general_skincare',
                products: {
                  competitors: [],
                  dupes: [],
                },
              });
            }
            const firstTarget = isPlainObject(nextTargets[0]) ? { ...nextTargets[0] } : {};
            const productsNode = isPlainObject(firstTarget.products) ? { ...firstTarget.products } : {};
            const competitors = Array.isArray(productsNode.competitors) ? productsNode.competitors.slice() : [];
            productsNode.competitors = [...competitors, ...recovered.products].slice(0, AURORA_PURCHASABLE_FALLBACK_RECOVERY_MAX_PRODUCTS);
            firstTarget.products = productsNode;
            nextTargets[0] = firstTarget;
          }
          keptProductsCount = countPurchasableProductsForTargets(nextTargets);
        }
      }

      const mergedFieldMissing = mergeFieldMissing(card.field_missing, [
        ...(droppedForCard > 0 ? [{ field: 'payload.targets[].products', reason: 'strict_skincare_filter' }] : []),
        ...(searchDemotedForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'search_url_demoted' }] : []),
        ...(contractDemotedForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'open_contract_only_demoted' }] : []),
        ...(missingUrlFallbackForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'product_url_missing_fallback' }] : []),
        ...(nonHttpsDemotedForCard > 0 ? [{ field: 'payload.external_search_ctas', reason: 'non_https_pdp_url_demoted' }] : []),
        ...(recoveryAttemptedForCard > 0 ? [{ field: 'payload.targets[].products', reason: 'purchasable_fallback_attempted' }] : []),
        ...(recoveryRecoveredForCard > 0 ? [{ field: 'payload.targets[].products', reason: 'purchasable_fallback_recovered' }] : []),
      ]);
      const finalExternalSearchCtas = AURORA_DISCOVERY_CARD_IN_LIST_ENABLED
        ? dedupeExternalSearchCtas(externalSearchCtas, 12)
        : [];
      const productsEmptyReason = deriveProductsEmptyReason({
        keptCount: keptProductsCount,
        externalSearchCount: finalExternalSearchCtas.length,
        strictFallbackCount: 0,
        droppedCount: droppedForCard,
        missingUrlCount: missingUrlFallbackForCard,
        contractOnlyCount: contractDemotedForCard,
        searchDemotedCount: searchDemotedForCard,
        nonHttpsCount: nonHttpsDemotedForCard,
      });

      nextCards.push({
        ...card,
        payload: {
          ...payload,
          ...(Array.isArray(payload.targets)
            ? { targets: nextTargets }
            : planNode
              ? { plan: { ...planNode, targets: nextTargets } }
              : { targets: nextTargets }),
          ...(finalExternalSearchCtas.length ? { external_search_ctas: finalExternalSearchCtas } : {}),
          ...(productsEmptyReason ? { products_empty_reason: productsEmptyReason } : {}),
        },
        ...(mergedFieldMissing.length ? { field_missing: mergedFieldMissing } : {}),
      });
      continue;
    }

    nextCards.push(card);
  }

  return { cards: nextCards, rejected, dropped, externalized };
}

function applyPhotoClaimConsistency(cards) {
  const list = Array.isArray(cards) ? cards : [];
  const hasPhotoModules = list.some((card) => {
    if (!isPlainObject(card)) return false;
    if (String(card.type || '').trim().toLowerCase() !== 'photo_modules_v1') return false;
    const payload = isPlainObject(card.payload) ? card.payload : {};
    const modules = Array.isArray(payload.modules) ? payload.modules : [];
    const qualityGrade = String(payload.quality_grade || '').trim().toLowerCase();
    return modules.length > 0 && qualityGrade !== 'fail';
  });

  return list.map((card) => {
    if (!isPlainObject(card)) return card;
    const type = String(card.type || '').trim().toLowerCase();
    const payload = isPlainObject(card.payload) ? { ...card.payload } : null;
    if (!payload) return card;

    if (type === 'photo_modules_v1') {
      return {
        ...card,
        payload: {
          ...payload,
          render_capabilities: {
            ...(isPlainObject(payload.render_capabilities) ? payload.render_capabilities : {}),
            mask_overlay_enabled: AURORA_PHOTO_MODULE_MASK_OVERLAY_ENABLED,
          },
        },
      };
    }

    if (type !== 'analysis_summary') return card;

    const qualityReport = isPlainObject(payload.quality_report) ? { ...payload.quality_report } : {};
    const photoQuality = isPlainObject(qualityReport.photo_quality) ? { ...qualityReport.photo_quality } : {};
    const qualityGrade = String(photoQuality.grade || '').trim().toLowerCase();
    const forceUnavailable = qualityGrade === 'fail' || !hasPhotoModules;

    if (!forceUnavailable) return card;

    const nextFieldMissing = mergeFieldMissing(card.field_missing, [
      {
        field: 'analysis.used_photos',
        reason: qualityGrade === 'fail' ? 'photo_quality_fail' : 'photo_modules_missing',
      },
    ]);

    return {
      ...card,
      payload: {
        ...payload,
        used_photos: false,
        photo_analysis_status: 'unavailable',
        photo_analysis_reason: qualityGrade === 'fail' ? 'photo_quality_fail' : 'photo_modules_missing',
      },
      ...(nextFieldMissing.length ? { field_missing: nextFieldMissing } : {}),
    };
  });
}

function buildAnalysisStoryFallbackPayload({ analysisSummaryPayload, profile, language } = {}) {
  const isCn = String(language || '').toUpperCase() === 'CN';
  const payload = isPlainObject(analysisSummaryPayload) ? analysisSummaryPayload : {};
  const analysis = isPlainObject(payload.analysis) ? payload.analysis : {};
  const features = Array.isArray(analysis.features) ? analysis.features : [];
  const findings = features
    .map((row, idx) => {
      const observation = pickFirstString(row && row.observation, row && row.title, row && row.name);
      if (!observation) return null;
      return {
        priority: idx + 1,
        title: observation,
        detail: observation,
        evidence_region_or_module: [],
      };
    })
    .filter(Boolean)
    .slice(0, 6);

  const missingFields = deriveRoutineMissingFields(profile);
  return {
    schema_version: 'aurora.analysis_story.v2',
    confidence_overall: isPlainObject(analysis.confidence) ? analysis.confidence : { level: payload.low_confidence ? 'low' : 'medium' },
    skin_profile: {
      skin_type_tendency: pickFirstString(profile && profile.skinType, isCn ? '待补充' : 'pending'),
      sensitivity_tendency: pickFirstString(profile && profile.sensitivity, isCn ? '待补充' : 'pending'),
      current_strengths:
        findings.length > 0
          ? findings.slice(0, 2).map((row) => row.title)
          : [isCn ? '当前可见信息有限，先按屏障友好策略执行。' : 'Visible signals are limited; start with a barrier-safe routine.'],
    },
    priority_findings: findings,
    target_state: [
      isCn ? '先稳定屏障，再提高提亮与均匀度。' : 'Stabilize barrier first, then improve tone and texture consistency.',
    ],
    core_principles: [
      isCn ? '先稳后进，避免一次叠加多个强活性。' : 'Stability first, then progression; avoid stacking multiple strong actives at once.',
      isCn ? '白天防晒是色素与光损管理的基线。' : 'Daily UV protection is the baseline for pigmentation and photoaging control.',
    ],
    am_plan: [
      { step: isCn ? '温和清洁' : 'Gentle cleanse', purpose: isCn ? '减少刺激起点' : 'Minimize irritation load' },
      { step: isCn ? '保湿/修护精华' : 'Hydration/repair serum', purpose: isCn ? '维持角质层稳定' : 'Support barrier stability' },
      { step: isCn ? 'SPF50+ 防晒' : 'SPF50+ sunscreen', purpose: isCn ? '控制紫外暴露' : 'Control UV exposure' },
    ],
    pm_plan: [
      { step: isCn ? '温和清洁' : 'Gentle cleanse', purpose: isCn ? '清除日间残留' : 'Remove daytime residue' },
      { step: isCn ? '单一主力活性（低频）' : 'Single core active (low frequency)', purpose: isCn ? '降低不耐受概率' : 'Reduce irritation risk' },
      { step: isCn ? '屏障面霜' : 'Barrier moisturizer', purpose: isCn ? '夜间修护' : 'Night recovery' },
    ],
    routine_bridge: {
      missing_fields: missingFields,
      why_now: isCn
        ? '补全 AM/PM routine 后，推荐会从通用建议升级为与你现有产品不冲突的个性化方案。'
        : 'Once AM/PM routine is provided, recommendations can be personalized and conflict-aware.',
      cta_label: isCn ? '补全 AM/PM Routine' : 'Add AM/PM routine',
      cta_action: 'open_routine_intake',
    },
    existing_products_optimization: {
      keep: [],
      add: [],
      replace: [],
      remove: [],
    },
    timeline: {
      first_4_weeks: [
        isCn ? '第1周：只保留基础清洁-保湿-防晒。' : 'Week 1: keep cleanse-moisturize-sunscreen baseline only.',
        isCn ? '第2-3周：逐步引入一个活性，隔天使用。' : 'Week 2-3: add one active gradually, every other day.',
        isCn ? '第4周：耐受稳定后再评估加强。' : 'Week 4: scale only if tolerance remains stable.',
      ],
      week_8_12_expectation: [
        isCn ? '8-12 周观察肤色均匀与稳定度改善。' : 'Expect visible stability and tone improvements in 8-12 weeks.',
      ],
    },
    safety_notes: [
      isCn ? '若持续刺痛/泛红/脱屑，请暂停新增活性并回到修护。' : 'If persistent stinging/redness/peeling occurs, pause new actives and return to barrier repair.',
    ],
    disclaimer_non_medical: true,
  };
}

function buildAnalysisEvidence({ analysisSummaryPayload, profile, language, fallbackStory } = {}) {
  const payload = isPlainObject(analysisSummaryPayload) ? analysisSummaryPayload : {};
  const analysis = isPlainObject(payload.analysis) ? payload.analysis : {};
  const features = Array.isArray(analysis.features) ? analysis.features : [];
  const findingEvidence = features
    .map((row, idx) => {
      const observation = pickFirstString(row && row.observation, row && row.title, row && row.name);
      if (!observation) return null;
      return {
        rank: idx + 1,
        observation,
      };
    })
    .filter(Boolean)
    .slice(0, 8);
  return {
    schema_version: 'aurora.analysis_story.evidence.v1',
    language: String(language || 'EN').toUpperCase(),
    profile: {
      skinType: pickFirstString(profile && profile.skinType),
      sensitivity: pickFirstString(profile && profile.sensitivity),
      barrierStatus: pickFirstString(profile && profile.barrierStatus),
      goals: Array.isArray(profile && profile.goals) ? profile.goals.map((item) => String(item || '').trim()).filter(Boolean) : [],
    },
    missing_routine_fields: deriveRoutineMissingFields(profile),
    analysis_source: pickFirstString(payload.analysis_source),
    low_confidence: payload.low_confidence === true,
    finding_evidence: findingEvidence,
    preferred_story: isPlainObject(fallbackStory) ? fallbackStory : null,
  };
}

function generateAnalysisStoryV2Json({ evidence, fallbackStory } = {}) {
  const preferred = isPlainObject(evidence && evidence.preferred_story) ? evidence.preferred_story : null;
  const base = isPlainObject(preferred) ? preferred : isPlainObject(fallbackStory) ? fallbackStory : {};
  const output = {
    ...base,
    schema_version: 'aurora.analysis_story.v2',
  };
  if (!isPlainObject(output.routine_bridge)) {
    output.routine_bridge = {
      missing_fields: Array.isArray(evidence && evidence.missing_routine_fields) ? evidence.missing_routine_fields : [],
      why_now: 'Add AM/PM routine to unlock personalized recommendations.',
      cta_label: 'Add AM/PM routine',
      cta_action: 'open_routine_intake',
    };
  }
  if (!Array.isArray(output.priority_findings) || !output.priority_findings.length) {
    const inferredFindings = Array.isArray(evidence && evidence.finding_evidence)
      ? evidence.finding_evidence.map((item) => ({
          priority: Number(item.rank) || 1,
          title: pickFirstString(item.observation),
          detail: pickFirstString(item.observation),
          evidence_region_or_module: [],
        }))
      : [];
    output.priority_findings = inferredFindings.slice(0, 6);
  }
  return output;
}

function reviewAnalysisStoryV2Json({ story, evidence } = {}) {
  const candidate = isPlainObject(story) ? { ...story } : {};
  const issues = [];
  if (candidate.disclaimer_non_medical !== true) {
    candidate.disclaimer_non_medical = true;
    issues.push('disclaimer_non_medical_forced_true');
  }
  const missingRoutine = Array.isArray(evidence && evidence.missing_routine_fields) ? evidence.missing_routine_fields : [];
  const bridge = isPlainObject(candidate.routine_bridge) ? { ...candidate.routine_bridge } : {};
  const bridgeMissing = Array.isArray(bridge.missing_fields) ? bridge.missing_fields.map((v) => String(v || '').trim()).filter(Boolean) : [];
  if (!bridgeMissing.length && missingRoutine.length) {
    bridge.missing_fields = missingRoutine;
    issues.push('routine_bridge_missing_fields_repaired');
  } else if (bridgeMissing.length) {
    bridge.missing_fields = bridgeMissing;
  }
  bridge.why_now = pickFirstString(bridge.why_now, 'Add AM/PM routine to unlock personalized recommendations.');
  bridge.cta_label = pickFirstString(bridge.cta_label, 'Add AM/PM routine');
  bridge.cta_action = pickFirstString(bridge.cta_action, 'open_routine_intake');
  candidate.routine_bridge = bridge;

  if (!Array.isArray(candidate.priority_findings)) {
    candidate.priority_findings = [];
    issues.push('priority_findings_repaired_to_array');
  }
  return {
    ok: true,
    repaired: candidate,
    issues,
  };
}

function buildAnalysisStoryGenerationPrompt({ evidence, fallbackStory } = {}) {
  const safeEvidence = isPlainObject(evidence) ? evidence : {};
  const safeFallback = isPlainObject(fallbackStory) ? fallbackStory : {};
  return [
    'Task: Generate a skincare analysis story JSON using ONLY provided evidence.',
    'Rules:',
    '- No medical diagnosis language.',
    '- Keep actionable AM/PM steps.',
    '- If routine is missing, include routine_bridge with why_now and CTA.',
    '- Return strict JSON only with schema compatible to aurora.analysis_story.v2.',
    '',
    'Evidence JSON:',
    JSON.stringify(safeEvidence, null, 2),
    '',
    'Fallback template JSON:',
    JSON.stringify(safeFallback, null, 2),
  ].join('\n');
}

function buildAnalysisStoryReviewPrompt({ story, evidence } = {}) {
  const safeStory = isPlainObject(story) ? story : {};
  const safeEvidence = isPlainObject(evidence) ? evidence : {};
  return [
    'Task: Review and patch a skincare analysis story JSON for factual consistency and safety.',
    'Output strict JSON with keys:',
    '- approved: boolean',
    '- issues: string[]',
    '- patched_story: object',
    'Rules:',
    '- patched_story must stay within evidence boundaries.',
    '- enforce non-medical disclaimer and routine_bridge when routine is missing.',
    '',
    'Evidence JSON:',
    JSON.stringify(safeEvidence, null, 2),
    '',
    'Story JSON:',
    JSON.stringify(safeStory, null, 2),
  ].join('\n');
}

async function generateAnalysisStoryV2JsonWithLlm({
  evidence,
  fallbackStory,
  qaMode = AURORA_LLM_QA_MODE,
  singleProvider = AURORA_LLM_SINGLE_PROVIDER,
  allowOpenAiFallback = AURORA_LLM_OPENAI_FALLBACK_ENABLED,
  qaContext = null,
} = {}) {
  const deterministic = generateAnalysisStoryV2Json({ evidence, fallbackStory });
  const mode = resolveQaMode(qaMode);
  if (mode === 'off') {
    markQaContextSkip(qaContext, 'story', 'qa_mode_off');
    return deterministic;
  }
  if (shouldSkipQaByBudget({ qaContext, stage: 'story' })) return deterministic;
  const providers = pickQaProvidersForMode({
    mode,
    singleProvider: resolveQaSingleProvider(singleProvider),
    allowOpenAiFallback,
  });
  if (!providers.length) return deterministic;

  const systemPrompt =
    'You are a skincare analysis generator. Output strict JSON only, valid for aurora.analysis_story.v2.';
  const userPrompt = buildAnalysisStoryGenerationPrompt({ evidence, fallbackStory });
  for (const provider of providers) {
    const result = await callDualQaProviderImpl({
      provider,
      systemPrompt,
      userPrompt,
      timeoutMs: ANALYSIS_STORY_LLM_TIMEOUT_MS,
    });
    if (!result || !result.ok || !isPlainObject(result.json)) {
      markQaContextCall(qaContext, 'story', provider, 'error');
      continue;
    }
    markQaContextCall(qaContext, 'story', provider, 'ok');
    return result.json;
  }
  return deterministic;
}

async function reviewAnalysisStoryV2JsonWithLlm({
  story,
  evidence,
  qaMode = AURORA_LLM_QA_MODE,
  singleProvider = AURORA_LLM_SINGLE_PROVIDER,
  allowOpenAiFallback = AURORA_LLM_OPENAI_FALLBACK_ENABLED,
  qaContext = null,
} = {}) {
  const localReviewed = reviewAnalysisStoryV2Json({ story, evidence });
  const mode = resolveQaMode(qaMode);
  if (mode !== 'dual') {
    markQaContextSkip(qaContext, 'story', mode === 'off' ? 'qa_mode_off' : 'single_mode_skip_secondary_review');
    return localReviewed;
  }
  if (shouldSkipQaByBudget({ qaContext, stage: 'story' })) return localReviewed;
  const providers = pickQaProvidersForMode({
    mode,
    singleProvider: resolveQaSingleProvider(singleProvider),
    allowOpenAiFallback,
  });
  if (providers.length < 2) return localReviewed;

  const systemPrompt =
    'You are a strict JSON reviewer for skincare analysis stories. Output strict JSON only.';
  const userPrompt = buildAnalysisStoryReviewPrompt({ story, evidence });
  for (const provider of providers) {
    const result = await callDualQaProviderImpl({
      provider,
      systemPrompt,
      userPrompt,
      timeoutMs: ANALYSIS_STORY_LLM_TIMEOUT_MS,
    });
    if (!result || !result.ok || !isPlainObject(result.json)) {
      markQaContextCall(qaContext, 'story', provider, 'error');
      continue;
    }
    const approved = result.json.approved === true;
    const patched = isPlainObject(result.json.patched_story) ? result.json.patched_story : null;
    if (!patched) continue;
    const reviewed = reviewAnalysisStoryV2Json({ story: patched, evidence });
    markQaContextCall(qaContext, 'story', provider, approved ? 'ok' : 'reject');
    return {
      ok: approved || (reviewed && reviewed.ok),
      repaired: reviewed && reviewed.repaired ? reviewed.repaired : patched,
      issues: Array.isArray(result.json.issues) ? result.json.issues.map((v) => String(v || '').trim()).filter(Boolean) : [],
    };
  }
  return localReviewed;
}

function coerceAnalysisStoryV2(candidate, fallbackPayload) {
  const parsed = AnalysisStoryV2Schema.safeParse(candidate);
  if (parsed.success) return parsed.data;
  const fallbackParsed = AnalysisStoryV2Schema.safeParse(fallbackPayload);
  if (fallbackParsed.success) return fallbackParsed.data;
  return {
    schema_version: 'aurora.analysis_story.v2',
    confidence_overall: { level: 'low' },
    skin_profile: { current_strengths: [] },
    priority_findings: [],
    target_state: [],
    core_principles: [],
    am_plan: [],
    pm_plan: [],
    routine_bridge: {
      missing_fields: ['currentRoutine.am', 'currentRoutine.pm'],
      why_now: 'Add AM/PM routine to unlock personalized recommendations.',
      cta_label: 'Add AM/PM routine',
      cta_action: 'open_routine_intake',
    },
    existing_products_optimization: { keep: [], add: [], replace: [], remove: [] },
    timeline: { first_4_weeks: [], week_8_12_expectation: [] },
    safety_notes: [],
    disclaimer_non_medical: true,
  };
}

function buildRoutinePromptCard({ ctx, language, missingFields }) {
  const isCn = String(language || '').toUpperCase() === 'CN';
  return {
    card_id: `routine_prompt_${ctx && ctx.request_id ? ctx.request_id : Date.now()}`,
    type: 'routine_prompt',
    payload: {
      missing_fields: Array.isArray(missingFields) && missingFields.length ? missingFields : ['currentRoutine.am', 'currentRoutine.pm'],
      why_now: isCn
        ? '补全当前 AM/PM 护肤步骤后，系统会根据你现有产品做冲突规避与个性化排序。'
        : 'Complete AM/PM routine to enable conflict-aware and personalized product ranking.',
      cta_label: isCn ? '补全 AM/PM Routine' : 'Add AM/PM routine',
      cta_action: 'open_routine_intake',
    },
  };
}

async function applyAnalysisStoryAndRoutineSoftGate(
  cards,
  {
    ctx,
    profile,
    language,
    qaMode = AURORA_LLM_QA_MODE,
    singleProvider = AURORA_LLM_SINGLE_PROVIDER,
    allowOpenAiFallback = AURORA_LLM_OPENAI_FALLBACK_ENABLED,
    qaContext = null,
  } = {},
) {
  let list = Array.isArray(cards) ? cards.filter((card) => card != null) : [];
  if (!list.length) return list;

  const analysisSummaryCard = list.find((card) => isPlainObject(card) && String(card.type || '').trim().toLowerCase() === 'analysis_summary');
  if (AURORA_ANALYSIS_STORY_V2_ENABLED && analysisSummaryCard) {
    const existingStory = list.find((card) => isPlainObject(card) && String(card.type || '').trim().toLowerCase() === 'analysis_story_v2');
    const summaryPayload = isPlainObject(analysisSummaryCard.payload) ? analysisSummaryCard.payload : {};
    const fallbackStory = buildAnalysisStoryFallbackPayload({ analysisSummaryPayload: summaryPayload, profile, language });
    const evidence = buildAnalysisEvidence({
      analysisSummaryPayload: summaryPayload,
      profile,
      language,
      fallbackStory,
    });
    const generated = await generateAnalysisStoryV2JsonWithLlm({
      evidence,
      fallbackStory,
      qaMode,
      singleProvider,
      allowOpenAiFallback,
      qaContext,
    });
    const reviewed = await reviewAnalysisStoryV2JsonWithLlm({
      story: isPlainObject(existingStory && existingStory.payload) ? existingStory.payload : generated,
      evidence,
      qaMode,
      singleProvider,
      allowOpenAiFallback,
      qaContext,
    });
    const storyPayload = coerceAnalysisStoryV2(
      reviewed && reviewed.repaired ? reviewed.repaired : generated,
      fallbackStory,
    );
    const storyCard = existingStory
      ? { ...existingStory, payload: storyPayload }
      : {
          card_id: `analysis_story_${ctx && ctx.request_id ? ctx.request_id : Date.now()}`,
          type: 'analysis_story_v2',
          payload: storyPayload,
        };
    list = list.filter((card) => !(isPlainObject(card) && String(card.type || '').trim().toLowerCase() === 'analysis_story_v2'));
    const photoModulesIdx = list.findIndex((card) => isPlainObject(card) && String(card.type || '').trim().toLowerCase() === 'photo_modules_v1');
    const insertIndex = photoModulesIdx >= 0 ? photoModulesIdx + 1 : 0;
    list.splice(insertIndex, 0, storyCard);
  }

  if (!AURORA_ROUTINE_SOFT_GATE_DELAY_RECO) return list;
  if (hasRoutineData(profile)) return list;

  const missingFields = deriveRoutineMissingFields(profile);
  const hasPrompt = list.some((card) => isPlainObject(card) && String(card.type || '').trim().toLowerCase() === 'routine_prompt');
  if (!hasPrompt) list.push(buildRoutinePromptCard({ ctx, language, missingFields }));

  list = list
    .map((card) => {
      if (!isPlainObject(card)) return card;
      const type = String(card.type || '').trim().toLowerCase();
      if (type === 'ingredient_plan_v2') {
        const payload = isPlainObject(card.payload) ? { ...card.payload } : {};
        const targets = Array.isArray(payload.targets) ? payload.targets : [];
        const nextTargets = targets.map((target) => {
          const t = isPlainObject(target) ? { ...target } : {};
          const products = isPlainObject(t.products) ? { ...t.products } : {};
          products.competitors = [];
          products.dupes = [];
          t.products = products;
          return t;
        });
        return {
          ...card,
          payload: {
            ...payload,
            targets: nextTargets,
            preview_only: true,
            preview_reason: 'routine_missing',
          },
          field_missing: mergeFieldMissing(card.field_missing, [{ field: 'payload.targets[].products', reason: 'routine_missing' }]),
        };
      }
      if (type === 'recommendations') {
        return null;
      }
      return card;
    })
    .filter(Boolean);

  const rank = (card) => {
    if (!isPlainObject(card)) return 1000;
    const type = String(card.type || '').trim().toLowerCase();
    if (type === 'photo_modules_v1') return 10;
    if (type === 'analysis_story_v2') return 20;
    if (type === 'analysis_summary') return 25;
    if (type === 'routine_prompt') return 30;
    if (type === 'ingredient_plan_v2') return 40;
    if (type === 'ingredient_plan') return 45;
    if (type === 'confidence_notice') return 50;
    return 200;
  };

  return list
    .map((card, index) => ({ card, index }))
    .sort((left, right) => {
      const rankDiff = rank(left.card) - rank(right.card);
      if (rankDiff !== 0) return rankDiff;
      return left.index - right.index;
    })
    .map((row) => row.card);
}

async function applyProductIntelGuardrailsToEnvelope({
  envelope,
  ctx,
  profile,
  language,
  logger = null,
  qaRuntime = null,
} = {}) {
  const base = isPlainObject(envelope) ? { ...envelope } : envelope;
  if (!isPlainObject(base)) {
    return { envelope: base, dropped: 0, externalized: 0, rejected: [] };
  }
  const qaContext = {
    budget_ms: Number.isFinite(Number(qaRuntime && qaRuntime.budget_ms)) ? Math.trunc(Number(qaRuntime.budget_ms)) : null,
    started_at_ms: Number.isFinite(Number(qaRuntime && qaRuntime.started_at_ms))
      ? Math.trunc(Number(qaRuntime.started_at_ms))
      : null,
    min_budget_ms: Number.isFinite(Number(qaRuntime && qaRuntime.min_budget_ms))
      ? Math.trunc(Number(qaRuntime.min_budget_ms))
      : AURORA_LLM_QA_MIN_REMAINING_BUDGET_MS,
    qa_mode: resolveQaMode(pickFirstString(qaRuntime && qaRuntime.qa_mode, AURORA_LLM_QA_MODE)),
    qa_provider: resolveQaSingleProvider(pickFirstString(qaRuntime && qaRuntime.qa_provider, AURORA_LLM_SINGLE_PROVIDER)),
    qa_openai_fallback_enabled:
      qaRuntime && qaRuntime.allow_openai_fallback !== undefined && qaRuntime.allow_openai_fallback !== null
        ? Boolean(qaRuntime.allow_openai_fallback)
        : AURORA_LLM_OPENAI_FALLBACK_ENABLED,
    story_meta: {},
    relevance_meta: {},
  };
  const productQaMode = resolveQaMode(
    pickFirstString(qaRuntime && qaRuntime.product_qa_mode, AURORA_PRODUCT_RELEVANCE_QA_MODE),
  );

  const rawCards = Array.isArray(base.cards) ? base.cards.slice() : [];
  const withPhotoConsistency = applyPhotoClaimConsistency(rawCards);
  const sanitized = await sanitizeRecoCandidatesForUi(withPhotoConsistency, {
    strictFilter: AURORA_PRODUCT_STRICT_SKINCARE_FILTER,
    qaMode: productQaMode,
    singleProvider: qaContext.qa_provider,
    allowOpenAiFallback: qaContext.qa_openai_fallback_enabled,
    qaContext,
    fallbackCandidateBuilder: AURORA_PURCHASABLE_FALLBACK_ENABLED ? buildPurchasableFallbackCandidates : null,
    allowExternalSeedSupplement: AURORA_EXTERNAL_SEED_SUPPLEMENT_ENABLED === true,
    externalSeedStrategy: 'supplement_internal_first',
    logger,
  });
  const withStoryAndGate = await applyAnalysisStoryAndRoutineSoftGate(sanitized.cards, {
    ctx,
    profile,
    language,
    qaMode: qaContext.qa_mode,
    singleProvider: qaContext.qa_provider,
    allowOpenAiFallback: qaContext.qa_openai_fallback_enabled,
    qaContext,
  });
  const analysisMetaBase = isPlainObject(base.analysis_meta) ? { ...base.analysis_meta } : null;
  const qaSkippedReason = pickFirstString(
    qaContext.story_meta && qaContext.story_meta.skipped_reason,
    qaContext.relevance_meta && qaContext.relevance_meta.skipped_reason,
  );
  const qaProvider = pickFirstString(
    qaContext.story_meta && qaContext.story_meta.provider,
    qaContext.relevance_meta && qaContext.relevance_meta.provider,
    qaContext.qa_provider,
  );
  const nextAnalysisMeta = analysisMetaBase
    ? {
        ...analysisMetaBase,
        qa_mode: qaContext.qa_mode,
        qa_provider: qaProvider || qaContext.qa_provider,
        ...(qaSkippedReason ? { qa_skipped_reason: qaSkippedReason } : {}),
      }
    : null;
  return {
    envelope: {
      ...base,
      cards: withStoryAndGate,
      ...(nextAnalysisMeta ? { analysis_meta: nextAnalysisMeta } : {}),
    },
    dropped: sanitized.dropped,
    externalized: sanitized.externalized,
    rejected: sanitized.rejected,
  };
}

function persistRejectedCatalogCandidates(ctx, rejected) {
  const rows = Array.isArray(rejected) ? rejected : [];
  if (!rows.length) return;
  setImmediate(async () => {
    for (const row of rows.slice(0, 40)) {
      try {
        const query = pickFirstString(row.query, row.candidate_title);
        const normalized = String(query || '')
          .trim()
          .toLowerCase()
          .replace(/[^\p{L}\p{N}]+/gu, ' ')
          .trim();
        if (!query || !normalized) continue;
        await upsertMissingCatalogProduct({
          normalized_query: normalized,
          query,
          lang: String((ctx && ctx.lang) || 'EN').toLowerCase(),
          market: pickFirstString(ctx && ctx.market, ctx && ctx.country, 'US'),
          caller: 'product_intel_guardrail',
          session_id: ctx && ctx.brief_id ? String(ctx.brief_id) : null,
          reason: row.reject_reason || 'unknown',
          candidate_title: row.candidate_title || null,
          candidate_url: row.candidate_url || null,
          candidate_source: row.candidate_source || null,
          reject_reason: row.reject_reason || null,
          rule_id: row.rule_id || null,
          hints: {
            trace_id: ctx && ctx.trace_id ? String(ctx.trace_id) : null,
            request_id: ctx && ctx.request_id ? String(ctx.request_id) : null,
          },
        });
      } catch {
        // best effort only
      }
    }
  });
}

function hasAnyToken(text, tokens) {
  const haystack = String(text || '').toLowerCase();
  return (Array.isArray(tokens) ? tokens : []).some((t) => haystack.includes(String(t || '').toLowerCase()));
}

const ROUTE_SECTION_HINTS = {
  'fit-check': [
    ['结论：', 'Verdict:'],
    ['风险点：', 'Risk points:'],
    ['更稳妥替代方向：', 'Safer alternatives:'],
    ['怎么用（频率/顺序/观察周期）：', 'How to use (frequency/order/timeline):'],
    ['停用信号：', 'Stop signals:'],
  ],
  reco: [
    ['目标与前提：', 'Goal & context:'],
    ['最小可行清单（早/晚）：', 'Minimum viable routine (AM/PM):'],
    ['成分方向（Top 3）：', 'Ingredient directions (Top 3):'],
    ['一周引入计划：', 'One-week onboarding plan:'],
    ['怎么选（选购标准）：', 'Buying criteria (how to choose):'],
    ['红旗信号：', 'Red flags:'],
  ],
  conflict: [
    ['冲突原因：', 'Conflict reason:'],
    ['安全排班（错开使用）：', 'Safer schedule (alternate use):'],
    ['优先级取舍：', 'Priority choices:'],
    ['停用信号：', 'Stop signals:'],
  ],
  env: [
    ['环境判断：', 'Environment check:'],
    ['加什么 / 减什么 / 替换什么：', 'Add / remove / replace:'],
    ['频率调整：', 'Frequency adjustment:'],
    ['临时极简方案：', 'Temporary minimal plan:'],
    ['防晒/保湿策略：', 'Sun/moisture strategy:'],
  ],
};

function isRouteStructuredAnswer(text, route) {
  const checks = ROUTE_SECTION_HINTS[String(route || '').trim()];
  if (!checks || !checks.length) return true;
  return checks.every((tokens) => hasAnyToken(text, tokens));
}

function looksLikeGenericStructuredNotice(text) {
  const raw = String(text || '').trim();
  if (!raw) return true;
  const lower = raw.toLowerCase();
  return (
    lower.includes('structured cards below') ||
    lower.includes('i did not receive any renderable structured cards') ||
    lower.includes('only a parse/summary stub') ||
    raw.includes('我已经把核心结果整理成结构化卡片') ||
    raw.includes('我还没能从上游拿到可结构化') ||
    raw.includes('仅返回了摘要/解析信息')
  );
}

function looksLikeStallPhrase(text) {
  const raw = String(text || '').trim();
  if (!raw) return false;
  const lower = raw.toLowerCase();
  return (
    lower.includes('please retry') ||
    lower.includes('retry shortly') ||
    lower.includes('upload photos') ||
    lower.includes('need a diagnosis result first') ||
    lower.includes('one quick detail before i continue') ||
    lower.includes('select one direction first') ||
    raw.includes('请重试') ||
    raw.includes('稍后重试') ||
    raw.includes('先上传照片') ||
    raw.includes('先给目的地') ||
    raw.includes('先选方向')
  );
}

function looksLikeMockPlaceholder(text) {
  return /\bmock\s+aurora\s+reply\b/i.test(String(text || ''));
}

function hasMinimumExecutableStepsForQuality(text, cards) {
  if (hasRenderableCards(cards)) return true;
  const raw = String(text || '').trim();
  if (!raw) return false;
  const lines = raw.split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
  let bullets = 0;
  for (const line of lines) {
    if (/^(\d+[\).]|[-*•]|[一二三四五六七八九十]+[、.．])\s*/.test(line)) bullets += 1;
  }
  if (bullets >= 2) return true;
  const imperativeHits = (raw.match(/(stop|avoid|use|apply|reduce|switch|pause|暂停|停用|改为|建议|先用|先停|先做)/gi) || []).length;
  return imperativeHits >= 2;
}

function isActionIntentForQuality(intent) {
  const value = String(intent || '').trim().toLowerCase();
  return (
    value === 'build_routine' ||
    value === 'add_product' ||
    value === 'report_reaction' ||
    value === 'ask_adjustment' ||
    value === 'plan_iteration'
  );
}

function isGateOnlyResponse(cards) {
  const rows = Array.isArray(cards) ? cards.filter((c) => c && typeof c === 'object' && !Array.isArray(c)) : [];
  if (!rows.length) return false;
  const types = rows.map((card) => String(card.type || '').trim().toLowerCase()).filter(Boolean);
  if (!types.length) return false;
  return types.every((type) => type === 'gate_notice' || type === 'diagnosis_gate');
}

function hasMissingRecommendationPurchasePath(cards) {
  const rows = Array.isArray(cards) ? cards : [];
  for (const card of rows) {
    if (!card || typeof card !== 'object' || Array.isArray(card)) continue;
    const type = String(card.type || '').trim().toLowerCase();
    if (type !== 'recommendations') continue;
    const payload = card.payload && typeof card.payload === 'object' && !Array.isArray(card.payload) ? card.payload : {};
    const recs = Array.isArray(payload.recommendations) ? payload.recommendations : [];
    if (!recs.length) continue;
    for (const row of recs) {
      const purchasePath = row && typeof row === 'object'
        ? (row.purchase_path || row.purchasePath || row.url || (row.sku && row.sku.purchase_path) || (row.product && row.product.purchase_path))
        : '';
      if (!/^https:\/\/\S+/i.test(String(purchasePath || '').trim())) return true;
    }
  }
  return false;
}

function hasDegradedModuleFailSignal(envelope) {
  const cards = Array.isArray(envelope && envelope.cards) ? envelope.cards : [];
  for (const card of cards) {
    if (!card || typeof card !== 'object' || Array.isArray(card)) continue;
    if (String(card.type || '').trim().toLowerCase() !== 'analysis_summary') continue;
    const payload = card.payload && typeof card.payload === 'object' && !Array.isArray(card.payload) ? card.payload : {};
    const source = String(payload.analysis_source || '').trim().toLowerCase();
    if (source.startsWith('rules_only_')) return true;
  }
  const events = Array.isArray(envelope && envelope.events) ? envelope.events : [];
  for (const evt of events) {
    if (!evt || typeof evt !== 'object' || Array.isArray(evt)) continue;
    const name = String(evt.event_name || evt.name || evt.type || '').trim().toLowerCase();
    const data = evt.data && typeof evt.data === 'object' && !Array.isArray(evt.data) ? evt.data : {};
    const reason = String(data.reason || '').trim().toLowerCase();
    if (name === 'routine_rules_fallback' && reason === 'contract_module_missing') return true;
  }
  return false;
}

function hasKnownFieldReaskInText({ profile, text, cards }) {
  const p = profile && typeof profile === 'object' && !Array.isArray(profile) ? profile : {};
  const composite = `${String(text || '')}\n${JSON.stringify(Array.isArray(cards) ? cards : [])}`;
  const hasQuestionHint = /(\?|which|what|是否|还是|哪种|确认|how)/i.test(composite);
  if (!hasQuestionHint) return false;
  if (typeof p.skinType === 'string' && p.skinType.trim() && /(skin type|肤质|油皮|混油|混干|干皮)/i.test(composite)) return true;
  if (typeof p.sensitivity === 'string' && p.sensitivity.trim() && /(sensitivity|sensitive|敏感度)/i.test(composite)) return true;
  if (typeof p.barrierStatus === 'string' && p.barrierStatus.trim() && /(barrier|屏障(状态|受损)?)/i.test(composite)) return true;
  if (Array.isArray(p.goals) && p.goals.length && /(goals?|concerns?|目标|诉求)/i.test(composite)) return true;
  if (typeof p.pregnancy_status === 'string' && p.pregnancy_status.trim() && /(pregnan|怀孕|孕周|备孕)/i.test(composite)) return true;
  if (typeof p.lactation_status === 'string' && p.lactation_status.trim() && /(lactat|breastfeed|哺乳)/i.test(composite)) return true;
  return false;
}

function findRoutineExpertNodeFromEnvelope(envelope) {
  const cards = Array.isArray(envelope && envelope.cards) ? envelope.cards : [];
  for (const card of cards) {
    if (!card || typeof card !== 'object' || Array.isArray(card)) continue;
    const type = String(card.type || '').trim().toLowerCase();
    if (type !== 'analysis_summary') continue;
    const payload = card.payload && typeof card.payload === 'object' && !Array.isArray(card.payload) ? card.payload : {};
    const analysis = payload.analysis && typeof payload.analysis === 'object' && !Array.isArray(payload.analysis) ? payload.analysis : {};
    const expert = analysis.routine_expert && typeof analysis.routine_expert === 'object' && !Array.isArray(analysis.routine_expert)
      ? analysis.routine_expert
      : null;
    if (expert) return expert;
  }
  return null;
}

function hasRoutineExpertRequiredModules(expert) {
  if (!expert || typeof expert !== 'object' || Array.isArray(expert)) return false;
  const hasSnapshot = expert.snapshot && typeof expert.snapshot === 'object' && !Array.isArray(expert.snapshot);
  const hasIssues = Array.isArray(expert.key_issues) && expert.key_issues.length > 0;
  const hasPhase = expert.phase_plan && typeof expert.phase_plan === 'object' && !Array.isArray(expert.phase_plan);
  const hasPlan7d = expert.plan_7d && typeof expert.plan_7d === 'object' && !Array.isArray(expert.plan_7d);
  const hasPrimaryQuestion = typeof expert.primary_question === 'string' && expert.primary_question.trim().length > 0;
  return hasSnapshot && hasIssues && hasPhase && hasPlan7d && hasPrimaryQuestion;
}

function isRoutineContractIntent(intent) {
  const value = String(intent || '').trim().toLowerCase();
  return (
    value === String(INTENT_ENUM.ROUTINE || '').trim().toLowerCase() ||
    value === String(INTENT_ENUM.INGREDIENT_SCIENCE || '').trim().toLowerCase() ||
    value === String(INTENT_ENUM.TRAVEL_PLANNING || '').trim().toLowerCase() ||
    value === String(INTENT_ENUM.WEATHER_ENV || '').trim().toLowerCase() ||
    value === String(INTENT_ENUM.CONFLICT_CHECK || '').trim().toLowerCase()
  );
}

function buildRoutineRulesOnlyFallbackCardsForChat({ ctx, message, profile, recentLogs, language, reason } = {}) {
  const expert = buildRulesOnlyRoutineExpertFromContext({ message, profile, recentLogs, language });
  const noticeReason = String(reason || '').trim().toLowerCase() === 'timeout_degraded' ? 'timeout_degraded' : 'default';
  return [
    {
      card_id: `analysis_${ctx && ctx.request_id ? ctx.request_id : Date.now()}_rules`,
      type: 'analysis_summary',
      payload: {
        analysis_source: noticeReason === 'timeout_degraded' ? 'rules_only_timeout_degraded' : 'rules_only_fallback',
        low_confidence: true,
        analysis: {
          routine_expert: expert,
        },
      },
    },
    {
      card_id: `conf_${ctx && ctx.request_id ? ctx.request_id : Date.now()}_rules`,
      type: 'confidence_notice',
      payload: buildConfidenceNoticeCardPayload({
        language,
        reason: noticeReason,
        confidence: {
          score: noticeReason === 'timeout_degraded' ? 0.35 : 0.42,
          level: 'low',
          rationale: ['rules_only_fallback'],
        },
        actions: ['continue_routine_intake', 'retry_routine_generation'],
        details: ['rules_only_structured_fallback'],
      }),
    },
  ];
}

function evaluateQualityContractForEnvelope({ envelope, policyMeta, assistantText, profile } = {}) {
  const cards = Array.isArray(envelope && envelope.cards) ? envelope.cards : [];
  const intent = String(policyMeta && policyMeta.intent_canonical ? policyMeta.intent_canonical : '').trim().toLowerCase();
  const placeholderStall = looksLikeMockPlaceholder(assistantText);
  const phraseStall = looksLikeStallPhrase(assistantText) && !hasRenderableCards(cards);
  const gateOnlyStall =
    isGateOnlyResponse(cards) &&
    (isActionIntentForQuality(policyMeta && policyMeta.user_intent) || isRoutineContractIntent(intent)) &&
    !hasMinimumExecutableStepsForQuality(assistantText, cards);
  const stallHit = Boolean(placeholderStall || phraseStall || gateOnlyStall);
  const critical = [];
  if (placeholderStall) critical.push('stall_fail_placeholder');
  if (gateOnlyStall) critical.push('stall_fail_gate_only');
  if (!placeholderStall && !gateOnlyStall && phraseStall) critical.push('stall_fail');

  const missingModules = [];
  const moduleFailFromDegradedSignal = hasDegradedModuleFailSignal(envelope);
  if (isRoutineContractIntent(intent)) {
    const expert = findRoutineExpertNodeFromEnvelope(envelope);
    if (!hasRoutineExpertRequiredModules(expert)) {
      critical.push('module_fail');
      missingModules.push('required_modules_missing');
    }
  }
  if (moduleFailFromDegradedSignal) {
    critical.push('module_fail_from_degraded_signal');
    missingModules.push('module_fail_from_degraded_signal');
  }

  const summaryText = JSON.stringify(cards).toLowerCase();
  if (/(makeup brush|blush brush|化妆刷|彩妆刷)/.test(summaryText)) {
    critical.push('catalog_poison_fail');
  }

  const urlInvariantPass = !hasMissingRecommendationPurchasePath(cards);
  if (!urlInvariantPass) {
    critical.push('missing_product_urls_in_recommendations');
  }

  const knownFieldReask = hasKnownFieldReaskInText({ profile, text: assistantText, cards });
  if (knownFieldReask) {
    critical.push('entity_miss_fail_seed_profile');
  }

  return {
    version: 'routine_expert.strict_quality_contract.v3',
    contract_pass: critical.length === 0,
    stall_hit: stallHit,
    missing_modules: Array.from(new Set(missingModules)),
    url_invariant_pass: urlInvariantPass,
    strict_fail_flags: {
      stall_fail_placeholder: placeholderStall,
      stall_fail_gate_only: gateOnlyStall,
      module_fail_from_degraded_signal: moduleFailFromDegradedSignal,
      missing_product_urls_in_recommendations: !urlInvariantPass,
      entity_miss_fail_seed_profile: knownFieldReask,
    },
    critical_fail_reasons: Array.from(new Set(critical)),
  };
}

function getCardPayload(card) {
  if (!card || typeof card !== 'object') return null;
  if (isPlainObject(card.payload)) return card.payload;
  return isPlainObject(card) ? card : null;
}

function inferRouteFromCards(cards) {
  const list = Array.isArray(cards) ? cards.filter((c) => c && typeof c === 'object') : [];
  const byType = new Map();
  for (const c of list) {
    const type = String(c.type || '').trim();
    if (!type) continue;
    if (!byType.has(type)) byType.set(type, c);
  }

  if (byType.has('routine_simulation') || byType.has('conflict_heatmap')) {
    const card = byType.get('routine_simulation') || byType.get('conflict_heatmap');
    return { route: 'conflict', payload: getCardPayload(card) };
  }
  if (byType.has('env_stress')) {
    return { route: 'env', payload: getCardPayload(byType.get('env_stress')) };
  }
  if (byType.has('product_analysis')) {
    return { route: 'fit-check', payload: getCardPayload(byType.get('product_analysis')) };
  }
  if (byType.has('recommendations')) {
    return { route: 'reco', payload: getCardPayload(byType.get('recommendations')) };
  }
  return null;
}

function inferRouteFromMessageIntent(message, { allowRecoCards } = {}) {
  if (looksLikeCompatibilityOrConflictQuestion(message)) return { route: 'conflict', payload: {} };
  if (looksLikeWeatherOrEnvironmentQuestion(message)) return { route: 'env', payload: {} };
  if (looksLikeSuitabilityRequest(message)) return { route: 'fit-check', payload: {} };
  if (allowRecoCards && looksLikeRecommendationRequest(message)) return { route: 'reco', payload: {} };
  return null;
}

function resolveRouteHint(fromCards, fromMessage) {
  const cardRoute = String(fromCards?.route || '').trim();
  const messageRoute = String(fromMessage?.route || '').trim();
  if (!cardRoute) return fromMessage || null;
  if (!messageRoute) return fromCards || null;

  const explicitMessageRoutes = new Set(['fit-check', 'conflict', 'env']);
  if (explicitMessageRoutes.has(messageRoute)) {
    if (cardRoute === 'reco') return fromMessage;
    if (cardRoute === messageRoute) return fromCards;
  }
  return fromCards;
}

function summarizeProfileForAnswer(profile, lang) {
  const p = isPlainObject(profile) ? profile : {};
  const skinType = typeof p.skinType === 'string' ? p.skinType.trim() : '';
  const sensitivity = typeof p.sensitivity === 'string' ? p.sensitivity.trim() : '';
  const barrier = typeof p.barrierStatus === 'string' ? p.barrierStatus.trim() : '';
  const goals = asStringArray(p.goals, 4);
  if (lang === 'CN') {
    const left = [skinType || '肤质待补充', sensitivity ? `${sensitivity}敏` : '敏感度待补充', barrier || '屏障状态待补充'];
    const goalText = goals.length ? `目标：${goals.join('、')}` : '目标：待补充';
    return `${left.join(' / ')}；${goalText}。`;
  }
  const left = [skinType || 'skin type pending', sensitivity ? `${sensitivity} sensitivity` : 'sensitivity pending', barrier || 'barrier pending'];
  const goalText = goals.length ? `Goals: ${goals.join(', ')}` : 'Goals: pending';
  return `${left.join(' / ')}; ${goalText}.`;
}

function pickRecoNames(payload, max = 3) {
  const recos = Array.isArray(payload && payload.recommendations) ? payload.recommendations : [];
  const out = [];
  const seen = new Set();
  for (const r of recos) {
    if (!r || typeof r !== 'object') continue;
    const sku = isPlainObject(r.sku) ? r.sku : isPlainObject(r.product) ? r.product : null;
    const brand = typeof sku?.brand === 'string' ? sku.brand.trim() : '';
    const name = typeof sku?.name === 'string' ? sku.name.trim() : '';
    const title = [brand, name].filter(Boolean).join(' ').trim() || (typeof r.title === 'string' ? r.title.trim() : '');
    if (!title) continue;
    const key = title.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(title);
    if (out.length >= max) break;
  }
  return out;
}

function buildRouteAwareAssistantText({ route, payload, language, profile }) {
  const lang = language === 'CN' ? 'CN' : 'EN';
  const p = isPlainObject(payload) ? payload : {};
  const profileLine = summarizeProfileForAnswer(profile, lang);

  if (route === 'fit-check') {
    const assessment = isPlainObject(p.assessment) ? p.assessment : {};
    const verdict = String(assessment.verdict || '').trim() || (lang === 'CN' ? '谨慎可试' : 'Cautious to try');
    const reasons = asStringArray(assessment.reasons, 6);
    const riskLines = reasons.filter((r) => /风险|刺激|刺痛|泛红|risk|irritat|sting|burn/i.test(r));
    const fitLines = reasons.filter((r) => !riskLines.includes(r));
    const risk = (riskLines.length ? riskLines : reasons).slice(0, 2);
    const fit = (fitLines.length ? fitLines : reasons).slice(0, 2);

    if (lang === 'CN') {
      return [
        `结论：${verdict}（先看耐受，再决定是否长期用）。`,
        `你的情况：${profileLine}`,
        '风险点：',
        ...(risk.length ? risk.map((r) => `- ${r}`) : ['- 若近期有刺痛/爆皮，需先降频并修护屏障。']),
        '更稳妥替代方向：',
        ...(fit.length ? fit.map((r) => `- 可优先考虑：${r}`) : ['- 先选低刺激、简配方、无香精版本。']),
        '怎么用（频率/顺序/观察周期）：',
        '- 先每周 2-3 次，晚间使用；连续 2-4 周观察再决定是否加频。',
        '- 早上务必防晒（SPF30+），并避免同晚叠加强酸/高强度活性。',
        '停用信号：出现持续刺痛、明显泛红或爆皮时先停用 3-5 天，仅保湿修护；持续加重请就医。',
      ].join('\n');
    }

    return [
      `Verdict: ${verdict} (start cautiously, then scale only if tolerated).`,
      `Your profile: ${profileLine}`,
      'Risk points:',
      ...(risk.length ? risk.map((r) => `- ${r}`) : ['- If stinging/peeling is active, reduce frequency and prioritize barrier repair.']),
      'Safer alternatives:',
      ...(fit.length ? fit.map((r) => `- Consider: ${r}`) : ['- Prefer low-irritation, simple, fragrance-free options first.']),
      'How to use (frequency/order/timeline):',
      '- Start at 2-3 nights/week; reassess after 2-4 weeks before increasing.',
      '- Use sunscreen every morning (SPF30+), and avoid stacking multiple strong actives in one night.',
      'Stop signals: pause if persistent stinging/redness/peeling, switch to barrier repair only, and seek dermatology care if worsening.',
    ].join('\n');
  }

  if (route === 'reco') {
    const names = pickRecoNames(p, 3);
    const topNames = names.length ? names : [lang === 'CN' ? '温和修护类精华' : 'gentle barrier-support serum'];
    if (lang === 'CN') {
      return [
        `目标与前提：${profileLine}`,
        '最小可行清单（早/晚）：',
        '- AM：温和清洁 → 保湿/功效精华（低刺激）→ 防晒。',
        '- PM：温和清洁 → 单一主活性（低频）→ 保湿修护。',
        '成分方向（Top 3）：',
        `- 方向 1：烟酰胺/神经酰胺（兼顾提亮与屏障支持）`,
        `- 方向 2：壬二酸/温和抗炎路线（痘印与泛红更稳）`,
        `- 方向 3：保湿舒缓体系（甘油/透明质酸/角鲨烷）`,
        `可优先看的示例：${topNames.join('、')}。`,
        '一周引入计划：',
        '- 第 1-3 天：只保留基础清洁+保湿+防晒，先稳耐受。',
        '- 第 4-7 天：单一活性每周 2-3 次起步，其余晚修护保湿。',
        '- 观察 2-4 周再加频；若刺痛/泛红/爆皮，立即降频或停用新活性。',
        '怎么选（选购标准）：',
        '- 优先考虑：低刺激、配方简洁、与你目标匹配的单一主活性。',
        '- 筛选原则：先看耐受和可持续性，再看叠加数量，避免一次上太多功效。',
        '红旗信号：',
        '- 若出现持续刺痛、明显泛红或爆皮，先停新活性 3-5 天，仅做修护保湿；持续加重请就医。',
      ].join('\n');
    }

    return [
      `Goal & context: ${profileLine}`,
      'Minimum viable routine (AM/PM):',
      '- AM: gentle cleanse → treatment/hydration → sunscreen.',
      '- PM: gentle cleanse → one core active (low frequency) → barrier moisturizer.',
      'Ingredient directions (Top 3):',
      '- Direction 1: niacinamide/ceramide for brightening + barrier support.',
      '- Direction 2: azelaic-acid-friendly, low-irritation anti-redness path.',
      '- Direction 3: hydration-soothing base (glycerin/HA/squalane).',
      `Sample options to review first: ${topNames.join(', ')}.`,
      'One-week onboarding plan:',
      '- Days 1-3: keep only cleanse + moisturizer + sunscreen to stabilize tolerance.',
      '- Days 4-7: introduce one active at 2-3 nights/week; keep recovery nights in between.',
      '- Reassess after 2-4 weeks and scale only if skin stays stable.',
      'Buying criteria (how to choose):',
      '- Look for low-irritation, simple formulas and one clear active aligned to your goal.',
      '- Prioritize tolerability and consistency before stacking more products.',
      'Red flags:',
      '- Pause new actives if persistent stinging/redness/peeling appears; switch to barrier repair and seek care if worsening.',
    ].join('\n');
  }

  if (route === 'conflict') {
    const conflicts = Array.isArray(p.conflicts) ? p.conflicts : [];
    const safe = Boolean(p.safe);
    const conflictMessages = asStringArray(conflicts.map((c) => (isPlainObject(c) ? c.message : null)), 3);
    if (lang === 'CN') {
      return [
        safe ? '冲突判断：当前未发现明显冲突。' : '冲突判断：检测到活性叠加冲突风险。',
        '冲突原因：',
        ...(conflictMessages.length
          ? conflictMessages.map((m) => `- ${m}`)
          : ['- 同晚叠加强活性会让刺激风险上升，耐受不稳时更容易泛红/爆皮。']),
        '安全排班（错开使用）：',
        '- AM：温和清洁 → 保湿 → 防晒。',
        '- PM：活性 A 与活性 B 交替晚用（例如周一/周四 A，周二/周五 B），中间留修护晚。',
        '- 先从每周 2-3 次起步，耐受稳定后再加频。',
        '优先级取舍：',
        '- 优先保留一个主活性先做满 2-4 周，再决定是否加入第二个活性。',
        '- 如果目标是“先稳后进”，优先减少叠加数量而不是提高浓度。',
        '停用信号：出现持续刺痛、明显泛红、爆皮时先停用新活性，仅做修护保湿；若持续恶化请就医。',
      ].join('\n');
    }

    return [
      safe ? 'Conflict check: no major conflict detected right now.' : 'Conflict check: potential active-stacking risk detected.',
      'Conflict reason:',
      ...(conflictMessages.length
        ? conflictMessages.map((m) => `- ${m}`)
        : ['- Layering strong actives in the same night can increase irritation and reduce tolerance.']),
      'Safer schedule (alternate use):',
      '- AM: gentle cleanse → moisturizer → sunscreen.',
      '- PM: alternate active A and active B on different nights; keep recovery nights between them.',
      '- Start at 2-3 active nights/week, then increase only after stable tolerance.',
      'Priority choices:',
      '- Keep one core active first for 2-4 weeks before adding a second active.',
      '- Prioritize lower stacking load before increasing concentration.',
      'Stop signals: pause new actives if persistent stinging/redness/peeling appears; switch to barrier repair only and seek care if worsening.',
    ].join('\n');
  }

  if (route === 'env') {
    const tier = typeof p.tier === 'string' ? p.tier.trim() : '';
    const ess = Number.isFinite(Number(p.ess)) ? Number(p.ess) : null;
    const notes = asStringArray(p.notes, 3);
    if (lang === 'CN') {
      return [
        `环境判断：当前环境压力 ${tier || '待评估'}${ess != null ? `（ESS ${Math.round(ess)}）` : ''}。`,
        notes.length ? `环境线索：${notes.join('；')}` : '环境线索：以天气变化为主，先做保守调整。',
        '加什么 / 减什么 / 替换什么：',
        '- 加：修护保湿（神经酰胺、甘油、角鲨烷等）与舒缓产品。',
        '- 减：同晚多活性叠加、高清洁力和高频去角质。',
        '- 替换：把刺激型活性改为低频或更温和版本。',
        '频率调整：',
        '- 活性先降到每周 2-3 次；其余晚以保湿修护为主。',
        '- 天气骤变期优先稳住 3-7 天，再逐步恢复原计划。',
        '临时极简方案：',
        '- 早晚都用“温和清洁 + 保湿修护”，白天固定防晒；先稳住再加功效。',
        '防晒/保湿策略：',
        '- 白天坚持 SPF30+ 并按需补涂；室内干燥时增加保湿层与补水频次。',
      ].join('\n');
    }

    return [
      `Environment check: stress level is ${tier || 'pending'}${ess != null ? ` (ESS ${Math.round(ess)})` : ''}.`,
      notes.length ? `Context clues: ${notes.join('; ')}` : 'Context clues: keep adjustments conservative while conditions shift.',
      'Add / remove / replace:',
      '- Add: barrier-support hydration and soothing layers.',
      '- Remove: same-night multi-active stacking and frequent strong exfoliation.',
      '- Replace: high-irritation steps with lower-frequency, gentler options.',
      'Frequency adjustment:',
      '- Reduce actives to 2-3 nights/week; keep recovery-focused nights in between.',
      '- Stabilize for 3-7 days during weather swings before ramping back up.',
      'Temporary minimal plan:',
      '- Keep cleanse + barrier moisturizer AM/PM, and hold high-irritation actives during unstable weather days.',
      'Sun/moisture strategy:',
      '- Keep daily SPF30+ and reapply as needed; increase moisturizer support in dry indoor air.',
    ].join('\n');
  }

  return '';
}

function coerceNumber(value) {
  if (value == null) return null;
  if (typeof value === 'number') return Number.isFinite(value) ? value : null;
  if (typeof value === 'string') {
    const n = Number(value);
    return Number.isFinite(n) ? n : null;
  }
  return null;
}

function clamp0to100(value) {
  if (!Number.isFinite(value)) return 0;
  return Math.max(0, Math.min(100, value));
}

function titleCase(value) {
  const t = String(value || '').trim();
  if (!t) return t;
  return t.charAt(0).toUpperCase() + t.slice(1);
}

function buildEnvStressUiModelFromUpstream(value, { language } = {}) {
  if (!isPlainObject(value)) return null;
  const schema = typeof value.schema_version === 'string' ? value.schema_version : '';

  if (schema === 'aurora.ui.env_stress.v1') return value;
  if (schema !== 'aurora.env_stress.v1') return null;

  const essRaw = coerceNumber(value.ess);
  const ess = essRaw == null ? null : clamp0to100(essRaw);
  const tier = typeof value.tier === 'string' ? value.tier.trim() || null : null;

  const contributors = Array.isArray(value.contributors) ? value.contributors : [];
  const weights = contributors.map((c) => {
    if (!isPlainObject(c)) return null;
    const w = coerceNumber(c.weight);
    return w == null || w < 0 ? null : w;
  });

  const weightSum = weights.reduce((acc, w) => acc + (w ?? 0), 0);
  const denom = weightSum > 0 ? weightSum : contributors.length;

  const radar = [];
  for (let i = 0; i < contributors.length; i += 1) {
    const c = contributors[i];
    if (!isPlainObject(c)) continue;
    const axisRaw = typeof c.key === 'string' ? c.key.trim() : '';
    if (!axisRaw) continue;
    const w = weightSum > 0 ? (weights[i] ?? 0) / denom : 1 / denom;
    const v = ess == null ? 0 : clamp0to100(Math.round(ess * w));
    radar.push({ axis: titleCase(axisRaw).slice(0, 40), value: v });
    if (radar.length >= 8) break;
  }

  const notes = [];
  const missing = Array.isArray(value.missing_inputs) ? value.missing_inputs : [];
  const missingFlat = missing.map((m) => String(m || '').trim()).filter(Boolean);
  if (missingFlat.length) {
    notes.push(
      language === 'CN'
        ? `缺少：${missingFlat.slice(0, 4).join(' / ')}`
        : `Missing: ${missingFlat.slice(0, 4).join(' / ')}`,
    );
  }

  for (const c of contributors) {
    if (!isPlainObject(c)) continue;
    const note = typeof c.note === 'string' ? c.note.trim() : '';
    if (!note) continue;
    notes.push(note.slice(0, 220));
    if (notes.length >= 4) break;
  }

  return {
    schema_version: 'aurora.ui.env_stress.v1',
    ess,
    tier,
    radar,
    notes,
  };
}

function looksLikeWeatherOrEnvironmentQuestion(message) {
  const t = String(message || '').trim();
  if (!t) return false;

  const lower = t.toLowerCase();

  // English
  if (
    /\b(snow|rain|weather|humidity|uv|climate|wind|dry air|cold|heat|sun exposure|travel|itinerary|destination|flight|ski)\b/i.test(
      lower,
    )
  )
    return true;

  // Chinese (keep focused on environment, not general skin symptoms)
  if (
    /(下雪|雪天|下雨|雨天|天气|气温|温度|湿度|紫外线|UV|风大|大风|寒冷|冷空气|高温|热浪|干燥(空气|天气)?|雾霾|污染|花粉|旅行|出差|飞行|飞机|高原|海边|滑雪|户外)/.test(
      t,
    )
  )
    return true;

  return false;
}

function extractWeatherScenario(message) {
  const t = String(message || '').trim();
  if (!t) return 'unknown';
  const lower = t.toLowerCase();

  if (/(下雪|雪天|滑雪)/.test(t) || /\bsnow|ski\b/i.test(lower)) return 'snow';
  if (/(下雨|雨天|暴雨)/.test(t) || /\brain|storm\b/i.test(lower)) return 'rain';
  if (/(紫外线|UV|日晒|阳光|晒)/.test(t) || /\buv|sun|sunlight\b/i.test(lower)) return 'uv';
  if (/(湿度|潮湿|闷热)/.test(t) || /\bhumid|humidity\b/i.test(lower)) return 'humid';
  if (/(干燥|干冷|冷空气)/.test(t) || /\bdry air|dry|dehydrating\b/i.test(lower)) return 'dry';
  if (/(寒冷|冷|低温)/.test(t) || /\bcold|freez(e|ing)\b/i.test(lower)) return 'cold';
  if (/(大风|风大|风|刮风)/.test(t) || /\bwind|windy\b/i.test(lower)) return 'wind';
  if (/(旅行|出差|飞行|飞机|高原|海边)/.test(t) || /\btravel|flight|itinerary|destination\b/i.test(lower)) return 'travel';
  return 'unknown';
}

function normalizeTravelWeatherReason({ weather, liveWeatherEnabled }) {
  if (!liveWeatherEnabled) return 'live_disabled';
  const source = String(weather && weather.source ? weather.source : '').trim().toLowerCase();
  if (source === 'weather_api') return 'live_ok';
  const reason = String(weather && weather.reason ? weather.reason : '').trim().toLowerCase();
  if (reason.includes('timeout')) return 'live_timeout';
  if (reason.includes('http_')) return 'live_http_error';
  if (reason.startsWith('geocode_')) return 'geocode_failed';
  return 'live_error';
}

function normalizeIsoTimestamp(value) {
  const text = String(value || '').trim();
  if (!text) return '';
  const ms = Date.parse(text);
  if (!Number.isFinite(ms)) return '';
  try {
    return new Date(ms).toISOString();
  } catch (_err) {
    return '';
  }
}

function maxTravelDataFreshness({ weather, alertsResult }) {
  const candidates = [
    normalizeIsoTimestamp(weather && weather.data_freshness_utc),
    normalizeIsoTimestamp(alertsResult && alertsResult.data_freshness_utc),
  ].filter(Boolean);
  if (!candidates.length) return new Date().toISOString();
  let latest = candidates[0];
  let latestMs = Date.parse(latest);
  for (const token of candidates.slice(1)) {
    const ms = Date.parse(token);
    if (Number.isFinite(ms) && ms > latestMs) {
      latest = token;
      latestMs = ms;
    }
  }
  return latest;
}

function sanitizeTravelReadiness(travelReadiness) {
  const payload = isPlainObject(travelReadiness) ? { ...travelReadiness } : {};
  const deltaVsHome = isPlainObject(payload.delta_vs_home) ? { ...payload.delta_vs_home } : null;
  if (!deltaVsHome) {
    return {
      travelReadiness: payload,
      baselineIntegrity: 'missing',
    };
  }

  const baselineStatus = String(deltaVsHome.baseline_status || '').trim().toLowerCase();
  if (baselineStatus !== 'baseline_unavailable') {
    return {
      travelReadiness: { ...payload, delta_vs_home: deltaVsHome },
      baselineIntegrity: 'ok',
    };
  }

  const metricKeys = ['temperature', 'humidity', 'uv', 'wind', 'precip'];
  let hadInvalidBaseline = false;
  for (const key of metricKeys) {
    const row = isPlainObject(deltaVsHome[key]) ? { ...deltaVsHome[key] } : null;
    if (!row) continue;

    const hasHome = row.home !== null && row.home !== undefined;
    const hasDelta = row.delta !== null && row.delta !== undefined;
    if (hasHome || hasDelta) hadInvalidBaseline = true;

    row.home = null;
    row.delta = null;
    deltaVsHome[key] = row;
  }

  return {
    travelReadiness: {
      ...payload,
      delta_vs_home: deltaVsHome,
    },
    baselineIntegrity: hadInvalidBaseline ? 'invalid_zero_coercion' : 'missing',
  };
}

function looksLikeTravelCardRequest(message) {
  const text = String(message || '').trim();
  if (!text) return false;
  const lower = text.toLowerCase();
  if (/\b(card|chart|radar|graph|show details|full details|full delta|all metrics)\b/i.test(lower)) return true;
  if (/(卡片|图示|图表|雷达|完整差异|详细指标|全部指标|展开详情)/.test(text)) return true;
  return false;
}

function buildTravelQuestionHash(message) {
  const normalized = String(message || '')
    .trim()
    .toLowerCase()
    .replace(/\s+/g, ' ');
  if (!normalized) return '';
  return crypto.createHash('sha1').update(normalized).digest('hex').slice(0, 16);
}

function extractKnownActivesFromText(text, language = 'EN') {
  const t = String(text || '').trim();
  if (!t) return [];
  const lower = t.toLowerCase();
  const lang = String(language || '').toUpperCase() === 'CN' ? 'CN' : 'EN';
  // Some CN inputs may contain spaces between characters (e.g. "阿达 帕林", "维 A").
  // Keep an additional whitespace-stripped view for conservative CN matching.
  const compact = t.replace(/\s+/g, '');
  const out = [];

  const push = (token) => {
    const key = String(token || '').trim().toLowerCase();
    if (!key) return;
    if (!out.includes(key)) out.push(key);
  };

  const conceptIds = collectConceptIdsFromText({
    text: t,
    language: lang,
    max: 64,
    includeSubstring: true,
  });
  for (const token of mapConceptsToRoutineActiveTokens(conceptIds)) {
    push(token);
  }

  const ontologyHits = matchIngredientOntology({
    text: t,
    language: lang,
    max: 32,
  });
  for (const row of ontologyHits) {
    if (!row || typeof row !== 'object') continue;
    for (const token of mapConceptsToRoutineActiveTokens(row.classes || [])) {
      push(token);
    }
  }

  // NOTE: This is used for routing + local compatibility simulation. Keep it conservative but multilingual.
  // EN: tretinoin/adapalene/retinal/retinol/retinoid
  // CN: 阿达帕林 / 维A(类)/维A酸 / 维甲酸 / 视黄醇/视黄醛 / A醇/A酸
  if (
    /(tretinoin|adapalene|retinal|retinol|retinoid)/i.test(lower) ||
    /(阿达帕林|维a类|维a酸|维a|维甲酸|维甲|视黄醇|视黄醛|a醇|a酸)/i.test(compact)
  ) {
    push('retinoid');
  }
  // Strong acids: BHA (salicylic) / AHA (glycolic/lactic/mandelic) / PHA.
  // CN: 水杨酸 / 果酸(甘醇酸/乳酸/杏仁酸) / PHA(葡糖酸内酯)
  // Treat PHA as "aha" for conflict heuristics (retinoid_x_acids includes AHA/BHA/PHA).
  if (/(benzoyl\s*peroxide|bpo)/i.test(lower)) push('benzoyl_peroxide');
  if (/(过氧化苯甲酰)/i.test(compact)) push('benzoyl_peroxide');
  if (/(salicylic|bha)/i.test(lower) || /(水杨酸)/i.test(compact)) push('bha');
  if (
    /(glycolic|lactic|mandelic|aha|pha|gluconolactone)/i.test(lower) ||
    /(果酸|甘醇酸|乙醇酸|乳酸|杏仁酸|葡糖酸内酯)/i.test(compact)
  ) {
    push('aha');
  }
  if (/(vitamin\s*c|ascorbic|l-ascorbic|ascorbate)/i.test(lower)) push('vitamin_c');
  if (/(维c|维生素c|抗坏血酸)/i.test(compact)) push('vitamin_c');
  if (/(niacinamide)/i.test(lower) || /(烟酰胺)/i.test(compact)) push('niacinamide');
  if (/(azelaic)/i.test(lower) || /(壬二酸)/i.test(compact)) push('azelaic_acid');
  if (/(tranexamic)/i.test(lower) || /(传明酸|氨甲环酸)/i.test(compact)) push('tranexamic_acid');

  return out;
}

function collectKnownActivesFromRoutine(routine) {
  const routineObj = routine && typeof routine === 'object' ? routine : {};
  const am = Array.isArray(routineObj.am) ? routineObj.am : [];
  const pm = Array.isArray(routineObj.pm) ? routineObj.pm : [];
  const out = [];
  const seen = new Set();

  const push = (token) => {
    const key = String(token || '').trim().toLowerCase();
    if (!key) return;
    if (seen.has(key)) return;
    seen.add(key);
    out.push(key);
  };

  const scanText = (raw) => {
    const text = String(raw || '');
    const lang = /[\u4e00-\u9fff]/.test(text) ? 'CN' : 'EN';
    const tokens = extractKnownActivesFromText(text, lang);
    for (const t of tokens) push(t);
  };

  const scanItem = (item) => {
    if (!item) return;
    if (typeof item === 'string') {
      scanText(item);
      return;
    }
    if (typeof item !== 'object' || Array.isArray(item)) return;

    const actives = item.key_actives || item.keyActives || item.actives;
    if (Array.isArray(actives)) {
      for (const a of actives) scanText(a);
    }

    const fields = [
      item.step,
      item.category,
      item.slot_step,
      item.slotStep,
      item.title,
      item.name,
      item.display_name,
      item.displayName,
      item.product,
    ];
    for (const f of fields) {
      if (typeof f === 'string' && f.trim()) scanText(f);
    }
  };

  for (const item of am) scanItem(item);
  for (const item of pm) scanItem(item);

  return out;
}

function looksLikeCompatibilityOrConflictQuestion(message) {
  const t = String(message || '').trim();
  if (!t) return false;
  const lower = t.toLowerCase();

  const hasCompatVerbEn =
    /\b(conflict|conflicts|compatible|incompatible|pair|layer|stack|mix|combine|together|same routine|same night|can i add|should i add|with)\b/i.test(
      lower,
    );
  const hasCompatVerbZh = /(冲突|相克|兼容|叠加|同晚|一起用|能不能一起|还能和|搭配|同用)/.test(t);
  if (!(hasCompatVerbEn || hasCompatVerbZh)) return false;

  // Avoid triggering on generic “conflict” questions without any known skincare actives.
  const actives = extractKnownActivesFromText(t, /[\u4e00-\u9fff]/.test(t) ? 'CN' : 'EN');
  return actives.length > 0;
}

function buildLocalCompatibilitySimulationInput({ message, profile } = {}) {
  const text = String(message || '').trim();
  if (!text) return null;
  const language = /[\u4e00-\u9fff]/.test(text) ? 'CN' : 'EN';

  const clauses = text
    .split(/[.?!。！？\n]+/)
    .map((s) => s.trim())
    .filter(Boolean)
    .slice(0, 8);

  let routineText = '';
  let testText = '';
  for (const clause of clauses) {
    const lower = clause.toLowerCase();
    const isRoutineContextEn = /\b(my|i use|i'm using|currently|routine|am|pm|at night|morning)\b/i.test(lower);
    const isRoutineContextZh = /(我(现在|目前|早上|晚上|一直)|我的(早晚)?(流程|步骤|routine)|正在用)/.test(clause);
    const isTestContextEn = /\b(add|can i|layer|stack|mix|combine|together|with|conflict|compatible)\b/i.test(lower);
    const isTestContextZh = /(叠加|同晚|一起用|能不能|还能和|搭配|冲突|兼容|同用)/.test(clause);

    if (isRoutineContextEn || isRoutineContextZh) routineText = `${routineText} ${clause}`.trim();
    if (isTestContextEn || isTestContextZh) testText = `${testText} ${clause}`.trim();
  }

  const all = extractKnownActivesFromText(text, language);
  const routineActives = routineText ? extractKnownActivesFromText(routineText, language) : [];
  const testActives = testText ? extractKnownActivesFromText(testText, language) : [];

  const setEq = (a, b) => {
    const aa = new Set((a || []).map((v) => String(v).toLowerCase()));
    const bb = new Set((b || []).map((v) => String(v).toLowerCase()));
    if (aa.size !== bb.size) return false;
    for (const v of aa) if (!bb.has(v)) return false;
    return true;
  };

  let routineTokens = routineActives;
  let testTokens = testActives;

  if (!routineTokens.length || !testTokens.length || setEq(routineTokens, testTokens)) {
    const has = (tok) => all.includes(tok);
    if (has('retinoid') && (has('aha') || has('bha'))) {
      routineTokens = ['retinoid'];
      testTokens = [...new Set([...(has('aha') ? ['aha'] : []), ...(has('bha') ? ['bha'] : [])])];
    } else if (has('retinoid') && has('benzoyl_peroxide')) {
      routineTokens = ['retinoid'];
      testTokens = ['benzoyl_peroxide'];
    } else if (has('vitamin_c') && (has('aha') || has('bha'))) {
      routineTokens = ['vitamin_c'];
      testTokens = [...new Set([...(has('aha') ? ['aha'] : []), ...(has('bha') ? ['bha'] : [])])];
    } else if (all.length >= 2) {
      routineTokens = [all[0]];
      testTokens = [all[1]];
    } else {
      // If we can’t confidently form a pair from text, don’t short-circuit.
      return null;
    }
  }

  const routineFromProfile =
    profile &&
    profile.currentRoutine &&
    typeof profile.currentRoutine === 'object' &&
    !Array.isArray(profile.currentRoutine) &&
    (Array.isArray(profile.currentRoutine.am) || Array.isArray(profile.currentRoutine.pm))
      ? profile.currentRoutine
      : null;

  const profileRoutineActives = routineFromProfile ? collectKnownActivesFromRoutine(routineFromProfile) : [];
  const shouldUseProfileRoutine = Boolean(
    routineFromProfile && routineTokens.some((t) => profileRoutineActives.includes(String(t || '').toLowerCase())),
  );

  const routine = shouldUseProfileRoutine ? routineFromProfile : {
    am: [],
    pm: routineTokens.length ? [{ step: 'Treatment', key_actives: routineTokens }] : [],
  };

  const testProduct = {
    step: 'Add-on',
    name: testTokens.join(' + ') || 'Test product',
    key_actives: testTokens,
  };

  if (!Array.isArray(testProduct.key_actives) || testProduct.key_actives.length === 0) return null;

  return { routine, testProduct };
}

function buildEnvStressUiModelFromLocal({ profile, recentLogs, message, language } = {}) {
  const lang = language === 'CN' ? 'CN' : 'EN';

  const barrier = String(profile && profile.barrierStatus ? profile.barrierStatus : '').trim().toLowerCase();
  const sensitivity = String(profile && profile.sensitivity ? profile.sensitivity : '').trim().toLowerCase();

  let ess = 35;
  if (barrier === 'impaired' || barrier === 'damaged') ess = 75;
  else if (barrier === 'healthy' || barrier === 'stable') ess = 20;
  else if (barrier) ess = 35;

  if (sensitivity === 'high' || sensitivity === 'sensitive') ess += 10;

  const scenario = extractWeatherScenario(message);
  const bumpMap = {
    snow: 18,
    cold: 15,
    wind: 12,
    dry: 15,
    uv: 15,
    rain: 8,
    humid: 8,
    travel: 12,
    unknown: 6,
  };
  ess += bumpMap[scenario] ?? 6;
  ess = clamp0to100(ess);

  const tier = ess <= 30 ? 'Low' : ess <= 60 ? 'Medium' : 'High';

  const barrierScore = barrier === 'impaired' || barrier === 'damaged' ? 80 : barrier === 'healthy' || barrier === 'stable' ? 20 : 40;
  const weatherScore = scenario === 'snow' || scenario === 'cold' || scenario === 'dry' || scenario === 'wind' ? 70 : scenario === 'rain' || scenario === 'humid' ? 45 : scenario === 'travel' ? 55 : 35;
  const uvScore = scenario === 'uv' || scenario === 'snow' ? 65 : 30;

  const radar = [
    { axis: 'Barrier', value: clamp0to100(barrierScore) },
    { axis: 'Weather', value: clamp0to100(weatherScore) },
    { axis: 'UV', value: clamp0to100(uvScore) },
  ];

  const missing = [];
  if (!String(profile && profile.sensitivity ? profile.sensitivity : '').trim()) missing.push('profile.sensitivity');
  if (!Array.isArray(recentLogs) || recentLogs.length === 0) missing.push('recent_logs');

  const notes = [];
  if (missing.length) {
    notes.push(lang === 'CN' ? `缺少：${missing.slice(0, 4).join(' / ')}` : `Missing: ${missing.slice(0, 4).join(' / ')}`);
  }
  if (barrier) notes.push(`barrier_status=${barrier}`.slice(0, 220));
  if (scenario && scenario !== 'unknown') notes.push((lang === 'CN' ? `场景：${scenario}（推断）` : `Scenario: ${scenario} (inferred)`).slice(0, 220));

  return {
    schema_version: 'aurora.ui.env_stress.v1',
    ess,
    tier,
    radar,
    notes: notes.slice(0, 4),
  };
}

function buildWeatherAdviceMessage({ language, scenario, profile } = {}) {
  const lang = language === 'CN' ? 'CN' : 'EN';
  const skin = String(profile && profile.skinType ? profile.skinType : '').trim();

  const skinLine =
    skin && lang === 'CN'
      ? `你的肤质：${skin}。`
      : skin && lang === 'EN'
        ? `Your skin type: ${skin}.`
        : '';

  if (lang === 'CN') {
    if (scenario === 'snow') {
      return [
        '雪天的皮肤压力通常来自：低温 + 干燥 + 大风 + 雪地反光导致的 UV（更容易晒/更容易干裂）。',
        skinLine,
        '',
        '**护肤要点（优先级从高到低）**',
        '1) **保湿 + 封闭**：面霜稍厚一点；口周/鼻翼/脸颊干处可薄薄封一层凡士林类。',
        '2) **防晒**：即使阴天/下雪也建议 SPF30+；如果户外时间长或雪地强反光，尽量提高防晒强度并注意补涂。',
        '3) **物理防护**：围巾/口罩/帽子减少冷风直吹；干裂倾向的手部建议戴手套。',
        '4) **温和清洁**：避免强清洁/磨砂；回家后用温和洁面即可。',
        '5) **活性减量**：如果你晚上用维A/酸，雪天更容易刺痛；更稳妥是把强酸和维A错开晚用。',
        '',
        '**对应产品清单（按“品类/关键词”找）**',
        '- 温和洁面（低泡/无磨砂）',
        '- 修护面霜（偏屏障修护/保湿）',
        '- 封闭修护（凡士林/修护膏；局部薄涂）',
        '- 防晒（广谱 SPF30+；户外注意补涂）',
        '- 润唇膏 + 护手霜（干裂优先）',
        '',
        '想要我根据你现有产品给你一个「雪天 AM/PM 版本」吗？也可以直接点下面的选项继续。',
      ]
        .filter(Boolean)
        .join('\n');
    }

    if (scenario === 'uv') {
      return [
        '这类问题更像是「紫外线/日晒压力」场景：主要风险是晒黑/反黑、屏障受刺激、炎症后色沉加重。',
        skinLine,
        '',
        '**护肤要点**',
        '1) 防晒优先：足量 SPF30+，户外注意补涂。',
        '2) 轻薄但够保湿：避免晒后紧绷脱皮。',
        '3) 活性分开用：敏感/刺痛时先停酸/维A，先修护。',
      ]
        .filter(Boolean)
        .join('\n');
    }

    return [
      '我把你的问题理解成「天气/环境变化对皮肤的影响」。',
      skinLine,
      '',
      '**通用要点**',
      '1) 保湿与屏障优先（面霜/修护类）。',
      '2) 容易刺痛就先减量/停用强活性（酸/维A）。',
      '3) 白天注意防晒（户外更重要）。',
      '',
      '如果你告诉我你明天大概会在户外多久、以及最近是否有刺痛/爆皮，我可以把建议进一步细化。',
    ]
      .filter(Boolean)
      .join('\n');
  }

  // EN
  if (scenario === 'snow') {
    return [
      'Snowy days usually stress skin via: cold + dry air + wind + higher UV exposure from snow reflection.',
      skinLine,
      '',
      '**Skincare priorities**',
      '1) **Moisturize + seal**: use a richer moisturizer; consider a thin occlusive layer on dry-prone areas.',
      '2) **Sunscreen**: SPF 30+ even on cloudy/snowy days. If you’re outdoors on snow for longer, go higher and reapply.',
      '3) **Physical protection**: scarf/mask/hat for wind; gloves if hands crack easily.',
      '4) **Gentle cleanse**: avoid harsh cleansing or scrubs.',
      '5) **Reduce actives**: if you use retinoids/acids, avoid stacking them on the same night—snowy weather increases irritation risk.',
      '',
      '**Product-type checklist**',
      '- Gentle cleanser',
      '- Barrier-support moisturizer',
      '- Occlusive (petrolatum/ointment) for dry spots',
      '- Broad-spectrum SPF 30+',
      '- Lip balm + hand cream',
      '',
      'Want me to adapt this into a simple AM/PM “snow day routine” for what you already use?',
    ]
      .filter(Boolean)
      .join('\n');
  }

  return [
    'I’m treating this as a “weather / environment stress” question for skin.',
    skinLine,
    '',
    '**General guidance**',
    '1) Prioritize barrier support (moisturizer, gentle routine).',
    '2) If you feel stinging/flaking, reduce strong actives (acids/retinoids).',
    '3) Use sunscreen for outdoor exposure.',
  ]
    .filter(Boolean)
    .join('\n');
}

function mergeExternalVerificationIntoStructured(structured, contextRaw) {
  const s = isPlainObject(structured) ? structured : null;
  if (!s) return structured;

  const hasExt = isPlainObject(s.external_verification) || isPlainObject(s.externalVerification);
  if (hasExt) return structured;

  const ctx = isPlainObject(contextRaw) ? contextRaw : null;
  if (!ctx) return structured;

  const ext = isPlainObject(ctx.external_verification) ? ctx.external_verification : isPlainObject(ctx.externalVerification) ? ctx.externalVerification : null;
  if (!ext) return structured;

  return { ...s, external_verification: ext };
}

function buildProductInputText(inputObj, url) {
  if (typeof url === 'string' && url.trim()) return url.trim();
  const o = inputObj && typeof inputObj === 'object' && !Array.isArray(inputObj) ? inputObj : null;
  if (!o) return null;
  const brand = typeof o.brand === 'string' ? o.brand.trim() : '';
  const name = typeof o.name === 'string' ? o.name.trim() : '';
  const display = typeof o.display_name === 'string' ? o.display_name.trim() : typeof o.displayName === 'string' ? o.displayName.trim() : '';
  const sku = typeof o.sku_id === 'string' ? o.sku_id.trim() : typeof o.skuId === 'string' ? o.skuId.trim() : '';
  const pid = typeof o.product_id === 'string' ? o.product_id.trim() : typeof o.productId === 'string' ? o.productId.trim() : '';
  const bestName = display || name;
  if (brand && bestName) return joinBrandAndName(brand, bestName);
  if (bestName) return bestName;
  if (sku) return sku;
  if (pid) return pid;
  return null;
}

function pickFirstTrimmed(...values) {
  for (const raw of values) {
    const s = typeof raw === 'string' ? raw.trim() : '';
    if (s) return s;
  }
  return '';
}

function joinBrandAndName(brandRaw, nameRaw) {
  const brand = String(brandRaw || '').trim();
  const name = String(nameRaw || '').trim();
  if (!brand) return name;
  if (!name) return brand;
  const brandLower = brand.toLowerCase();
  const nameLower = name.toLowerCase();
  if (nameLower === brandLower || nameLower.startsWith(`${brandLower} `)) return name;
  return `${brand} ${name}`.trim();
}

function isUuidLikeString(value) {
  return typeof value === 'string' && /^[0-9a-f]{8}(?:-[0-9a-f]{4}){3}-[0-9a-f]{12}$/i.test(String(value || '').trim());
}

function normalizeCanonicalProductRef(input, { requireMerchant = true, allowOpaqueProductId = true } = {}) {
  const ref = input && typeof input === 'object' && !Array.isArray(input) ? input : null;
  if (!ref) return null;
  const productId = pickFirstTrimmed(ref.product_id, ref.productId);
  const merchantId = pickFirstTrimmed(ref.merchant_id, ref.merchantId);
  if (!productId) return null;
  if (!allowOpaqueProductId && isUuidLikeString(productId)) return null;
  if (requireMerchant && !merchantId) return null;
  return {
    product_id: productId,
    ...(merchantId ? { merchant_id: merchantId } : {}),
  };
}

const RECO_TEST_SEED_ID_SET = new Set([
  'a39dd7a3-5d80-4cb3-82e1-3bf2707f65fc',
  'a39dd7a35d804cb382e13bf2707f65fc',
  'e7c90e06-8673-4c97-835d-074a26ab2162',
  'e7c90e0686734c97835d074a26ab2162',
  'c231aaaa-8b00-4145-a704-684931049303',
  'c231aaaa8b004145a704684931049303',
  'to_copper_peptides',
]);

const RECO_TEST_SEED_NAME_SET = new Set([
  'winona soothing repair serum',
  'ipsa time reset aqua',
  'the ordinary buffet plus copper peptides 1 percent',
  'the ordinary niacinamide 10 percent plus zinc 1 percent',
]);

function normalizeRecoSeedToken(value) {
  return String(value || '')
    .trim()
    .toLowerCase()
    .replace(/&/g, ' and ')
    .replace(/\+/g, ' plus ')
    .replace(/%/g, ' percent ')
    .replace(/[^a-z0-9\u4e00-\u9fff]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function buildRecoDiversityHistoryKey(ctx) {
  const uid = pickFirstTrimmed(ctx?.aurora_uid, ctx?.brief_id);
  if (uid) return `uid:${uid.toLowerCase()}`;
  return '';
}

function buildRecoDiversityToken(item) {
  const base = item && typeof item === 'object' && !Array.isArray(item) ? item : {};
  const sku =
    base.sku && typeof base.sku === 'object' && !Array.isArray(base.sku)
      ? base.sku
      : base.product && typeof base.product === 'object' && !Array.isArray(base.product)
        ? base.product
        : {};
  const productId = pickFirstTrimmed(sku.product_id, sku.productId, base.product_id, base.productId, sku.sku_id, sku.skuId);
  if (productId) return `id:${String(productId).trim().toLowerCase()}`;

  const brand = pickFirstTrimmed(sku.brand, base.brand);
  const name = pickFirstTrimmed(
    sku.display_name,
    sku.displayName,
    sku.name,
    base.display_name,
    base.displayName,
    base.title,
  );
  const joined = joinBrandAndName(brand, name);
  const token = normalizeRecoSeedToken(joined || name);
  return token ? `name:${token}` : '';
}

function getRecoRecentExposureState(historyKey, nowMs = Date.now()) {
  const key = String(historyKey || '').trim();
  if (!key) return { tokens: [], round: 0 };
  const entry = recoRecentExposureState.get(key);
  if (!entry || typeof entry !== 'object') return { tokens: [], round: 0 };

  const expiresAt = Number(entry.expiresAt || 0);
  if (!Number.isFinite(expiresAt) || expiresAt <= nowMs) {
    recoRecentExposureState.delete(key);
    return { tokens: [], round: 0 };
  }

  const tokens = Array.isArray(entry.tokens) ? entry.tokens : [];
  const round = Number.isFinite(Number(entry.round)) ? Math.max(0, Math.trunc(Number(entry.round))) : 0;
  return {
    round,
    tokens: tokens
    .map((token) => String(token || '').trim())
    .filter(Boolean)
    .slice(-RECO_DIVERSITY_HISTORY_MAX_ITEMS),
  };
}

function getRecoRecentExposureTokens(historyKey, nowMs = Date.now()) {
  return getRecoRecentExposureState(historyKey, nowMs).tokens;
}

function updateRecoRecentExposureTokens(historyKey, nextTokens, nowMs = Date.now()) {
  const key = String(historyKey || '').trim();
  if (!key) return;
  const currentState = getRecoRecentExposureState(key, nowMs);
  const current = currentState.tokens;
  const incoming = (Array.isArray(nextTokens) ? nextTokens : [])
    .map((token) => String(token || '').trim())
    .filter(Boolean);
  if (!incoming.length && !current.length) return;

  const merged = [...current, ...incoming].slice(-RECO_DIVERSITY_HISTORY_MAX_ITEMS);
  const roundIncrement = incoming.length > 0 ? 1 : 0;
  recoRecentExposureState.delete(key);
  recoRecentExposureState.set(key, {
    tokens: merged,
    round: Math.max(0, Math.trunc(Number(currentState.round || 0))) + roundIncrement,
    expiresAt: nowMs + RECO_DIVERSITY_HISTORY_TTL_MS,
  });

  while (recoRecentExposureState.size > 800) {
    const oldestKey = recoRecentExposureState.keys().next().value;
    if (!oldestKey) break;
    recoRecentExposureState.delete(oldestKey);
  }
}

function applyRecoRecentDiversityGuard(recommendations, {
  historyTokens = [],
  maxRepeatPerResponse = RECO_DIVERSITY_MAX_REPEAT_PER_RESPONSE,
  minTotal = RECO_DIVERSITY_MIN_TOTAL,
  rotationRound = 0,
} = {}) {
  const list = Array.isArray(recommendations) ? recommendations : [];
  if (!list.length) {
    return {
      recommendations: list,
      repeated_before: 0,
      repeated_after: 0,
      filtered_count: 0,
      applied: false,
    };
  }

  const historySet = new Set(
    (Array.isArray(historyTokens) ? historyTokens : [])
      .map((token) => String(token || '').trim())
      .filter(Boolean),
  );
  if (!historySet.size) {
    return {
      recommendations: list,
      repeated_before: 0,
      repeated_after: 0,
      filtered_count: 0,
      applied: false,
    };
  }

  const annotated = list.map((item, idx) => {
    const token = buildRecoDiversityToken(item);
    const repeated = Boolean(token && historySet.has(token));
    return { idx, item, token, repeated };
  });
  const lastSeenPosByToken = new Map();
  const historyOrdered = (Array.isArray(historyTokens) ? historyTokens : [])
    .map((token) => String(token || '').trim())
    .filter(Boolean);
  for (let idx = 0; idx < historyOrdered.length; idx += 1) {
    const token = historyOrdered[idx];
    lastSeenPosByToken.set(token, idx);
  }
  const rankForNovelty = (rows) =>
    rows
      .slice()
      .sort((a, b) => {
        if (a.repeated !== b.repeated) return a.repeated ? 1 : -1;
        if (!a.repeated && !b.repeated) return a.idx - b.idx;
        const aPos = Number.isFinite(Number(lastSeenPosByToken.get(a.token)))
          ? Number(lastSeenPosByToken.get(a.token))
          : -1;
        const bPos = Number.isFinite(Number(lastSeenPosByToken.get(b.token)))
          ? Number(lastSeenPosByToken.get(b.token))
          : -1;
        if (aPos !== bPos) return aPos - bPos;
        return a.idx - b.idx;
      });
  const repeatedBefore = annotated.filter((row) => row.repeated).length;
  if (!repeatedBefore) {
    return {
      recommendations: list,
      repeated_before: 0,
      repeated_after: 0,
      filtered_count: 0,
      applied: false,
    };
  }

  const freshCount = annotated.filter((row) => !row.repeated).length;
  const maxRepeat = Math.max(0, Math.min(4, Number.isFinite(Number(maxRepeatPerResponse)) ? Math.trunc(Number(maxRepeatPerResponse)) : RECO_DIVERSITY_MAX_REPEAT_PER_RESPONSE));
  const minKeepTotal = Math.max(1, Math.min(8, Number.isFinite(Number(minTotal)) ? Math.trunc(Number(minTotal)) : RECO_DIVERSITY_MIN_TOTAL));
  const repeatKeepFloor = Math.max(0, minKeepTotal - freshCount);
  const allowedRepeats = Math.min(repeatedBefore, Math.max(maxRepeat, repeatKeepFloor));

  if (allowedRepeats >= repeatedBefore) {
    const noveltyRanked = rankForNovelty(annotated).map((row) => row.item);
    let rotated = noveltyRanked.slice();
    if (repeatedBefore === annotated.length && rotated.length > 1) {
      const normalizedRound = Number.isFinite(Number(rotationRound)) ? Math.max(0, Math.trunc(Number(rotationRound))) : 0;
      const offset = normalizedRound % rotated.length;
      if (offset > 0) {
        rotated = [...rotated.slice(offset), ...rotated.slice(0, offset)];
      }
    }
    const reRanked = rotated.some((item, idx) => item !== list[idx]);
    return {
      recommendations: rotated,
      repeated_before: repeatedBefore,
      repeated_after: repeatedBefore,
      filtered_count: 0,
      applied: reRanked,
    };
  }

  const keep = [];
  let repeatKept = 0;
  for (const row of annotated) {
    if (!row.repeated) {
      keep.push(row.item);
      continue;
    }
    if (repeatKept < allowedRepeats) {
      keep.push(row.item);
      repeatKept += 1;
    }
  }

  return {
    recommendations: keep,
    repeated_before: repeatedBefore,
    repeated_after: repeatKept,
    filtered_count: repeatedBefore - repeatKept,
    applied: repeatedBefore > repeatKept,
  };
}

function buildRecoSeedCandidateTokens(item) {
  const base = item && typeof item === 'object' && !Array.isArray(item) ? item : {};
  const sku =
    base.sku && typeof base.sku === 'object' && !Array.isArray(base.sku)
      ? base.sku
      : base.product && typeof base.product === 'object' && !Array.isArray(base.product)
        ? base.product
        : {};
  const brand = pickFirstTrimmed(sku.brand, base.brand);
  const name = pickFirstTrimmed(sku.name, base.name);
  const displayName = pickFirstTrimmed(sku.display_name, sku.displayName, base.display_name, base.displayName, name);
  const joined = joinBrandAndName(brand, displayName || name);
  return uniqCaseInsensitiveStrings(
    [
      displayName,
      joined,
      pickFirstTrimmed(base.title, base.product_name, base.productTitle),
      name,
      brand,
    ].map((x) => normalizeRecoSeedToken(x)),
    10,
  );
}

function isRecoKnownTestSeedItem(item) {
  const base = item && typeof item === 'object' && !Array.isArray(item) ? item : {};
  const sku =
    base.sku && typeof base.sku === 'object' && !Array.isArray(base.sku)
      ? base.sku
      : base.product && typeof base.product === 'object' && !Array.isArray(base.product)
        ? base.product
        : {};

  const ids = uniqCaseInsensitiveStrings(
    [
      pickFirstTrimmed(sku.product_id, sku.productId),
      pickFirstTrimmed(sku.sku_id, sku.skuId),
      pickFirstTrimmed(base.product_id, base.productId),
      pickFirstTrimmed(base.sku_id, base.skuId),
    ].map((x) => String(x || '').trim().toLowerCase()),
    10,
  );
  if (ids.some((id) => RECO_TEST_SEED_ID_SET.has(id))) return true;

  const tokens = buildRecoSeedCandidateTokens(base);
  if (tokens.some((token) => RECO_TEST_SEED_NAME_SET.has(token))) return true;
  return false;
}

function limitRecoKnownTestSeedRecommendations(recommendations, {
  maxSeedItems = RECO_TEST_SEED_MAX_PER_RESPONSE,
  minTotal = RECO_TEST_SEED_MIN_TOTAL,
} = {}) {
  const list = Array.isArray(recommendations) ? recommendations : [];
  if (!list.length) {
    return {
      recommendations: list,
      seed_count_before: 0,
      seed_count_after: 0,
      filtered_count: 0,
      applied: false,
    };
  }

  const maxSeed = Math.max(0, Math.min(4, Number.isFinite(Number(maxSeedItems)) ? Math.trunc(Number(maxSeedItems)) : RECO_TEST_SEED_MAX_PER_RESPONSE));
  const minKeepTotal = Math.max(1, Math.min(8, Number.isFinite(Number(minTotal)) ? Math.trunc(Number(minTotal)) : RECO_TEST_SEED_MIN_TOTAL));
  if (maxSeed >= list.length) {
    return {
      recommendations: list,
      seed_count_before: 0,
      seed_count_after: 0,
      filtered_count: 0,
      applied: false,
    };
  }

  const seedIndexes = [];
  const nonSeedIndexes = [];
  for (let i = 0; i < list.length; i += 1) {
    if (isRecoKnownTestSeedItem(list[i])) seedIndexes.push(i);
    else nonSeedIndexes.push(i);
  }

  if (!seedIndexes.length || seedIndexes.length <= maxSeed || !nonSeedIndexes.length) {
    return {
      recommendations: list,
      seed_count_before: seedIndexes.length,
      seed_count_after: seedIndexes.length,
      filtered_count: 0,
      applied: false,
    };
  }

  const nonSeedCount = nonSeedIndexes.length;
  const seedKeepFloor = Math.max(0, minKeepTotal - nonSeedCount);
  const allowedSeedCount = Math.min(seedIndexes.length, Math.max(maxSeed, seedKeepFloor));
  if (allowedSeedCount >= seedIndexes.length) {
    return {
      recommendations: list,
      seed_count_before: seedIndexes.length,
      seed_count_after: seedIndexes.length,
      filtered_count: 0,
      applied: false,
    };
  }

  const seedIndexSet = new Set(seedIndexes);
  const allowedSeedIndexSet = new Set(seedIndexes.slice(0, allowedSeedCount));
  const filtered = [];
  for (let i = 0; i < list.length; i += 1) {
    if (!seedIndexSet.has(i)) {
      filtered.push(list[i]);
      continue;
    }
    if (allowedSeedIndexSet.has(i)) filtered.push(list[i]);
  }

  return {
    recommendations: filtered,
    seed_count_before: seedIndexes.length,
    seed_count_after: allowedSeedCount,
    filtered_count: seedIndexes.length - allowedSeedCount,
    applied: seedIndexes.length > allowedSeedCount,
  };
}

function extractRecoPdpDirectKeys(base, skuCandidate) {
  const candidates = [base, skuCandidate].filter((v) => Boolean(v) && typeof v === 'object' && !Array.isArray(v));
  const subjectCandidates = [];
  for (const source of candidates) {
    if (source.subject && typeof source.subject === 'object' && !Array.isArray(source.subject)) {
      subjectCandidates.push(source.subject);
    }
  }

  let subjectProductGroupId = '';
  for (const subject of subjectCandidates) {
    const type = pickFirstTrimmed(subject.type).toLowerCase();
    const asId = pickFirstTrimmed(subject.id);
    const asPgid = pickFirstTrimmed(subject.product_group_id, subject.productGroupId);
    if (type === 'product_group' && asId) {
      subjectProductGroupId = asId;
      break;
    }
    if (asPgid) {
      subjectProductGroupId = asPgid;
      break;
    }
  }

  if (!subjectProductGroupId) {
    subjectProductGroupId = pickFirstTrimmed(
      base?.product_group_id,
      base?.productGroupId,
      skuCandidate?.product_group_id,
      skuCandidate?.productGroupId,
      base?.pdp_open?.subject?.product_group_id,
      base?.pdp_open?.subject?.id,
      base?.pdpOpen?.subject?.product_group_id,
      base?.pdpOpen?.subject?.id,
    );
  }

  const canonicalRefCandidates = [
    base?.canonical_product_ref,
    base?.canonicalProductRef,
    skuCandidate?.canonical_product_ref,
    skuCandidate?.canonicalProductRef,
    base?.product_ref,
    base?.productRef,
    skuCandidate?.product_ref,
    skuCandidate?.productRef,
  ];

  let directProductRef = null;
  for (const refRaw of canonicalRefCandidates) {
    const ref = normalizeCanonicalProductRef(refRaw, { requireMerchant: true, allowOpaqueProductId: false });
    if (ref) {
      directProductRef = ref;
      break;
    }
  }

  const rawProductId = pickFirstTrimmed(
    skuCandidate?.product_id,
    skuCandidate?.productId,
    base?.product_id,
    base?.productId,
  );
  const rawMerchantId = pickFirstTrimmed(
    skuCandidate?.merchant_id,
    skuCandidate?.merchantId,
    base?.merchant_id,
    base?.merchantId,
  );

  if (!directProductRef) {
    const fallbackRef = normalizeCanonicalProductRef(
      {
        product_id: rawProductId,
        merchant_id: rawMerchantId,
      },
      { requireMerchant: true, allowOpaqueProductId: false },
    );
    if (fallbackRef) directProductRef = fallbackRef;
  }

  return {
    subjectProductGroupId,
    directProductRef,
    rawProductId,
    rawMerchantId,
  };
}

function buildRecoResolveHints({ base, skuCandidate, rawProductId, rawMerchantId, brand, name, displayName }) {
  const aliases = [];
  const seen = new Set();
  const pushAlias = (value) => {
    const s = String(value || '').trim();
    if (!s) return;
    const key = s.toLowerCase();
    if (seen.has(key)) return;
    seen.add(key);
    aliases.push(s);
  };

  pushAlias(displayName);
  pushAlias(name);
  if (brand && displayName) pushAlias(joinBrandAndName(brand, displayName));
  if (brand && name) pushAlias(joinBrandAndName(brand, name));
  pushAlias(base?.title);

  const hints = {};
  const canonicalHintRef = normalizeCanonicalProductRef(
    {
      product_id: rawProductId,
      merchant_id: rawMerchantId,
    },
    { requireMerchant: false, allowOpaqueProductId: false },
  );
  if (canonicalHintRef) {
    hints.product_ref = canonicalHintRef;
  }
  if (brand) hints.brand = brand;
  if (aliases.length) hints.aliases = aliases.slice(0, 8);
  return hints;
}

function normalizeResolveReasonCode(raw, fallback = 'no_candidates') {
  const code = String(raw || '').trim().toLowerCase();
  if (code === 'db_error' || code === 'upstream_timeout' || code === 'no_candidates') return code;
  return fallback;
}

function normalizePdpOpenMode(raw, fallback = 'external') {
  const mode = String(raw || '').trim().toLowerCase();
  if (mode === 'group' || mode === 'ref' || mode === 'resolve' || mode === 'external') return mode;
  return fallback;
}

function normalizePdpOpenPath(raw, fallback = 'external') {
  const path = String(raw || '').trim().toLowerCase();
  if (path === 'internal' || path === 'external') return path;
  if (path === 'group' || path === 'ref' || path === 'resolve') return 'internal';
  return fallback;
}

function mapResolveFailureCode({ resolveBody, statusCode, error } = {}) {
  const explicit = normalizeResolveReasonCode(
    resolveBody?.reason_code || resolveBody?.reasonCode || resolveBody?.metadata?.resolve_reason_code,
    '',
  );

  const reason = String(resolveBody?.reason || '').trim().toLowerCase();
  const sources = Array.isArray(resolveBody?.metadata?.sources) ? resolveBody.metadata.sources : [];
  const sourceReasons = sources
    .map((item) => String(item && item.reason ? item.reason : '').trim().toLowerCase())
    .filter(Boolean);
  const sourceDerivedReason =
    sourceReasons.some((r) => r.startsWith('db_') || r === 'products_cache_missing')
      ? 'db_error'
      : sourceReasons.some((r) => r.includes('timeout') || r.startsWith('upstream_'))
        ? 'upstream_timeout'
        : null;

  if (explicit === 'db_error' || explicit === 'upstream_timeout') return explicit;
  if (sourceDerivedReason) return sourceDerivedReason;
  if (explicit === 'no_candidates') return explicit;

  if (reason === 'no_candidates' || reason === 'low_confidence' || reason === 'empty_query') return 'no_candidates';
  if (reason.startsWith('db_') || reason === 'products_cache_missing') return 'db_error';
  if (reason.includes('timeout') || reason.startsWith('upstream_') || reason === 'upstream_error') return 'upstream_timeout';

  if (sourceReasons.some((r) => r.startsWith('db_') || r === 'products_cache_missing')) return 'db_error';
  if (sourceReasons.some((r) => r.includes('timeout') || r.startsWith('upstream_'))) return 'upstream_timeout';

  const status = Number(statusCode || 0);
  if (status >= 500 || status === 429) return 'upstream_timeout';

  const errText = String(error?.code || error?.message || error || '').trim().toLowerCase();
  if (errText.includes('timeout') || errText.includes('econnaborted') || errText.includes('etimedout')) {
    return 'upstream_timeout';
  }
  if (errText.includes('db_') || errText.includes('database') || errText.includes('postgres')) {
    return 'db_error';
  }
  return 'no_candidates';
}

function shouldAttemptLocalRecoFallback(reasonCode, error) {
  if (reasonCode === 'no_candidates') {
    return RECO_PDP_LOCAL_INVOKE_FALLBACK_ON_NO_CANDIDATES;
  }
  if (reasonCode === 'upstream_timeout') return RECO_PDP_LOCAL_INVOKE_FALLBACK_ON_UPSTREAM_TIMEOUT;
  if (reasonCode === 'db_error') return true;
  if (error) return true;
  return false;
}

function getRecoPdpResolveTimeoutMs({ strictInternal = false, requestedTimeoutMs = null } = {}) {
  const requested = Number.isFinite(Number(requestedTimeoutMs)) ? Math.trunc(Number(requestedTimeoutMs)) : RECO_PDP_RESOLVE_TIMEOUT_MS;
  const baseline = Math.max(300, Math.min(12000, requested));
  if (!strictInternal) return baseline;
  return Math.max(baseline, RECO_PDP_RESOLVE_TIMEOUT_STRICT_MIN_MS);
}

function extractCanonicalFromOffersResolveBody(body) {
  const payload = body && typeof body === 'object' && !Array.isArray(body) ? body : null;
  const mapping = payload && payload.mapping && typeof payload.mapping === 'object' && !Array.isArray(payload.mapping)
    ? payload.mapping
    : null;
  let canonicalProductGroupId = pickFirstTrimmed(
    mapping?.canonical_product_group_id,
    mapping?.canonicalProductGroupId,
    mapping?.canonical_product_group?.id,
    mapping?.canonical_product_group?.product_group_id,
  );

  const canonicalRefCandidates = [
    mapping?.canonical_ref,
    mapping?.canonical_product_ref,
    payload?.canonical_product_ref,
  ];
  let canonicalProductRef = null;
  for (const candidate of canonicalRefCandidates) {
    const normalized = normalizeCanonicalProductRef(candidate, {
      requireMerchant: true,
      allowOpaqueProductId: false,
    });
    if (normalized) {
      canonicalProductRef = normalized;
      break;
    }
  }

  if (!canonicalProductRef) {
    const canonicalProduct =
      mapping?.canonical_product && typeof mapping.canonical_product === 'object' && !Array.isArray(mapping.canonical_product)
        ? mapping.canonical_product
        : null;
    const fallbackRef = normalizeCanonicalProductRef(
      {
        product_id: pickFirstTrimmed(canonicalProduct?.product_id, canonicalProduct?.id),
        merchant_id: pickFirstTrimmed(
          canonicalProduct?.merchant_id,
          canonicalProduct?.merchantId,
          canonicalProduct?.merchant?.merchant_id,
        ),
      },
      { requireMerchant: true, allowOpaqueProductId: false },
    );
    if (fallbackRef) canonicalProductRef = fallbackRef;
  }

  const pdpTargets = [
    payload?.pdp_target?.v1,
    payload?.pdpTarget?.v1,
    mapping?.pdp_target?.v1,
    mapping?.pdpTarget?.v1,
  ].filter((candidate) => Boolean(candidate) && typeof candidate === 'object' && !Array.isArray(candidate));

  for (const target of pdpTargets) {
    if (!canonicalProductGroupId) {
      const fromSubject = pickFirstTrimmed(
        target?.subject?.product_group_id,
        target?.subject?.productGroupId,
        target?.subject?.id,
        target?.product_group_id,
        target?.productGroupId,
      );
      if (fromSubject) canonicalProductGroupId = fromSubject;
    }

    if (!canonicalProductRef) {
      const fromTargetRef =
        normalizeCanonicalProductRef(target?.canonical_product_ref, {
          requireMerchant: true,
          allowOpaqueProductId: false,
        }) ||
        normalizeCanonicalProductRef(target?.product_ref, {
          requireMerchant: true,
          allowOpaqueProductId: false,
        });
      if (fromTargetRef) canonicalProductRef = fromTargetRef;
    }
  }

  return { canonicalProductRef, canonicalProductGroupId };
}

function resolveRecoStableAliasRefByQuery(queryText) {
  if (!resolveKnownStableProductRef) return null;
  const raw = String(queryText || '').trim();
  if (!raw) return null;

  const normalizedQuery = normalizeTextForStableResolver(raw);
  const queryTokens = tokenizeStableResolverQuery(normalizedQuery);
  if (!normalizedQuery || !Array.isArray(queryTokens) || queryTokens.length === 0) return null;

  const match = resolveKnownStableProductRef({
    query: raw,
    normalizedQuery,
    queryTokens,
  });
  if (!match || !match.product_ref || typeof match.product_ref !== 'object') return null;

  const canonicalProductRef = normalizeCanonicalProductRef(match.product_ref, {
    requireMerchant: true,
    allowOpaqueProductId: false,
  });
  if (!canonicalProductRef) return null;

  return {
    canonicalProductRef,
    matchId: String(match.id || '').trim() || null,
    matchedAlias: String(match.matched_alias || '').trim() || null,
    reason: String(match.reason || '').trim() || 'stable_alias_ref',
    score: Number.isFinite(Number(match.score)) ? Number(match.score) : null,
  };
}

async function resolveRecoPdpByStableIds({
  productId,
  skuId,
  brand,
  name,
  displayName,
  merchantId,
  logger,
  allowLocalInvokeFallback = true,
} = {}) {
  const normalizedProductId = String(productId || '').trim();
  const normalizedSkuId = String(skuId || '').trim();
  const normalizedBrand = String(brand || '').trim();
  const normalizedName = String(name || '').trim();
  const normalizedDisplayName = String(displayName || '').trim();
  const normalizedMerchantId = String(merchantId || '').trim();
  const stableQueryText = pickFirstTrimmed(
    normalizedBrand && normalizedDisplayName
      ? joinBrandAndName(normalizedBrand, normalizedDisplayName)
      : '',
    normalizedBrand && normalizedName ? joinBrandAndName(normalizedBrand, normalizedName) : '',
    normalizedDisplayName,
    normalizedName,
    normalizedSkuId,
    normalizedProductId,
  );

  const stableAliasMatch = resolveRecoStableAliasRefByQuery(stableQueryText);
  if (stableAliasMatch?.canonicalProductRef) {
    logger?.info(
      {
        product_id: normalizedProductId || null,
        sku_id: normalizedSkuId || null,
        match_id: stableAliasMatch.matchId,
        matched_alias: stableAliasMatch.matchedAlias,
        score: stableAliasMatch.score,
      },
      'aurora bff: reco stable-id resolved via local stable alias',
    );
    return {
      ok: true,
      canonicalProductRef: stableAliasMatch.canonicalProductRef,
      requestIds: null,
      localFallbackAttempted: false,
      resolveAttempted: false,
      reasonCode: 'stable_alias_ref',
    };
  }

  if (!PIVOTA_BACKEND_BASE_URL || (!normalizedProductId && !normalizedSkuId)) {
    return { ok: false, reasonCode: 'no_candidates' };
  }

  const stableIdCandidates = [normalizedProductId, normalizedSkuId].filter(Boolean);
  const hasOnlyOpaqueStableIds = stableIdCandidates.length > 0 && stableIdCandidates.every((v) => isUuidLikeString(v));
  if (RECO_PDP_SKIP_OPAQUE_STABLE_IDS && hasOnlyOpaqueStableIds && !normalizedMerchantId) {
    logger?.info(
      {
        product_id: normalizedProductId || null,
        sku_id: normalizedSkuId || null,
        merchant_id: null,
      },
      'aurora bff: reco stable-id offers.resolve skipped for opaque ids without merchant',
    );
    return {
      ok: false,
      reasonCode: 'no_candidates',
      requestIds: null,
      localFallbackAttempted: false,
      resolveAttempted: false,
    };
  }

  let responseBody = null;
  let statusCode = 0;
  let responseError = null;
  let primaryRequestId = null;
  let localRequestId = null;
  let localFallbackAttempted = false;
  const primaryInvokeUrl = `${String(PIVOTA_BACKEND_BASE_URL || '').replace(/\/+$/, '')}/agent/shop/v1/invoke`;
  try {
    const resolvePayload = {
      product: {
        ...(normalizedProductId ? { product_id: normalizedProductId } : {}),
        ...(normalizedSkuId ? { sku_id: normalizedSkuId } : {}),
        ...(normalizedMerchantId ? { merchant_id: normalizedMerchantId } : {}),
        ...(normalizedBrand ? { brand: normalizedBrand } : {}),
        ...(normalizedName ? { name: normalizedName } : {}),
        ...(normalizedDisplayName ? { display_name: normalizedDisplayName } : {}),
        ...(stableQueryText ? { query: stableQueryText } : {}),
      },
      ...(normalizedProductId ? { product_id: normalizedProductId } : {}),
      ...(normalizedSkuId ? { sku_id: normalizedSkuId } : {}),
      ...(stableQueryText ? { query: stableQueryText } : {}),
    };
    const resp = await axios.post(
      primaryInvokeUrl,
      {
        operation: 'offers.resolve',
        payload: resolvePayload,
      },
      {
        headers: buildPivotaBackendAgentHeaders(),
        timeout: RECO_PDP_OFFERS_RESOLVE_TIMEOUT_MS,
        validateStatus: () => true,
      },
    );
    responseBody = resp && typeof resp.data === 'object' ? resp.data : null;
    statusCode = Number(resp?.status || 0);
    primaryRequestId = pickFirstTrimmed(
      responseBody?.metadata?.request_id,
      responseBody?.metadata?.requestId,
      resp?.headers?.['x-request-id'],
      resp?.headers?.['X-Request-Id'],
    );
  } catch (err) {
    responseError = err;
  }

  if (statusCode === 200 && responseBody && String(responseBody.status || '').trim().toLowerCase() === 'success') {
    const { canonicalProductRef, canonicalProductGroupId } = extractCanonicalFromOffersResolveBody(responseBody);
    if (canonicalProductGroupId || canonicalProductRef) {
      return {
        ok: true,
        canonicalProductGroupId,
        canonicalProductRef,
        requestIds:
          primaryRequestId
        ? { primary: primaryRequestId }
        : null,
        localFallbackAttempted: false,
        resolveAttempted: true,
      };
    }
  }

  let reasonCode = mapOfferResolveFailureCode({
    responseBody,
    statusCode,
    error: responseError,
  });

  const localInvokeUrl = `${String(RECO_PDP_LOCAL_INVOKE_BASE_URL || '').replace(/\/+$/, '')}/agent/shop/v1/invoke`;
  const shouldAttemptLocalFallback =
    allowLocalInvokeFallback &&
    RECO_PDP_LOCAL_INVOKE_FALLBACK_CHAT_ENABLED &&
    RECO_PDP_LOCAL_INVOKE_FALLBACK_ENABLED &&
    localInvokeUrl &&
    localInvokeUrl !== primaryInvokeUrl &&
    shouldAttemptLocalRecoFallback(reasonCode, responseError);
  if (
    shouldAttemptLocalFallback
  ) {
    recordRecoPdpInternalRetryAttempt(1);
    localFallbackAttempted = true;
    let localBody = null;
    let localStatusCode = 0;
    let localError = null;
    try {
      const resp = await axios.post(
        localInvokeUrl,
        {
          operation: 'offers.resolve',
          payload: {
            product: {
              ...(normalizedProductId ? { product_id: normalizedProductId } : {}),
              ...(normalizedSkuId ? { sku_id: normalizedSkuId } : {}),
              ...(normalizedMerchantId ? { merchant_id: normalizedMerchantId } : {}),
              ...(normalizedBrand ? { brand: normalizedBrand } : {}),
              ...(normalizedName ? { name: normalizedName } : {}),
              ...(normalizedDisplayName ? { display_name: normalizedDisplayName } : {}),
              ...(stableQueryText ? { query: stableQueryText } : {}),
            },
            ...(normalizedProductId ? { product_id: normalizedProductId } : {}),
            ...(normalizedSkuId ? { sku_id: normalizedSkuId } : {}),
            ...(stableQueryText ? { query: stableQueryText } : {}),
          },
        },
        {
          headers: { 'Content-Type': 'application/json' },
          timeout: RECO_PDP_LOCAL_INVOKE_TIMEOUT_MS,
          validateStatus: () => true,
        },
      );
      localBody = resp && typeof resp.data === 'object' ? resp.data : null;
      localStatusCode = Number(resp?.status || 0);
      localRequestId = pickFirstTrimmed(
        localBody?.metadata?.request_id,
        localBody?.metadata?.requestId,
        resp?.headers?.['x-request-id'],
        resp?.headers?.['X-Request-Id'],
      );
    } catch (err) {
      localError = err;
    }

    if (localStatusCode === 200 && localBody && String(localBody.status || '').trim().toLowerCase() === 'success') {
      const { canonicalProductRef, canonicalProductGroupId } = extractCanonicalFromOffersResolveBody(localBody);
      if (canonicalProductGroupId || canonicalProductRef) {
        logger?.info(
          {
            product_id: normalizedProductId || null,
            sku_id: normalizedSkuId || null,
            primary_reason_code: reasonCode,
            local_status_code: localStatusCode,
            primary_request_id: primaryRequestId || null,
            local_request_id: localRequestId || null,
          },
          'aurora bff: reco stable-id resolved via local invoke fallback',
        );
        return {
          ok: true,
          canonicalProductGroupId,
          canonicalProductRef,
          requestIds:
            (primaryRequestId || localRequestId)
              ? {
                  ...(primaryRequestId ? { primary: primaryRequestId } : {}),
                  ...(localRequestId ? { local: localRequestId } : {}),
                }
              : null,
          localFallbackAttempted,
          resolveAttempted: true,
        };
      }
    }

    const localReasonCode = mapOfferResolveFailureCode({
      responseBody: localBody,
      statusCode: localStatusCode,
      error: localError,
    });
    logger?.warn(
      {
        product_id: normalizedProductId || null,
        sku_id: normalizedSkuId || null,
        primary_reason_code: reasonCode,
        local_reason_code: localReasonCode,
        local_status_code: localStatusCode || null,
        primary_request_id: primaryRequestId || null,
        local_request_id: localRequestId || null,
        local_err: localError ? localError.message || String(localError) : null,
      },
      'aurora bff: reco stable-id local invoke fallback unresolved',
    );
    if (reasonCode === 'no_candidates' && localReasonCode && localReasonCode !== 'no_candidates') {
      reasonCode = localReasonCode;
    }
  }

  if (!responseError) {
    logger?.warn(
      {
        status_code: statusCode || null,
        product_id: normalizedProductId || null,
        sku_id: normalizedSkuId || null,
        reason_code: reasonCode,
        response_status: responseBody?.status || null,
        primary_request_id: primaryRequestId || null,
        local_fallback_attempted: localFallbackAttempted,
      },
      'aurora bff: reco stable-id offers.resolve unresolved',
    );
  }
  if (responseError) {
    logger?.warn(
      {
        err: responseError?.message || String(responseError),
        product_id: normalizedProductId || null,
        sku_id: normalizedSkuId || null,
        reason_code: reasonCode,
        primary_request_id: primaryRequestId || null,
        local_fallback_attempted: localFallbackAttempted,
      },
      'aurora bff: reco stable-id offers.resolve failed',
    );
  }
  return {
    ok: false,
    reasonCode,
    requestIds:
      (primaryRequestId || localRequestId)
        ? {
            ...(primaryRequestId ? { primary: primaryRequestId } : {}),
            ...(localRequestId ? { local: localRequestId } : {}),
          }
        : null,
    localFallbackAttempted,
    resolveAttempted: true,
  };
}

async function resolveRecoPdpByLocalResolver({
  queryText,
  hints = null,
  logger,
  timeoutMs = null,
} = {}) {
  const q = String(queryText || '').trim();
  if (!q) return { ok: false, reasonCode: 'no_candidates' };

  const resolveTimeoutMs = getRecoPdpResolveTimeoutMs({
    strictInternal: true,
    requestedTimeoutMs: timeoutMs,
  });
  const localResolveUrl = `${String(RECO_PDP_LOCAL_INVOKE_BASE_URL || '').replace(/\/+$/, '')}/agent/v1/products/resolve`;
  const localHttpTimeoutMs = Math.max(RECO_PDP_LOCAL_INVOKE_TIMEOUT_MS, resolveTimeoutMs);
  const canUseLocalHttpFallback = Boolean(localResolveUrl && /^https?:\/\//i.test(localResolveUrl));

  const runLocalHttpResolveFallback = async () => {
    if (!canUseLocalHttpFallback) {
      return { responseBody: null, responseStatusCode: null, responseError: new Error('local_resolver_unavailable') };
    }
    try {
      const resp = await axios.post(
        localResolveUrl,
        {
          query: q,
          lang: 'en',
          ...(hints && typeof hints === 'object' && !Array.isArray(hints) ? { hints } : {}),
          options: {
            search_all_merchants: true,
            timeout_ms: resolveTimeoutMs,
            upstream_retries: 0,
            stable_alias_short_circuit: true,
            allow_stable_alias_for_uuid: true,
            allow_external_seed: false,
          },
          caller: 'aurora_chatbox',
        },
        {
          headers: { 'Content-Type': 'application/json' },
          timeout: localHttpTimeoutMs,
          validateStatus: () => true,
        },
      );
      return {
        responseBody: resp && typeof resp.data === 'object' ? resp.data : null,
        responseStatusCode: Number.isFinite(Number(resp?.status)) ? Math.trunc(Number(resp.status)) : null,
        responseError: null,
      };
    } catch (err) {
      return { responseBody: null, responseStatusCode: null, responseError: err };
    }
  };

  let responseBody = null;
  let responseStatusCode = null;
  let responseError = null;
  let fallbackMode = 'direct';
  if (typeof resolveProductRefDirectImpl === 'function') {
    try {
      responseBody = await resolveProductRefDirectImpl({
        query: q,
        lang: 'en',
        ...(hints && typeof hints === 'object' && !Array.isArray(hints) ? { hints } : {}),
        options: {
          search_all_merchants: true,
          timeout_ms: resolveTimeoutMs,
          upstream_retries: 0,
          stable_alias_short_circuit: true,
          allow_stable_alias_for_uuid: true,
        },
        caller: 'aurora_chatbox',
      });
    } catch (err) {
      responseError = err;
    }
  } else {
    const fallbackOut = await runLocalHttpResolveFallback();
    responseBody = fallbackOut.responseBody;
    responseStatusCode = fallbackOut.responseStatusCode;
    responseError = fallbackOut.responseError;
    fallbackMode = 'local_http';
  }

  const resolvedProductRef = normalizeCanonicalProductRef(responseBody?.product_ref, {
    requireMerchant: true,
    allowOpaqueProductId: false,
  });
  if (responseBody?.resolved === true && resolvedProductRef) {
    return {
      ok: true,
      canonicalProductRef: resolvedProductRef,
      reasonCode: null,
    };
  }

  const reasonCode = mapResolveFailureCode({
    resolveBody: responseBody,
    statusCode: responseStatusCode,
    error: responseError,
  });
  let finalReasonCode = reasonCode;

  const shouldAttemptLocalHttpAfterDirect =
    fallbackMode === 'direct' &&
    canUseLocalHttpFallback &&
    (
      finalReasonCode === 'upstream_timeout' ||
      finalReasonCode === 'db_error' ||
      Boolean(responseError)
    );
  if (shouldAttemptLocalHttpAfterDirect) {
    recordRecoPdpInternalRetryAttempt(1);
    const fallbackOut = await runLocalHttpResolveFallback();
    const fallbackResolvedProductRef = normalizeCanonicalProductRef(fallbackOut.responseBody?.product_ref, {
      requireMerchant: true,
      allowOpaqueProductId: false,
    });
    if (fallbackOut.responseBody?.resolved === true && fallbackResolvedProductRef) {
      return {
        ok: true,
        canonicalProductRef: fallbackResolvedProductRef,
        reasonCode: null,
      };
    }
    const fallbackReasonCode = mapResolveFailureCode({
      resolveBody: fallbackOut.responseBody,
      statusCode: fallbackOut.responseStatusCode,
      error: fallbackOut.responseError,
    });
    if (fallbackReasonCode && fallbackReasonCode !== 'upstream_timeout' && fallbackReasonCode !== 'db_error') {
      finalReasonCode = fallbackReasonCode;
    } else if (
      (finalReasonCode === 'upstream_timeout' || finalReasonCode === 'db_error') &&
      fallbackReasonCode === 'no_candidates'
    ) {
      finalReasonCode = 'no_candidates';
    }
    responseBody = fallbackOut.responseBody || responseBody;
    responseStatusCode = fallbackOut.responseStatusCode || responseStatusCode;
    responseError = fallbackOut.responseError || responseError;
    fallbackMode = 'local_http_after_direct';
  }

  if (responseError || reasonCode !== 'no_candidates') {
    logger?.warn(
      {
        query: q.slice(0, 120),
        reason_code: finalReasonCode,
        status_code: responseStatusCode,
        fallback_mode: fallbackMode,
        err: responseError ? responseError.message || String(responseError) : null,
      },
      'aurora bff: reco pdp local resolver fallback unresolved',
    );
  }
  return {
    ok: false,
    reasonCode: finalReasonCode,
  };
}

async function resolveRecoPdpByCatalogSearch({
  queryText,
  logger,
  timeoutMs = RECO_CATALOG_SEARCH_TIMEOUT_MS,
  forceLocalSearchFallback = false,
} = {}) {
  const q = String(queryText || '').trim();
  if (!q) return { ok: false, reasonCode: 'no_candidates' };

  const searchOut = await searchPivotaBackendProducts({
    query: q,
    limit: 4,
    logger,
    timeoutMs,
    searchAllMerchants: true,
    forceLocalSearchFallback,
  });

  const products = Array.isArray(searchOut?.products) ? searchOut.products : [];
  for (const product of products) {
    if (!product || typeof product !== 'object' || Array.isArray(product)) continue;
    const { subjectProductGroupId, directProductRef } = extractRecoPdpDirectKeys(product, product);
    if (subjectProductGroupId || directProductRef) {
      return {
        ok: true,
        canonicalProductGroupId: subjectProductGroupId || null,
        canonicalProductRef: directProductRef || null,
        reasonCode: null,
      };
    }
  }

  return {
    ok: false,
    reasonCode: normalizeResolveReasonCode(searchOut?.reason || '', 'no_candidates'),
  };
}

function buildExternalGoogleSearchUrl(query) {
  const q = String(query || '').trim();
  if (!q) return 'https://www.google.com/';
  return `https://www.google.com/search?q=${encodeURIComponent(q)}`;
}

function withRecoPdpMetadata(base, {
  path,
  subject = null,
  canonicalProductRef = null,
  queryText = '',
  resolveReasonCode = null,
  resolveAttempted = false,
  resolvedViaQuery = null,
  timeToPdpMs = null,
  stableResolveRequestIds = null,
  stableResolveLocalFallbackAttempted = false,
}) {
  const nextMode = normalizePdpOpenMode(path, 'external');
  const nextPath = nextMode === 'external' ? 'external' : 'internal';
  const metadataBase = isPlainObject(base?.metadata) ? { ...base.metadata } : {};
  const normalizedFailReason =
    resolveReasonCode != null && resolveReasonCode !== ''
      ? normalizeResolveReasonCode(resolveReasonCode)
      : null;
  const normalizedTimeToPdp =
    Number.isFinite(Number(timeToPdpMs)) && Number(timeToPdpMs) >= 0
      ? Math.max(0, Math.round(Number(timeToPdpMs)))
      : null;
  const nextMetadata = {
    ...metadataBase,
    pdp_open_path: nextPath,
    pdp_open_mode: nextMode,
    ...(resolveAttempted ? { pdp_open_resolve_attempted: true } : {}),
    ...(normalizedFailReason
      ? {
          resolve_reason_code: normalizedFailReason,
          pdp_open_fail_reason: normalizedFailReason,
          resolve_fail_reason: normalizedFailReason,
        }
      : {}),
    ...(normalizedTimeToPdp != null ? { time_to_pdp_ms: normalizedTimeToPdp } : {}),
    ...(stableResolveRequestIds ? { stable_resolve_request_ids: stableResolveRequestIds } : {}),
    ...(stableResolveRequestIds || stableResolveLocalFallbackAttempted
      ? { stable_resolve_local_fallback_attempted: Boolean(stableResolveLocalFallbackAttempted) }
      : {}),
  };

  const nextSku =
    base && base.sku && typeof base.sku === 'object' && !Array.isArray(base.sku)
      ? { ...base.sku }
      : null;
  if (nextSku && subject?.product_group_id) {
    nextSku.product_group_id = String(subject.product_group_id);
  }
  if (nextSku && canonicalProductRef) {
    nextSku.canonical_product_ref = canonicalProductRef;
    nextSku.product_id = canonicalProductRef.product_id;
    nextSku.productId = canonicalProductRef.product_id;
    nextSku.sku_id = canonicalProductRef.product_id;
    nextSku.skuId = canonicalProductRef.product_id;
    if (canonicalProductRef.merchant_id) {
      nextSku.merchant_id = canonicalProductRef.merchant_id;
      nextSku.merchantId = canonicalProductRef.merchant_id;
    }
  }

  if (nextMode === 'group' && subject) {
    const productGroupId = String(subject.product_group_id || subject.id || '').trim();
    const normalizedSubject = { type: 'product_group', id: productGroupId, product_group_id: productGroupId };
    return {
      ...base,
      ...(nextSku ? { sku: nextSku } : {}),
      subject: normalizedSubject,
      metadata: nextMetadata,
      pdp_open: {
        path: 'group',
        subject: normalizedSubject,
        get_pdp_v2_payload: { subject: { type: 'product_group', id: productGroupId } },
      },
    };
  }

  if ((nextMode === 'ref' || nextMode === 'resolve') && canonicalProductRef) {
    return {
      ...base,
      ...(nextSku ? { sku: nextSku } : {}),
      canonical_product_ref: canonicalProductRef,
      metadata: nextMetadata,
      pdp_open: {
        path: nextMode,
        product_ref: canonicalProductRef,
        get_pdp_v2_payload: { product_ref: canonicalProductRef },
        ...(resolvedViaQuery ? { resolved_via_query: resolvedViaQuery } : {}),
      },
    };
  }

  const externalUrl = buildExternalGoogleSearchUrl(queryText);
  return {
    ...base,
    ...(nextSku ? { sku: nextSku } : {}),
    metadata: nextMetadata,
    pdp_open: {
      path: 'external',
      external: {
        provider: 'google',
        target: '_blank',
        url: externalUrl,
        query: String(queryText || '').trim() || null,
      },
      ...(normalizedFailReason ? { resolve_reason_code: normalizedFailReason } : {}),
    },
  };
}

async function enrichRecoItemWithPdpOpenContract(item, { logger, allowLocalInvokeFallback = true } = {}) {
  const startedAt = Date.now();
  const elapsedMs = () => Math.max(0, Date.now() - startedAt);
  const base = item && typeof item === 'object' && !Array.isArray(item) ? item : null;
  if (!base) return item;

  const skuCandidate =
    base.sku && typeof base.sku === 'object' && !Array.isArray(base.sku)
      ? base.sku
      : base.product && typeof base.product === 'object' && !Array.isArray(base.product)
        ? base.product
        : null;

  const brand = pickFirstTrimmed(skuCandidate?.brand, base.brand);
  const name = pickFirstTrimmed(skuCandidate?.name, base.name);
  const displayName = pickFirstTrimmed(
    skuCandidate?.display_name,
    skuCandidate?.displayName,
    base.display_name,
    base.displayName,
    name,
  );

  const { subjectProductGroupId, directProductRef, rawProductId, rawMerchantId } = extractRecoPdpDirectKeys(
    base,
    skuCandidate,
  );

  if (subjectProductGroupId) {
    return withRecoPdpMetadata(base, {
      path: 'group',
      subject: { type: 'product_group', id: subjectProductGroupId, product_group_id: subjectProductGroupId },
      canonicalProductRef: directProductRef,
      timeToPdpMs: elapsedMs(),
    });
  }

  if (directProductRef) {
    return withRecoPdpMetadata(base, {
      path: 'ref',
      canonicalProductRef: directProductRef,
      timeToPdpMs: elapsedMs(),
    });
  }

  const stableProductId = pickFirstTrimmed(
    rawProductId,
    skuCandidate?.product_id,
    skuCandidate?.productId,
    base?.product_id,
    base?.productId,
  );
  const stableSkuId = pickFirstTrimmed(
    skuCandidate?.sku_id,
    skuCandidate?.skuId,
    base?.sku_id,
    base?.skuId,
    stableProductId,
  );
  const stableQueryText = pickFirstTrimmed(
    brand && displayName ? joinBrandAndName(brand, displayName) : '',
    brand && name ? joinBrandAndName(brand, name) : '',
    displayName,
    name,
    stableSkuId,
    stableProductId,
  );
  const stableAliasMatch = resolveRecoStableAliasRefByQuery(stableQueryText);
  if (stableAliasMatch?.canonicalProductRef) {
    return withRecoPdpMetadata(base, {
      path: 'ref',
      canonicalProductRef: stableAliasMatch.canonicalProductRef,
      resolveAttempted: false,
      timeToPdpMs: elapsedMs(),
    });
  }
  let stableResolveReasonCode = null;
  let stableResolveRequestIds = null;
  let stableResolveLocalFallbackAttempted = false;
  if (
    PIVOTA_BACKEND_BASE_URL &&
    (stableProductId || stableSkuId) &&
    (RECO_PDP_RESOLVE_ENABLED || RECO_PDP_STRICT_INTERNAL_FIRST)
  ) {
    const stableResolved = await resolveRecoPdpByStableIds({
      productId: stableProductId,
      skuId: stableSkuId,
      brand,
      name,
      displayName,
      merchantId: rawMerchantId,
      logger,
      allowLocalInvokeFallback,
    });
    stableResolveRequestIds =
      stableResolved?.requestIds && typeof stableResolved.requestIds === 'object'
        ? stableResolved.requestIds
        : null;
    stableResolveLocalFallbackAttempted = Boolean(stableResolved?.localFallbackAttempted);
    if (stableResolved.ok && stableResolved.canonicalProductGroupId) {
      return withRecoPdpMetadata(base, {
        path: 'group',
        subject: {
          type: 'product_group',
          id: stableResolved.canonicalProductGroupId,
          product_group_id: stableResolved.canonicalProductGroupId,
        },
        canonicalProductRef: stableResolved.canonicalProductRef || null,
        resolveAttempted: stableResolved.resolveAttempted === true,
        timeToPdpMs: elapsedMs(),
        stableResolveRequestIds,
        stableResolveLocalFallbackAttempted,
      });
    }
    if (stableResolved.ok && stableResolved.canonicalProductRef) {
      return withRecoPdpMetadata(base, {
        path: 'ref',
        canonicalProductRef: stableResolved.canonicalProductRef,
        resolveAttempted: stableResolved.resolveAttempted === true,
        timeToPdpMs: elapsedMs(),
        stableResolveRequestIds,
        stableResolveLocalFallbackAttempted,
      });
    }
    stableResolveReasonCode = stableResolved.reasonCode || null;
  }

  const queryText =
    buildProductInputText(skuCandidate || base, typeof base.url === 'string' ? base.url : null) ||
    stableQueryText;
  const stableResolveFailureCode = normalizeResolveReasonCode(stableResolveReasonCode || '', null);
  const shouldSkipNoCandidateQueryResolve =
    RECO_PDP_SKIP_QUERY_RESOLVE_ON_STABLE_NO_CANDIDATES &&
    !RECO_PDP_STRICT_INTERNAL_FIRST;
  const shouldSkipQueryResolveForStableFailure =
    RECO_PDP_SKIP_QUERY_RESOLVE_ON_STABLE_FAILURE &&
    Boolean(stableResolveFailureCode) &&
    (
      stableResolveFailureCode === 'no_candidates'
        ? shouldSkipNoCandidateQueryResolve
        : RECO_PDP_FAST_EXTERNAL_FALLBACK_ENABLED
    );
  if (
    shouldSkipQueryResolveForStableFailure
  ) {
    recordRecoPdpExternalFallback(stableResolveFailureCode);
    return withRecoPdpMetadata(base, {
      path: 'external',
      queryText,
      resolveReasonCode: stableResolveFailureCode,
      resolveAttempted: true,
      timeToPdpMs: elapsedMs(),
      stableResolveRequestIds,
      stableResolveLocalFallbackAttempted,
    });
  }

  const hints = buildRecoResolveHints({
    base,
    skuCandidate,
    rawProductId,
    rawMerchantId,
    brand,
    name,
    displayName,
  });
  const queryResolveTimeoutMs = getRecoPdpResolveTimeoutMs({
    strictInternal: RECO_PDP_STRICT_INTERNAL_FIRST,
  });

  if (!queryText) {
    recordRecoPdpExternalFallback(stableResolveReasonCode || 'no_candidates');
    return withRecoPdpMetadata(base, {
      path: 'external',
      queryText,
      resolveReasonCode: stableResolveReasonCode || 'no_candidates',
      resolveAttempted: false,
      timeToPdpMs: elapsedMs(),
      stableResolveRequestIds,
      stableResolveLocalFallbackAttempted,
    });
  }

  if (!PIVOTA_BACKEND_BASE_URL && RECO_PDP_STRICT_INTERNAL_FIRST) {
    const localResolved = await resolveRecoPdpByLocalResolver({
      queryText,
      hints,
      logger,
      timeoutMs: queryResolveTimeoutMs,
    });
    if (localResolved.ok && localResolved.canonicalProductRef) {
      return withRecoPdpMetadata(base, {
        path: 'resolve',
        canonicalProductRef: localResolved.canonicalProductRef,
        resolveAttempted: true,
        resolvedViaQuery: queryText,
        timeToPdpMs: elapsedMs(),
        stableResolveRequestIds,
        stableResolveLocalFallbackAttempted,
      });
    }
    if (!stableResolveReasonCode && localResolved.reasonCode) {
      stableResolveReasonCode = localResolved.reasonCode;
    }
  }

  const shouldAttemptQueryResolve =
    Boolean(PIVOTA_BACKEND_BASE_URL) &&
    (RECO_PDP_RESOLVE_ENABLED || RECO_PDP_STRICT_INTERNAL_FIRST);
  if (!shouldAttemptQueryResolve) {
    const skipReasonCode = stableResolveReasonCode || 'db_error';
    recordRecoPdpExternalFallback(skipReasonCode);
    return withRecoPdpMetadata(base, {
      path: 'external',
      queryText,
      resolveReasonCode: skipReasonCode,
      resolveAttempted: false,
      timeToPdpMs: elapsedMs(),
      stableResolveRequestIds,
      stableResolveLocalFallbackAttempted,
    });
  }

  // Avoid opaque UUID-only lookups; they frequently produce unstable cross-merchant misses.
  const isOpaqueUuidOnlyQuery = isUuidLikeString(queryText) && (!hints.aliases || hints.aliases.length === 0);
  if (isOpaqueUuidOnlyQuery) {
    recordRecoPdpExternalFallback(stableResolveReasonCode || 'no_candidates');
    return withRecoPdpMetadata(base, {
      path: 'external',
      queryText,
      resolveReasonCode: stableResolveReasonCode || 'no_candidates',
      resolveAttempted: false,
      timeToPdpMs: elapsedMs(),
      stableResolveRequestIds,
      stableResolveLocalFallbackAttempted,
    });
  }

  let resolveBody = null;
  let resolveStatus = 0;
  let resolveError = null;
  const primaryResolveUrl = `${PIVOTA_BACKEND_BASE_URL}/agent/v1/products/resolve`;
  const queryResolvePayload = {
    query: queryText,
    lang: 'en',
    hints,
    options: {
      search_all_merchants: true,
      timeout_ms: queryResolveTimeoutMs,
      upstream_retries: 0,
      ...(rawMerchantId ? { prefer_merchants: [rawMerchantId] } : {}),
    },
    caller: 'aurora_chatbox',
  };
  try {
    const resp = await axios.post(
      primaryResolveUrl,
      queryResolvePayload,
      {
        headers: buildPivotaBackendAgentHeaders(),
        timeout: queryResolveTimeoutMs,
        validateStatus: () => true,
      },
    );
    resolveBody = resp && typeof resp.data === 'object' ? resp.data : null;
    resolveStatus = Number(resp?.status || 0);
  } catch (err) {
    resolveError = err;
  }

  const resolvedProductRef = normalizeCanonicalProductRef(resolveBody?.product_ref, {
    requireMerchant: true,
    allowOpaqueProductId: false,
  });
  if (resolveStatus === 200 && resolveBody?.resolved === true && resolvedProductRef) {
    return withRecoPdpMetadata(base, {
      path: 'resolve',
      canonicalProductRef: resolvedProductRef,
      resolveAttempted: true,
      resolvedViaQuery: queryText,
      timeToPdpMs: elapsedMs(),
    });
  }

  let reasonCode = mapResolveFailureCode({
    resolveBody,
    statusCode: resolveStatus,
    error: resolveError,
  });
  const localResolveUrl = `${String(RECO_PDP_LOCAL_INVOKE_BASE_URL || '').replace(/\/+$/, '')}/agent/v1/products/resolve`;
  const shouldAttemptLocalResolveFallback =
    allowLocalInvokeFallback &&
    RECO_PDP_LOCAL_INVOKE_FALLBACK_CHAT_ENABLED &&
    RECO_PDP_LOCAL_INVOKE_FALLBACK_ENABLED &&
    localResolveUrl &&
    localResolveUrl !== primaryResolveUrl &&
    shouldAttemptLocalRecoFallback(reasonCode, resolveError);
  if (shouldAttemptLocalResolveFallback) {
    recordRecoPdpInternalRetryAttempt(1);
    let localResolveBody = null;
    let localResolveStatus = 0;
    let localResolveError = null;
    try {
      const resp = await axios.post(
        localResolveUrl,
        queryResolvePayload,
        {
          headers: { 'Content-Type': 'application/json' },
          timeout: RECO_PDP_LOCAL_INVOKE_TIMEOUT_MS,
          validateStatus: () => true,
        },
      );
      localResolveBody = resp && typeof resp.data === 'object' ? resp.data : null;
      localResolveStatus = Number(resp?.status || 0);
    } catch (err) {
      localResolveError = err;
    }

    const localResolvedProductRef = normalizeCanonicalProductRef(localResolveBody?.product_ref, {
      requireMerchant: true,
      allowOpaqueProductId: false,
    });
    if (localResolveStatus === 200 && localResolveBody?.resolved === true && localResolvedProductRef) {
      logger?.info(
        {
          query: queryText.slice(0, 120),
          primary_reason_code: reasonCode,
          local_status_code: localResolveStatus,
        },
        'aurora bff: reco pdp resolved via local products.resolve fallback',
      );
      return withRecoPdpMetadata(base, {
        path: 'resolve',
        canonicalProductRef: localResolvedProductRef,
        resolveAttempted: true,
        resolvedViaQuery: queryText,
        timeToPdpMs: elapsedMs(),
        stableResolveRequestIds,
        stableResolveLocalFallbackAttempted,
      });
    }

    const localReasonCode = mapResolveFailureCode({
      resolveBody: localResolveBody,
      statusCode: localResolveStatus,
      error: localResolveError,
    });
    if (reasonCode === 'no_candidates' && localReasonCode && localReasonCode !== 'no_candidates') {
      reasonCode = localReasonCode;
    }
    logger?.warn(
      {
        query: queryText.slice(0, 120),
        primary_reason_code: reasonCode,
        local_reason_code: localReasonCode,
        local_status_code: localResolveStatus || null,
        local_err: localResolveError ? localResolveError.message || String(localResolveError) : null,
      },
      'aurora bff: reco pdp local products.resolve fallback unresolved',
    );
  }
  const stableIdCandidates = [stableProductId, stableSkuId]
    .map((value) => String(value || '').trim())
    .filter(Boolean);
  const hasOnlyOpaqueStableIdsWithoutMerchant =
    !rawMerchantId &&
    stableIdCandidates.length > 0 &&
    stableIdCandidates.every((value) => isUuidLikeString(value));
  const hasStrongNamedQueryForCatalogFallback = Boolean(
    (brand && (displayName || name)) ||
      (displayName && String(displayName).trim().split(/\s+/).filter(Boolean).length >= 2) ||
      (name && String(name).trim().split(/\s+/).filter(Boolean).length >= 2),
  );
  const shouldAttemptDeterministicLocalResolver =
    RECO_PDP_STRICT_INTERNAL_FIRST &&
    (
      reasonCode === 'upstream_timeout' ||
      reasonCode === 'db_error' ||
      (
        reasonCode === 'no_candidates' &&
        (hasOnlyOpaqueStableIdsWithoutMerchant || hasStrongNamedQueryForCatalogFallback)
      )
    );
  if (shouldAttemptDeterministicLocalResolver) {
    recordRecoPdpInternalRetryAttempt(1);
    const localResolved = await resolveRecoPdpByLocalResolver({
      queryText,
      hints,
      logger,
      timeoutMs: queryResolveTimeoutMs,
    });
    if (localResolved.ok && localResolved.canonicalProductRef) {
      logger?.info(
        {
          query: queryText.slice(0, 120),
          primary_reason_code: reasonCode,
          fallback: 'local_resolver',
        },
        'aurora bff: reco pdp resolved via deterministic local resolver',
      );
      return withRecoPdpMetadata(base, {
        path: 'resolve',
        canonicalProductRef: localResolved.canonicalProductRef,
        resolveAttempted: true,
        resolvedViaQuery: queryText,
        timeToPdpMs: elapsedMs(),
        stableResolveRequestIds,
        stableResolveLocalFallbackAttempted,
      });
    }
    if (
      localResolved.reasonCode &&
      localResolved.reasonCode !== 'upstream_timeout' &&
      localResolved.reasonCode !== 'db_error'
    ) {
      reasonCode = localResolved.reasonCode;
    }
  }
  const shouldAttemptCatalogSearchFallback =
    RECO_PDP_STRICT_INTERNAL_FIRST &&
    (
      (
        reasonCode === 'no_candidates' &&
        (hasOnlyOpaqueStableIdsWithoutMerchant || hasStrongNamedQueryForCatalogFallback)
      ) ||
      (
        (reasonCode === 'upstream_timeout' || reasonCode === 'db_error') &&
        (hasOnlyOpaqueStableIdsWithoutMerchant || hasStrongNamedQueryForCatalogFallback)
      )
    );
  if (shouldAttemptCatalogSearchFallback) {
    const transientReasonForCatalog = reasonCode === 'upstream_timeout' || reasonCode === 'db_error';
    const reasonCodeBeforeCatalog = reasonCode;
    const catalogResolved = await resolveRecoPdpByCatalogSearch({
      queryText,
      logger,
      timeoutMs: Math.max(RECO_CATALOG_SEARCH_TIMEOUT_MS, queryResolveTimeoutMs),
      forceLocalSearchFallback: transientReasonForCatalog,
    });
    if (catalogResolved.ok && catalogResolved.canonicalProductGroupId) {
      return withRecoPdpMetadata(base, {
        path: 'group',
        subject: {
          type: 'product_group',
          id: catalogResolved.canonicalProductGroupId,
          product_group_id: catalogResolved.canonicalProductGroupId,
        },
        canonicalProductRef: catalogResolved.canonicalProductRef || null,
        resolveAttempted: true,
        resolvedViaQuery: queryText,
        timeToPdpMs: elapsedMs(),
        stableResolveRequestIds,
        stableResolveLocalFallbackAttempted,
      });
    }
    if (catalogResolved.ok && catalogResolved.canonicalProductRef) {
      return withRecoPdpMetadata(base, {
        path: 'ref',
        canonicalProductRef: catalogResolved.canonicalProductRef,
        resolveAttempted: true,
        resolvedViaQuery: queryText,
        timeToPdpMs: elapsedMs(),
        stableResolveRequestIds,
        stableResolveLocalFallbackAttempted,
      });
    }
    if (catalogResolved.reasonCode && catalogResolved.reasonCode !== 'no_candidates') {
      const catalogReasonIsTransient =
        catalogResolved.reasonCode === 'upstream_timeout' || catalogResolved.reasonCode === 'db_error';
      // If local deterministic resolver already downgraded to no_candidates, do not re-upgrade on catalog transient.
      if (!(reasonCodeBeforeCatalog === 'no_candidates' && catalogReasonIsTransient)) {
        reasonCode = catalogResolved.reasonCode;
      }
    } else if (
      (reasonCodeBeforeCatalog === 'upstream_timeout' || reasonCodeBeforeCatalog === 'db_error') &&
      catalogResolved.reasonCode === 'no_candidates'
    ) {
      // Transient resolve failures should not force fast external fallback when catalog search can determine emptiness.
      reasonCode = 'no_candidates';
    }
  }
  if (resolveError) {
    logger?.warn(
      {
        err: resolveError?.message || String(resolveError),
        query: queryText.slice(0, 120),
        pdp_open_path: 'external',
        fail_reason: reasonCode,
        resolve_reason_code: reasonCode,
      },
      'aurora bff: reco pdp resolve failed; using external fallback',
    );
  }
  recordRecoPdpExternalFallback(reasonCode || 'no_candidates');
  return withRecoPdpMetadata(base, {
    path: 'external',
    queryText,
    resolveReasonCode: reasonCode,
    resolveAttempted: true,
    timeToPdpMs: elapsedMs(),
    stableResolveRequestIds,
    stableResolveLocalFallbackAttempted,
  });
}

function tallyPdpOpenPathStats(recommendations) {
  const stats = { group: 0, ref: 0, resolve: 0, external: 0 };
  for (const item of Array.isArray(recommendations) ? recommendations : []) {
    const mode = normalizePdpOpenMode(
      item?.pdp_open?.path || item?.metadata?.pdp_open_mode || item?.metadata?.pdp_open_path,
      'external',
    );
    if (mode === 'group' || mode === 'ref' || mode === 'resolve' || mode === 'external') {
      stats[mode] += 1;
    } else {
      stats.external += 1;
    }
  }
  return stats;
}

function tallyResolveFailReasonCounts(recommendations) {
  const counts = { db_error: 0, upstream_timeout: 0, no_candidates: 0 };
  for (const item of Array.isArray(recommendations) ? recommendations : []) {
    const code = normalizeResolveReasonCode(
      item?.metadata?.pdp_open_fail_reason ||
        item?.metadata?.resolve_reason_code ||
        item?.metadata?.resolve_fail_reason ||
        item?.pdp_open?.resolve_reason_code,
      '',
    );
    if (code === 'db_error' || code === 'upstream_timeout' || code === 'no_candidates') {
      counts[code] += 1;
    }
  }
  return counts;
}

function summarizeTimeToPdpStats(items) {
  const values = [];
  for (const item of Array.isArray(items) ? items : []) {
    const raw = item?.metadata?.time_to_pdp_ms;
    const num = Number(raw);
    if (!Number.isFinite(num) || num < 0) continue;
    values.push(Math.round(num));
  }
  values.sort((a, b) => a - b);

  if (!values.length) {
    return { count: 0, mean: 0, p50: 0, p90: 0, max: 0 };
  }

  const pickPercentile = (p) => {
    const idx = Math.min(values.length - 1, Math.max(0, Math.ceil(values.length * p) - 1));
    return values[idx];
  };
  const sum = values.reduce((acc, v) => acc + v, 0);
  return {
    count: values.length,
    mean: Math.round(sum / values.length),
    p50: pickPercentile(0.5),
    p90: pickPercentile(0.9),
    max: values[values.length - 1],
  };
}

function mapOfferResolveFailureCode({ responseBody, statusCode, error } = {}) {
  const explicit = normalizeResolveReasonCode(
    responseBody?.reason_code || responseBody?.reasonCode || responseBody?.metadata?.reason_code || responseBody?.metadata?.resolve_reason_code,
    '',
  );
  if (explicit) return explicit;

  const reason = String(
    responseBody?.reason ||
      responseBody?.error ||
      responseBody?.code ||
      responseBody?.message ||
      '',
  )
    .trim()
    .toLowerCase();
  if (reason.startsWith('db_') || reason.includes('database') || reason.includes('postgres')) return 'db_error';
  if (reason.includes('timeout') || reason.startsWith('upstream_') || reason === 'upstream_error') return 'upstream_timeout';
  if (reason === 'no_candidates' || reason === 'not_found' || reason === 'not_found_in_cache') return 'no_candidates';

  const status = Number(statusCode || 0);
  if (status >= 500 || status === 429 || status === 408) return 'upstream_timeout';

  const errText = String(error?.code || error?.message || error || '').trim().toLowerCase();
  if (errText.includes('timeout') || errText.includes('econnaborted') || errText.includes('etimedout')) {
    return 'upstream_timeout';
  }
  if (errText.includes('db_') || errText.includes('database') || errText.includes('postgres')) {
    return 'db_error';
  }
  return 'no_candidates';
}

function applyOfferItemPdpOpenContract(item, { failReasonCode = null, resolveAttempted = false, timeToPdpMs = null } = {}) {
  const base = item && typeof item === 'object' && !Array.isArray(item) ? item : {};
  const product = base.product && typeof base.product === 'object' && !Array.isArray(base.product) ? { ...base.product } : {};
  const offer = base.offer && typeof base.offer === 'object' && !Array.isArray(base.offer) ? { ...base.offer } : base.offer;
  const failReason =
    failReasonCode != null && failReasonCode !== ''
      ? normalizeResolveReasonCode(failReasonCode)
      : null;
  const { subjectProductGroupId, directProductRef } = extractRecoPdpDirectKeys(product, product);

  const metadataBase = isPlainObject(base.metadata) ? { ...base.metadata } : {};
  const normalizedTimeToPdp =
    Number.isFinite(Number(timeToPdpMs)) && Number(timeToPdpMs) >= 0
      ? Math.max(0, Math.round(Number(timeToPdpMs)))
      : null;
  const metadata = {
    ...metadataBase,
    ...(resolveAttempted ? { offer_resolve_attempted: true } : {}),
    ...(normalizedTimeToPdp != null ? { time_to_pdp_ms: normalizedTimeToPdp } : {}),
  };

  if (subjectProductGroupId) {
    const subject = {
      type: 'product_group',
      id: subjectProductGroupId,
      product_group_id: subjectProductGroupId,
    };
    product.product_group_id = subjectProductGroupId;
    if (directProductRef) product.canonical_product_ref = directProductRef;
    metadata.pdp_open_path = 'internal';
    metadata.pdp_open_mode = 'group';
    if (failReason) {
      metadata.pdp_open_fail_reason = failReason;
      metadata.resolve_reason_code = failReason;
      metadata.resolve_fail_reason = failReason;
    }
    return {
      ...base,
      product,
      ...(offer && typeof offer === 'object' ? { offer } : {}),
      metadata,
      pdp_open: {
        path: 'group',
        subject,
        get_pdp_v2_payload: { subject: { type: 'product_group', id: subjectProductGroupId } },
      },
    };
  }

  if (directProductRef) {
    product.canonical_product_ref = directProductRef;
    metadata.pdp_open_path = 'internal';
    metadata.pdp_open_mode = 'ref';
    if (failReason) {
      metadata.pdp_open_fail_reason = failReason;
      metadata.resolve_reason_code = failReason;
      metadata.resolve_fail_reason = failReason;
    }
    return {
      ...base,
      product,
      ...(offer && typeof offer === 'object' ? { offer } : {}),
      metadata,
      pdp_open: {
        path: 'ref',
        product_ref: directProductRef,
        get_pdp_v2_payload: { product_ref: directProductRef },
      },
    };
  }

  const offerUrl =
    (offer && typeof offer === 'object' && typeof offer.affiliate_url === 'string' && offer.affiliate_url.trim()) ||
    (offer && typeof offer === 'object' && typeof offer.affiliateUrl === 'string' && offer.affiliateUrl.trim()) ||
    (offer && typeof offer === 'object' && typeof offer.url === 'string' && offer.url.trim()) ||
    '';
  const queryText = buildProductInputText(product, offerUrl) || pickFirstTrimmed(product.display_name, product.name, product.brand);
  const externalFailReason = normalizeResolveReasonCode(failReason || '', 'no_candidates');
  metadata.pdp_open_path = 'external';
  metadata.pdp_open_mode = 'external';
  metadata.pdp_open_fail_reason = externalFailReason;
  metadata.resolve_reason_code = externalFailReason;
  metadata.resolve_fail_reason = externalFailReason;

  return {
    ...base,
    product,
    ...(offer && typeof offer === 'object' ? { offer } : {}),
    metadata,
    pdp_open: {
      path: 'external',
      external: {
        provider: 'google',
        target: '_blank',
        url: buildExternalGoogleSearchUrl(queryText),
        query: queryText || null,
      },
      resolve_reason_code: externalFailReason,
    },
  };
}

function summarizeOfferPdpOpen(items) {
  const stats = { internal: 0, external: 0 };
  const failReasonCounts = { db_error: 0, upstream_timeout: 0, no_candidates: 0 };
  for (const item of Array.isArray(items) ? items : []) {
    const path = normalizePdpOpenPath(item?.metadata?.pdp_open_path || item?.pdp_open?.path, 'external');
    if (path === 'internal') stats.internal += 1;
    else stats.external += 1;

    const failReason = normalizeResolveReasonCode(
      item?.metadata?.pdp_open_fail_reason || item?.metadata?.resolve_reason_code || item?.pdp_open?.resolve_reason_code,
      '',
    );
    if (failReason === 'db_error' || failReason === 'upstream_timeout' || failReason === 'no_candidates') {
      failReasonCounts[failReason] += 1;
    }
  }
  return {
    path_stats: stats,
    fail_reason_counts: failReasonCounts,
    time_to_pdp_ms_stats: summarizeTimeToPdpStats(items),
  };
}

function normalizePdpPrefetchReason(reason) {
  const normalized = String(reason || '')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9:_-]+/g, '_')
    .replace(/^_+|_+$/g, '');
  return normalized || 'unknown';
}

function getPdpPrefetchReasonBucket(reason) {
  const key = normalizePdpPrefetchReason(reason);
  if (!pdpPrefetchStats.by_reason[key]) {
    pdpPrefetchStats.by_reason[key] = {
      total: 0,
      ok: 0,
      non_200: 0,
      failed: 0,
    };
  }
  return { key, bucket: pdpPrefetchStats.by_reason[key] };
}

function recordPdpPrefetchResult({ reason, status = 0, ok = false, failed = false, key = '', durationMs = 0, error = '' } = {}) {
  const { key: reasonKey, bucket } = getPdpPrefetchReasonBucket(reason);
  pdpPrefetchStats.totals.total += 1;
  bucket.total += 1;
  if (ok) {
    pdpPrefetchStats.totals.ok += 1;
    bucket.ok += 1;
  } else if (failed) {
    pdpPrefetchStats.totals.failed += 1;
    bucket.failed += 1;
  } else {
    pdpPrefetchStats.totals.non_200 += 1;
    bucket.non_200 += 1;
  }
  pdpPrefetchStats.last_prefetch = {
    at: new Date().toISOString(),
    reason: reasonKey,
    key: key || null,
    status: Number(status || 0),
    ok: Boolean(ok),
    failed: Boolean(failed),
    duration_ms: Number(durationMs || 0),
    error: error ? String(error).slice(0, 400) : null,
  };
}

function getNormalizedPdpHotsetPrewarmPayloads() {
  return (Array.isArray(AURORA_BFF_PDP_HOTSET_PREWARM_ITEMS) ? AURORA_BFF_PDP_HOTSET_PREWARM_ITEMS : [])
    .map((item) => normalizePdpCorePrefetchPayload(item))
    .filter(Boolean);
}

function getPdpPrefetchStateSnapshot() {
  return {
    config: {
      prefetch_enabled: AURORA_BFF_PDP_CORE_PREFETCH_ENABLED,
      prefetch_include: AURORA_BFF_PDP_CORE_PREFETCH_INCLUDE,
      prefetch_timeout_ms: AURORA_BFF_PDP_CORE_PREFETCH_TIMEOUT_MS,
      prefetch_dedup_ttl_ms: AURORA_BFF_PDP_CORE_PREFETCH_DEDUP_TTL_MS,
      hotset_prewarm_enabled: AURORA_BFF_PDP_HOTSET_PREWARM_ENABLED,
      hotset_size: getNormalizedPdpHotsetPrewarmPayloads().length,
      hotset_concurrency: AURORA_BFF_PDP_HOTSET_PREWARM_CONCURRENCY,
      hotset_interval_ms: AURORA_BFF_PDP_HOTSET_PREWARM_INTERVAL_MS,
      hotset_initial_delay_ms: AURORA_BFF_PDP_HOTSET_PREWARM_INITIAL_DELAY_MS,
      hotset_bootstrap_rounds: AURORA_BFF_PDP_HOTSET_PREWARM_BOOTSTRAP_ROUNDS,
      hotset_bootstrap_gap_ms: AURORA_BFF_PDP_HOTSET_PREWARM_BOOTSTRAP_GAP_MS,
    },
    runtime: {
      started: pdpHotsetPrewarmStarted,
      in_flight: pdpHotsetPrewarmInFlight,
      totals: { ...pdpPrefetchStats.totals },
      by_reason: { ...pdpPrefetchStats.by_reason },
      last_prefetch: pdpPrefetchStats.last_prefetch ? { ...pdpPrefetchStats.last_prefetch } : null,
      hotset_runs: { ...pdpPrefetchStats.hotset_runs },
      hotset_last: pdpPrefetchStats.hotset_last ? { ...pdpPrefetchStats.hotset_last } : null,
    },
  };
}

function getPdpHotsetPrewarmAdminToken(req) {
  if (!req || typeof req.get !== 'function') return '';
  return String(req.get('X-Aurora-Admin-Key') || req.get('x-aurora-admin-key') || '').trim();
}

function hasPdpHotsetPrewarmAdminAccess(req) {
  if (!AURORA_BFF_PDP_HOTSET_PREWARM_ADMIN_KEY) return false;
  const provided = getPdpHotsetPrewarmAdminToken(req);
  if (!provided) return false;
  const expectedBuf = Buffer.from(AURORA_BFF_PDP_HOTSET_PREWARM_ADMIN_KEY);
  const providedBuf = Buffer.from(provided);
  if (expectedBuf.length !== providedBuf.length) return false;
  try {
    return crypto.timingSafeEqual(expectedBuf, providedBuf);
  } catch {
    return false;
  }
}

function hasRecoPrelabelAdminAccess(req) {
  if (!AURORA_BFF_RECO_PRELABEL_ADMIN_KEY) return false;
  const provided = getPdpHotsetPrewarmAdminToken(req);
  if (!provided) return false;
  const expectedBuf = Buffer.from(AURORA_BFF_RECO_PRELABEL_ADMIN_KEY);
  const providedBuf = Buffer.from(provided);
  if (expectedBuf.length !== providedBuf.length) return false;
  try {
    return crypto.timingSafeEqual(expectedBuf, providedBuf);
  } catch {
    return false;
  }
}

function normalizePdpCorePrefetchPayload(raw) {
  if (!raw || typeof raw !== 'object' || Array.isArray(raw)) return null;
  const productRef = normalizeCanonicalProductRef(raw.product_ref, {
    requireMerchant: true,
    allowOpaqueProductId: false,
  });
  if (productRef) return { product_ref: productRef };

  const subject = raw.subject && typeof raw.subject === 'object' && !Array.isArray(raw.subject) ? raw.subject : null;
  const subjectType = String(subject?.type || '').trim().toLowerCase();
  const subjectId = pickFirstTrimmed(subject?.id, subject?.product_group_id);
  if (subjectType === 'product_group' && subjectId) {
    return {
      subject: {
        type: 'product_group',
        id: subjectId,
      },
    };
  }

  return null;
}

function extractPdpCorePrefetchPayloadFromItem(item) {
  const fromContract = normalizePdpCorePrefetchPayload(item?.pdp_open?.get_pdp_v2_payload);
  if (fromContract) return fromContract;

  const mode = normalizePdpOpenMode(item?.pdp_open?.path || item?.metadata?.pdp_open_mode, '');
  if (mode === 'group') {
    const subjectId = pickFirstTrimmed(item?.pdp_open?.subject?.id, item?.pdp_open?.subject?.product_group_id);
    if (subjectId) {
      return {
        subject: {
          type: 'product_group',
          id: subjectId,
        },
      };
    }
    return null;
  }
  if (mode === 'ref' || mode === 'resolve') {
    const productRef = normalizeCanonicalProductRef(item?.pdp_open?.product_ref, {
      requireMerchant: true,
      allowOpaqueProductId: false,
    });
    if (productRef) return { product_ref: productRef };
  }

  return null;
}

function makePdpCorePrefetchKey(payload) {
  const normalized = normalizePdpCorePrefetchPayload(payload);
  if (!normalized) return '';
  if (normalized.subject?.type === 'product_group' && normalized.subject.id) {
    return `subject:product_group:${normalized.subject.id}`;
  }
  if (normalized.product_ref?.merchant_id && normalized.product_ref?.product_id) {
    return `ref:${normalized.product_ref.merchant_id}:${normalized.product_ref.product_id}`;
  }
  return '';
}

function shouldRunPdpCorePrefetch(key) {
  if (!key) return false;
  const now = Date.now();
  const prev = Number(pdpPrefetchRecentMap.get(key) || 0);
  if (prev > 0 && now - prev < AURORA_BFF_PDP_CORE_PREFETCH_DEDUP_TTL_MS) return false;
  pdpPrefetchRecentMap.set(key, now);
  if (pdpPrefetchRecentMap.size > 300) {
    const oldest = pdpPrefetchRecentMap.keys().next().value;
    if (oldest) pdpPrefetchRecentMap.delete(oldest);
  }
  return true;
}

async function invokePdpCorePrefetch(payload, { logger, reason = null } = {}) {
  if (!PIVOTA_BACKEND_BASE_URL) return { skipped: true, skip_reason: 'missing_base_url' };
  const normalized = normalizePdpCorePrefetchPayload(payload);
  if (!normalized) return { skipped: true, skip_reason: 'invalid_payload' };
  const invokeUrl = `${String(PIVOTA_BACKEND_BASE_URL || '').replace(/\/+$/, '')}/agent/shop/v1/invoke`;
  const reasonKey = normalizePdpPrefetchReason(reason);
  const prefetchKey = makePdpCorePrefetchKey(normalized) || null;
  const startedAt = Date.now();
  try {
    const resp = await axios.post(
      invokeUrl,
      {
        operation: 'get_pdp_v2',
        payload: {
          ...normalized,
          include: AURORA_BFF_PDP_CORE_PREFETCH_INCLUDE,
          capabilities: {
            client: 'aurora_bff_prefetch',
            client_version: 'v1',
          },
        },
      },
      {
        headers: buildPivotaBackendAgentHeaders(),
        timeout: AURORA_BFF_PDP_CORE_PREFETCH_TIMEOUT_MS,
        validateStatus: () => true,
      },
    );
    const status = Number(resp?.status || 0);
    const durationMs = Date.now() - startedAt;
    if (status >= 400) {
      recordPdpPrefetchResult({
        reason: reasonKey,
        status,
        ok: false,
        failed: false,
        key: prefetchKey || '',
        durationMs,
      });
      logger?.warn(
        {
          reason: reasonKey,
          status,
          key: prefetchKey,
          duration_ms: durationMs,
        },
        'aurora bff: pdp core prefetch non-200',
      );
      return { ok: false, status, duration_ms: durationMs, key: prefetchKey };
    }
    recordPdpPrefetchResult({
      reason: reasonKey,
      status,
      ok: true,
      failed: false,
      key: prefetchKey || '',
      durationMs,
    });
    return { ok: true, status, duration_ms: durationMs, key: prefetchKey };
  } catch (err) {
    const durationMs = Date.now() - startedAt;
    const errMessage = err?.message || String(err);
    recordPdpPrefetchResult({
      reason: reasonKey,
      status: 0,
      ok: false,
      failed: true,
      key: prefetchKey || '',
      durationMs,
      error: errMessage,
    });
    logger?.warn(
      {
        reason: reasonKey,
        err: errMessage,
        key: prefetchKey,
        duration_ms: durationMs,
      },
      'aurora bff: pdp core prefetch failed',
    );
    return { ok: false, status: 0, duration_ms: durationMs, key: prefetchKey, error: errMessage };
  }
}

function schedulePdpCorePrefetchFromItems(items, { logger, reason = null, maxItems = AURORA_BFF_PDP_CORE_PREFETCH_MAX_ITEMS } = {}) {
  if (!AURORA_BFF_PDP_CORE_PREFETCH_ENABLED || !PIVOTA_BACKEND_BASE_URL) return;
  const list = Array.isArray(items) ? items : [];
  if (!list.length) return;

  const targets = [];
  const limit = Math.max(1, Math.min(12, Number(maxItems) || AURORA_BFF_PDP_CORE_PREFETCH_MAX_ITEMS));
  for (const item of list) {
    const payload = extractPdpCorePrefetchPayloadFromItem(item);
    if (!payload) continue;
    const key = makePdpCorePrefetchKey(payload);
    if (!shouldRunPdpCorePrefetch(key)) continue;
    targets.push({ payload, key });
    if (targets.length >= limit) break;
  }
  if (!targets.length) return;

  void mapWithConcurrency(targets, 2, async (target) => {
    await invokePdpCorePrefetch(target.payload, { logger, reason });
  });
}

async function runPdpHotsetPrewarmBatch({ logger, reason = 'hotset_prewarm', allowWhenDisabled = false } = {}) {
  const reasonKey = normalizePdpPrefetchReason(reason);
  if (!PIVOTA_BACKEND_BASE_URL) {
    pdpPrefetchStats.hotset_runs.skipped_unavailable += 1;
    pdpPrefetchStats.hotset_last = {
      at: new Date().toISOString(),
      reason: reasonKey,
      ok: false,
      skipped: true,
      skip_reason: 'missing_base_url',
      duration_ms: 0,
      hotset_size: 0,
    };
    return { ok: false, skipped: true, skip_reason: 'missing_base_url', hotset_size: 0, duration_ms: 0 };
  }
  if (!allowWhenDisabled && !AURORA_BFF_PDP_HOTSET_PREWARM_ENABLED) {
    pdpPrefetchStats.hotset_runs.skipped_disabled += 1;
    pdpPrefetchStats.hotset_last = {
      at: new Date().toISOString(),
      reason: reasonKey,
      ok: false,
      skipped: true,
      skip_reason: 'feature_disabled',
      duration_ms: 0,
      hotset_size: 0,
    };
    return { ok: false, skipped: true, skip_reason: 'feature_disabled', hotset_size: 0, duration_ms: 0 };
  }
  const hotset = getNormalizedPdpHotsetPrewarmPayloads();
  if (!hotset.length) {
    pdpPrefetchStats.hotset_runs.skipped_no_hotset += 1;
    pdpPrefetchStats.hotset_last = {
      at: new Date().toISOString(),
      reason: reasonKey,
      ok: false,
      skipped: true,
      skip_reason: 'empty_hotset',
      duration_ms: 0,
      hotset_size: 0,
    };
    return { ok: false, skipped: true, skip_reason: 'empty_hotset', hotset_size: 0, duration_ms: 0 };
  }
  if (pdpHotsetPrewarmInFlight) {
    pdpPrefetchStats.hotset_runs.skipped_in_flight += 1;
    pdpPrefetchStats.hotset_last = {
      at: new Date().toISOString(),
      reason: reasonKey,
      ok: false,
      skipped: true,
      skip_reason: 'in_flight',
      duration_ms: 0,
      hotset_size: hotset.length,
    };
    return { ok: false, skipped: true, skip_reason: 'in_flight', hotset_size: hotset.length, duration_ms: 0 };
  }

  pdpHotsetPrewarmInFlight = true;
  pdpPrefetchStats.hotset_runs.started += 1;
  const startedAt = Date.now();
  try {
    await mapWithConcurrency(hotset, AURORA_BFF_PDP_HOTSET_PREWARM_CONCURRENCY, async (payload) => {
      await invokePdpCorePrefetch(payload, { logger, reason: reasonKey });
    });
    const durationMs = Date.now() - startedAt;
    pdpPrefetchStats.hotset_runs.completed += 1;
    pdpPrefetchStats.hotset_last = {
      at: new Date().toISOString(),
      reason: reasonKey,
      ok: true,
      skipped: false,
      duration_ms: durationMs,
      hotset_size: hotset.length,
    };
    return { ok: true, skipped: false, duration_ms: durationMs, hotset_size: hotset.length };
  } catch (err) {
    const durationMs = Date.now() - startedAt;
    const errMessage = err?.message || String(err);
    pdpPrefetchStats.hotset_runs.failed += 1;
    pdpPrefetchStats.hotset_last = {
      at: new Date().toISOString(),
      reason: reasonKey,
      ok: false,
      skipped: false,
      duration_ms: durationMs,
      hotset_size: hotset.length,
      error: String(errMessage).slice(0, 400),
    };
    logger?.warn(
      {
        reason: reasonKey,
        hotset_size: hotset.length,
        duration_ms: durationMs,
        err: errMessage,
      },
      'aurora bff: pdp hotset prewarm run failed',
    );
    return { ok: false, skipped: false, duration_ms: durationMs, hotset_size: hotset.length, error: errMessage };
  } finally {
    pdpHotsetPrewarmInFlight = false;
  }
}

function startPdpHotsetPrewarmLoop({ logger } = {}) {
  if (pdpHotsetPrewarmStarted) return;
  if (!AURORA_BFF_PDP_HOTSET_PREWARM_ENABLED || !PIVOTA_BACKEND_BASE_URL) return;
  const hotset = getNormalizedPdpHotsetPrewarmPayloads();
  if (!hotset.length) return;

  pdpHotsetPrewarmStarted = true;
  const waitMs = async (ms) => {
    const delay = Math.max(0, Number(ms) || 0);
    if (!delay) return;
    await new Promise((resolve) => {
      setTimeout(resolve, delay);
    });
  };

  const runOnce = async ({ reason = 'hotset_prewarm' } = {}) => {
    await runPdpHotsetPrewarmBatch({ logger, reason, allowWhenDisabled: false });
  };

  const runBootstrapBurst = async () => {
    for (let i = 0; i < AURORA_BFF_PDP_HOTSET_PREWARM_BOOTSTRAP_ROUNDS; i += 1) {
      const reason = i === 0 ? 'hotset_prewarm_startup' : 'hotset_prewarm_startup_followup';
      await runOnce({ reason });
      if (i < AURORA_BFF_PDP_HOTSET_PREWARM_BOOTSTRAP_ROUNDS - 1) {
        await waitMs(AURORA_BFF_PDP_HOTSET_PREWARM_BOOTSTRAP_GAP_MS);
      }
    }
  };

  setTimeout(() => {
    void runBootstrapBurst();
  }, AURORA_BFF_PDP_HOTSET_PREWARM_INITIAL_DELAY_MS);

  const timer = setInterval(() => {
    void runOnce({ reason: 'hotset_prewarm_interval' });
  }, AURORA_BFF_PDP_HOTSET_PREWARM_INTERVAL_MS);
  if (typeof timer.unref === 'function') timer.unref();
}

function buildRecoPdpQuickItem(item, { fastFallbackReasonCode = null } = {}) {
  const base = item && typeof item === 'object' && !Array.isArray(item) ? item : null;
  if (!base) return item;
  const skuCandidate =
    base.sku && typeof base.sku === 'object' && !Array.isArray(base.sku)
      ? base.sku
      : base.product && typeof base.product === 'object' && !Array.isArray(base.product)
        ? base.product
        : null;

  const {
    subjectProductGroupId,
    directProductRef,
    rawProductId,
  } = extractRecoPdpDirectKeys(base, skuCandidate);
  if (subjectProductGroupId) {
    return withRecoPdpMetadata(base, {
      path: 'group',
      subject: { type: 'product_group', id: subjectProductGroupId, product_group_id: subjectProductGroupId },
      canonicalProductRef: directProductRef,
      resolveAttempted: false,
      timeToPdpMs: 0,
    });
  }
  if (directProductRef) {
    return withRecoPdpMetadata(base, {
      path: 'ref',
      canonicalProductRef: directProductRef,
      resolveAttempted: false,
      timeToPdpMs: 0,
    });
  }

  const brand = pickFirstTrimmed(skuCandidate?.brand, base.brand);
  const name = pickFirstTrimmed(skuCandidate?.name, base.name);
  const displayName = pickFirstTrimmed(
    skuCandidate?.display_name,
    skuCandidate?.displayName,
    base.display_name,
    base.displayName,
    name,
  );
  const stableProductId = pickFirstTrimmed(
    rawProductId,
    skuCandidate?.product_id,
    skuCandidate?.productId,
    base?.product_id,
    base?.productId,
  );
  const stableSkuId = pickFirstTrimmed(
    skuCandidate?.sku_id,
    skuCandidate?.skuId,
    base?.sku_id,
    base?.skuId,
    stableProductId,
  );
  const stableQueryText = pickFirstTrimmed(
    brand && displayName ? joinBrandAndName(brand, displayName) : '',
    brand && name ? joinBrandAndName(brand, name) : '',
    displayName,
    name,
    stableSkuId,
    stableProductId,
  );
  const stableAliasMatch = resolveRecoStableAliasRefByQuery(stableQueryText);
  if (stableAliasMatch?.canonicalProductRef) {
    return withRecoPdpMetadata(base, {
      path: 'ref',
      canonicalProductRef: stableAliasMatch.canonicalProductRef,
      resolveAttempted: false,
      timeToPdpMs: 0,
    });
  }

  const queryText =
    buildProductInputText(skuCandidate || base, typeof base.url === 'string' ? base.url : null) ||
    pickFirstTrimmed(
      skuCandidate?.display_name,
      skuCandidate?.displayName,
      skuCandidate?.name,
      base.display_name,
      base.displayName,
      base.name,
      base.brand,
    );
  if (fastFallbackReasonCode) {
    recordRecoPdpExternalFallback(fastFallbackReasonCode);
  }
  return withRecoPdpMetadata(base, {
    path: 'external',
    queryText,
    resolveReasonCode: fastFallbackReasonCode,
    resolveAttempted: false,
    timeToPdpMs: 0,
  });
}

async function enrichRecommendationsWithPdpOpenContract({
  recommendations,
  logger,
  fastExternalFallbackReasonCode = null,
} = {}) {
  const recos = Array.isArray(recommendations) ? recommendations : [];
  if (!recos.length) {
    return {
      recommendations: recos,
      path_stats: { group: 0, ref: 0, resolve: 0, external: 0 },
      fail_reason_counts: { db_error: 0, upstream_timeout: 0, no_candidates: 0 },
      time_to_pdp_ms_stats: { count: 0, mean: 0, p50: 0, p90: 0, max: 0 },
    };
  }

  const fastFallbackReasonCode = normalizeResolveReasonCode(fastExternalFallbackReasonCode || '', null);
  const shouldApplyFastExternalFallback = Boolean(fastFallbackReasonCode && RECO_PDP_FAST_EXTERNAL_FALLBACK_ENABLED);
  if (fastFallbackReasonCode && !shouldApplyFastExternalFallback) {
    recordRecoPdpExternalFallbackBlocked(recos.length);
  }
  if (shouldApplyFastExternalFallback) {
    const fastExternal = recos.map((item) => buildRecoPdpQuickItem(item, { fastFallbackReasonCode }));
    schedulePdpCorePrefetchFromItems(fastExternal, {
      logger,
      reason: 'reco_card_fast_fallback',
    });
    return {
      recommendations: fastExternal,
      path_stats: tallyPdpOpenPathStats(fastExternal),
      fail_reason_counts: tallyResolveFailReasonCounts(fastExternal),
      time_to_pdp_ms_stats: summarizeTimeToPdpStats(fastExternal),
    };
  }

  const networkItemCap = Math.max(0, Math.min(recos.length, RECO_PDP_ENRICH_MAX_NETWORK_ITEMS));
  const allowLocalInvokeFallback = !RECO_PDP_CHAT_DISABLE_LOCAL_DOUBLE_HOP;
  const enriched = await mapWithConcurrency(recos, RECO_PDP_ENRICH_CONCURRENCY, async (item, idx) => {
    if (idx >= networkItemCap) return buildRecoPdpQuickItem(item, { fastFallbackReasonCode: null });
    return enrichRecoItemWithPdpOpenContract(item, { logger, allowLocalInvokeFallback });
  });
  const normalized = enriched.map((item, idx) => {
    if (item && typeof item === 'object' && !Array.isArray(item)) return item;
    return recos[idx];
  });
  schedulePdpCorePrefetchFromItems(normalized, {
    logger,
    reason: 'reco_card',
  });

  return {
    recommendations: normalized,
    path_stats: tallyPdpOpenPathStats(normalized),
    fail_reason_counts: tallyResolveFailReasonCounts(normalized),
    time_to_pdp_ms_stats: summarizeTimeToPdpStats(normalized),
  };
}

function coerceRecoItemForUi(item, { lang } = {}) {
  const base = item && typeof item === 'object' && !Array.isArray(item) ? item : null;
  if (!base) return item;

  const skuCandidate =
    base.sku && typeof base.sku === 'object' && !Array.isArray(base.sku)
      ? base.sku
      : base.product && typeof base.product === 'object' && !Array.isArray(base.product)
        ? base.product
        : null;

  const skuId =
    (skuCandidate && typeof skuCandidate.sku_id === 'string' ? skuCandidate.sku_id : null) ||
    (skuCandidate && typeof skuCandidate.skuId === 'string' ? skuCandidate.skuId : null) ||
    (typeof base.sku_id === 'string' ? base.sku_id : null) ||
    (typeof base.skuId === 'string' ? base.skuId : null) ||
    (skuCandidate && typeof skuCandidate.product_id === 'string' ? skuCandidate.product_id : null) ||
    (skuCandidate && typeof skuCandidate.productId === 'string' ? skuCandidate.productId : null) ||
    (typeof base.product_id === 'string' ? base.product_id : null) ||
    (typeof base.productId === 'string' ? base.productId : null) ||
    null;

  const productId =
    (skuCandidate && typeof skuCandidate.product_id === 'string' ? skuCandidate.product_id : null) ||
    (skuCandidate && typeof skuCandidate.productId === 'string' ? skuCandidate.productId : null) ||
    (typeof base.product_id === 'string' ? base.product_id : null) ||
    (typeof base.productId === 'string' ? base.productId : null) ||
    null;

  const brand =
    (skuCandidate && typeof skuCandidate.brand === 'string' ? skuCandidate.brand.trim() : '') ||
    (typeof base.brand === 'string' ? base.brand.trim() : '') ||
    '';
  const name =
    (skuCandidate && typeof skuCandidate.name === 'string' ? skuCandidate.name.trim() : '') ||
    (typeof base.name === 'string' ? base.name.trim() : '') ||
    '';
  const displayName =
    (skuCandidate && typeof skuCandidate.display_name === 'string' ? skuCandidate.display_name.trim() : '') ||
    (skuCandidate && typeof skuCandidate.displayName === 'string' ? skuCandidate.displayName.trim() : '') ||
    (typeof base.display_name === 'string' ? base.display_name.trim() : '') ||
    (typeof base.displayName === 'string' ? base.displayName.trim() : '') ||
    name ||
    '';
  const category =
    (skuCandidate && typeof skuCandidate.category === 'string' ? skuCandidate.category.trim() : '') ||
    (typeof base.category === 'string' ? base.category.trim() : '') ||
    '';

  const slotRaw = typeof base.slot === 'string' ? base.slot.trim().toLowerCase() : '';
  const slot = slotRaw === 'am' || slotRaw === 'pm' ? slotRaw : 'other';
  const step =
    (typeof base.step === 'string' && base.step.trim()) ||
    (typeof base.category === 'string' && base.category.trim()) ||
    category ||
    (String(lang || '').toUpperCase() === 'CN' ? '推荐' : 'Recommendation');

  const notesRaw =
    Array.isArray(base.notes) ? base.notes
      : Array.isArray(base.reasons) ? base.reasons
        : Array.isArray(base.why) ? base.why
          : typeof base.reason === 'string' ? [base.reason]
            : typeof base.why === 'string' ? [base.why]
              : [];

  const notes = Array.isArray(notesRaw)
    ? notesRaw
      .map((v) => (typeof v === 'string' ? v.trim() : v == null ? '' : String(v).trim()))
      .filter(Boolean)
      .slice(0, 8)
    : [];

  const nextSku = skuCandidate || skuId || productId || brand || name || displayName || category
    ? {
      ...(skuCandidate && typeof skuCandidate === 'object' ? skuCandidate : {}),
      ...(skuId ? { sku_id: skuId } : {}),
      ...(productId ? { product_id: productId } : {}),
      ...(brand ? { brand } : {}),
      ...(name ? { name } : {}),
      ...(displayName ? { display_name: displayName } : {}),
      ...(category ? { category } : {}),
    }
    : null;

  return {
    ...base,
    slot,
    step,
    ...(nextSku ? { sku: nextSku } : {}),
    ...(notes.length ? { notes } : {}),
  };
}

const LOW_CONF_TREATMENT_TOKEN_RE = /\b(treatment|retinol|retinoid|retinal|tretinoin|adapalene|exfoliant|chemical peel|aha|bha|pha|glycolic|salicylic|mandelic|lactic)\b|(?:视黄醇|阿达帕林|维a|果酸|水杨酸|杏仁酸|乳酸|焕肤|去角质|刷酸)/i;
const MEDIUM_CONFIDENCE_UPPER_BOUND = 0.75;
const LOW_CONF_NON_TREATMENT_SLOTS = new Set(['cleanser', 'moisturizer', 'sunscreen', 'toner', 'optional']);

function normalizeRoutineSlotToken(raw) {
  const token = String(raw || '').trim().toLowerCase();
  if (!token) return '';
  if (token === 'treatment') return 'treatment';
  if (LOW_CONF_NON_TREATMENT_SLOTS.has(token)) return token;
  return '';
}

function isTreatmentLikeRecommendationForLowConfidence(item) {
  const base = isPlainObject(item) ? item : null;
  if (!base) return false;

  const sku = isPlainObject(base.sku)
    ? base.sku
    : isPlainObject(base.product)
      ? base.product
      : null;

  // Trust explicit matcher slot labels first so non-treatment slots are not over-filtered by keyword matches.
  const explicitSlot = normalizeRoutineSlotToken(base.routine_slot || base.routineSlot);
  if (explicitSlot) return explicitSlot === 'treatment';

  const textCandidates = [
    base.step,
    base.slot_step,
    base.slotStep,
    base.category,
    base.product_type,
    base.productType,
    base.name,
    base.display_name,
    base.displayName,
    sku && sku.category,
    sku && sku.name,
    sku && sku.display_name,
    sku && sku.displayName,
    sku && sku.product_type,
    sku && sku.productType,
  ];

  const listCandidates = [
    ...(Array.isArray(base.notes) ? base.notes : []),
    ...(Array.isArray(base.reasons) ? base.reasons : []),
    ...(Array.isArray(base.why) ? base.why : []),
    ...(Array.isArray(base.key_actives) ? base.key_actives : []),
    ...(Array.isArray(base.keyActives) ? base.keyActives : []),
    ...(Array.isArray(base.active_ingredients) ? base.active_ingredients : []),
    ...(Array.isArray(base.activeIngredients) ? base.activeIngredients : []),
    ...(sku && Array.isArray(sku.key_actives) ? sku.key_actives : []),
    ...(sku && Array.isArray(sku.keyActives) ? sku.keyActives : []),
    ...(sku && Array.isArray(sku.active_ingredients) ? sku.active_ingredients : []),
    ...(sku && Array.isArray(sku.activeIngredients) ? sku.activeIngredients : []),
  ];

  const flattened = [...textCandidates, ...listCandidates]
    .map((value) => (typeof value === 'string' ? value.trim() : value == null ? '' : String(value).trim()))
    .filter(Boolean)
    .slice(0, 40);

  return flattened.some((token) => LOW_CONF_TREATMENT_TOKEN_RE.test(token));
}

function applyLowConfidenceRecoGuard(payload) {
  const base = isPlainObject(payload) ? { ...payload } : {};
  const recommendations = Array.isArray(base.recommendations) ? base.recommendations : [];
  if (!recommendations.length) {
    return { payload: base, filteredCount: 0, totalCount: 0 };
  }

  const filtered = [];
  let filteredCount = 0;
  for (const row of recommendations) {
    if (isTreatmentLikeRecommendationForLowConfidence(row)) {
      filteredCount += 1;
      continue;
    }
    filtered.push(row);
  }

  return {
    payload: {
      ...base,
      recommendations: filtered,
    },
    filteredCount,
    totalCount: recommendations.length,
  };
}

function isLowOrMediumConfidenceLevelToken(raw) {
  const token = String(raw || '').trim().toLowerCase();
  return token === 'low' || token === 'medium';
}

function isLowOrMediumConfidenceScore(raw) {
  const score = Number(raw);
  if (!Number.isFinite(score)) return false;
  return score <= MEDIUM_CONFIDENCE_UPPER_BOUND;
}

function isLowOrMediumConfidenceNode(node) {
  if (!isPlainObject(node)) return false;
  if (isLowOrMediumConfidenceLevelToken(node.level)) return true;
  if (isLowOrMediumConfidenceScore(node.score)) return true;
  return false;
}

function envelopeRequiresConservativeRecoGuard(envelope) {
  const base = isPlainObject(envelope) ? envelope : {};
  const cards = Array.isArray(base.cards) ? base.cards : [];
  const events = Array.isArray(base.events) ? base.events : [];

  for (const card of cards) {
    if (!isPlainObject(card)) continue;
    const type = String(card.type || '').trim().toLowerCase();
    const payload = isPlainObject(card.payload) ? card.payload : {};
    if (type === 'confidence_notice' && String(payload.reason || '').trim().toLowerCase() === 'low_confidence') {
      return true;
    }
    if (isLowOrMediumConfidenceNode(payload.confidence)) return true;
    if (isLowOrMediumConfidenceLevelToken(payload.recommendation_confidence_level)) return true;
    if (isLowOrMediumConfidenceScore(payload.recommendation_confidence_score)) return true;
  }

  for (const evt of events) {
    if (!isPlainObject(evt)) continue;
    const data = isPlainObject(evt.data) ? evt.data : {};
    if (String(evt.event_name || '').trim() === 'recos_requested') {
      if (data.low_confidence === true) return true;
      if (isLowOrMediumConfidenceLevelToken(data.confidence_level)) return true;
      if (isLowOrMediumConfidenceScore(data.confidence_score)) return true;
    }
  }

  return false;
}

function pickConfidenceNodeForConservativeRecoFallback(envelope) {
  const base = isPlainObject(envelope) ? envelope : {};
  const cards = Array.isArray(base.cards) ? base.cards : [];
  for (const card of cards) {
    if (!isPlainObject(card)) continue;
    const payload = isPlainObject(card.payload) ? card.payload : null;
    if (!payload) continue;
    if (isLowOrMediumConfidenceNode(payload.confidence)) {
      return payload.confidence;
    }
  }
  return { score: LOW_CONFIDENCE_THRESHOLD, level: 'medium', rationale: ['low_medium_reco_policy'] };
}

function buildConservativeRecoNoticeCard({ ctx, language, confidence, details } = {}) {
  return {
    card_id: `conf_${ctx && ctx.request_id ? ctx.request_id : Date.now()}_low_medium`,
    type: 'confidence_notice',
    payload: buildConfidenceNoticeCardPayload({
      language,
      reason: 'low_confidence',
      confidence,
      actions: ['upload_daylight_and_indoor_white', 'update_current_routine', 'retry_recommendations'],
      details: Array.isArray(details) ? details : [],
    }),
  };
}

