function buildLowMediumSafeFallbackRecommendations({ language } = {}) {
  const isCN = String(language || '').toUpperCase() === 'CN';
  return LOW_MEDIUM_SAFE_RECO_FALLBACK_TEMPLATES.map((template, idx) => {
    const locale = isCN ? template.cn : template.en;
    const name = String(locale && locale.name ? locale.name : '').trim();
    const step = String(locale && locale.step ? locale.step : template.category || 'Recommendation').trim();
    const reasons = Array.isArray(locale && locale.reasons)
      ? locale.reasons.map((row) => String(row || '').trim()).filter(Boolean).slice(0, 4)
      : [];
    const stableKey = String(template.key || `fallback_${idx + 1}`).trim().toLowerCase();
    const productId = `safe_fallback_${stableKey}_${idx + 1}`;

    return coerceRecoItemForUi(
      {
        slot: template.slot,
        routine_slot: template.routine_slot,
        category: template.category,
        step,
        score: Number.isFinite(Number(template.score)) ? Number(template.score) : 70,
        confidence: { score: 0.55, level: 'medium', rationale: ['low_medium_safe_product_fallback'] },
        reasons,
        metadata: { fallback_type: 'low_medium_safe_product' },
        sku: {
          sku_id: productId,
          product_id: productId,
          brand: isCN ? '稳妥基线' : 'Safe Baseline',
          name,
          display_name: name,
          category: template.category,
        },
      },
      { lang: isCN ? 'CN' : 'EN' },
    );
  })
    .map((item) => buildRecoPdpQuickItem(item, { fastFallbackReasonCode: 'no_candidates' }))
    .slice(0, 3);
}

function hasRenderableRecommendationsCard(cards) {
  return (Array.isArray(cards) ? cards : []).some((card) => {
    if (!isPlainObject(card)) return false;
    if (String(card.type || '').trim().toLowerCase() !== 'recommendations') return false;
    const payload = isPlainObject(card.payload) ? card.payload : {};
    return Array.isArray(payload.recommendations) && payload.recommendations.length > 0;
  });
}

function isRecoRequestFlowFromEvents(events) {
  return (Array.isArray(events) ? events : []).some((evt) => {
    if (!isPlainObject(evt)) return false;
    return String(evt.event_name || '').trim() === 'recos_requested';
  });
}

function buildLowMediumSafeFallbackRecoCard({
  ctx,
  language,
  sourcePayload,
  sourceFieldMissing,
  fallbackRecommendationMeta,
} = {}) {
  const recommendations = buildLowMediumSafeFallbackRecommendations({ language });
  if (!recommendations.length) return null;

  const srcPayload = isPlainObject(sourcePayload) ? sourcePayload : {};
  const srcMeta = isPlainObject(srcPayload.metadata) ? srcPayload.metadata : {};
  const payload = {
    ...srcPayload,
    recommendations,
    metadata: {
      ...srcMeta,
      pdp_open_path_stats: tallyPdpOpenPathStats(recommendations),
      resolve_fail_reason_counts: tallyResolveFailReasonCounts(recommendations),
      time_to_pdp_ms_stats: summarizeTimeToPdpStats(recommendations),
      low_medium_safe_fallback: true,
    },
    ...(isPlainObject(fallbackRecommendationMeta) ? { recommendation_meta: fallbackRecommendationMeta } : {}),
  };

  return {
    card_id: `reco_${ctx && ctx.request_id ? ctx.request_id : Date.now()}_safe_fallback`,
    type: 'recommendations',
    payload,
    field_missing: mergeFieldMissing(sourceFieldMissing, [
      { field: 'recommendations', reason: 'low_medium_safe_product_fallback' },
    ]),
  };
}

function applyLowOrMediumRecoGuardToEnvelope({ envelope, ctx, language } = {}) {
  const baseEnvelope = isPlainObject(envelope)
    ? {
        ...envelope,
        cards: Array.isArray(envelope.cards) ? envelope.cards.slice() : [],
        events: Array.isArray(envelope.events) ? envelope.events.slice() : [],
      }
    : {
        assistant_message: null,
        suggested_chips: [],
        cards: [],
        session_patch: {},
        events: [],
      };

  if (!envelopeRequiresConservativeRecoGuard(baseEnvelope)) {
    return { envelope: baseEnvelope, applied: false, filteredCount: 0, totalCount: 0, fallbackApplied: false };
  }

  const nextCards = [];
  let filteredCount = 0;
  let totalCount = 0;
  let fallbackRecoSourcePayload = null;
  let fallbackRecoSourceFieldMissing = null;
  for (const card of baseEnvelope.cards) {
    if (!isPlainObject(card)) {
      nextCards.push(card);
      continue;
    }
    const payload = isPlainObject(card.payload) ? card.payload : null;
    if (!payload || !Array.isArray(payload.recommendations)) {
      nextCards.push(card);
      continue;
    }

    const guarded = applyLowConfidenceRecoGuard(payload);
    filteredCount += guarded.filteredCount;
    totalCount += guarded.totalCount;

    const nextPayload = guarded.payload;
    if (!fallbackRecoSourcePayload) fallbackRecoSourcePayload = nextPayload;
    if (!fallbackRecoSourceFieldMissing) fallbackRecoSourceFieldMissing = card.field_missing;
    const nextRecs = Array.isArray(nextPayload.recommendations) ? nextPayload.recommendations : [];
    const nextCard = {
      ...card,
      payload: nextPayload,
      ...(guarded.filteredCount > 0
        ? {
            field_missing: mergeFieldMissing(card.field_missing, [
              { field: 'recommendations', reason: 'low_confidence_treatment_filtered' },
            ]),
          }
        : {}),
    };

    if (nextRecs.length > 0) {
      nextCards.push(nextCard);
      continue;
    }
    const cardType = String(card.type || '').trim().toLowerCase();
    if (cardType !== 'recommendations') nextCards.push(nextCard);
  }

  let finalCards = nextCards;
  let safeRecoFallbackApplied = false;
  let noticeFallbackApplied = false;
  let hasReco = hasRenderableRecommendationsCard(finalCards);
  const isRecoRequestFlow = isRecoRequestFlowFromEvents(baseEnvelope.events);

  if (!hasReco && isRecoRequestFlow) {
    const safeRecoCard = buildLowMediumSafeFallbackRecoCard({
      ctx,
      language,
      sourcePayload: fallbackRecoSourcePayload,
      sourceFieldMissing: fallbackRecoSourceFieldMissing,
      fallbackRecommendationMeta: isPlainObject(baseEnvelope.recommendation_meta) ? baseEnvelope.recommendation_meta : null,
    });
    if (safeRecoCard) {
      finalCards = [...finalCards, safeRecoCard];
      safeRecoFallbackApplied = true;
      hasReco = true;
    }
  }

  if (!hasReco && filteredCount > 0) {
    const hasLowConfidenceNotice = finalCards.some((card) => {
      if (!isPlainObject(card)) return false;
      if (String(card.type || '').trim().toLowerCase() !== 'confidence_notice') return false;
      const payload = isPlainObject(card.payload) ? card.payload : {};
      return String(payload.reason || '').trim().toLowerCase() === 'low_confidence';
    });
    if (!hasLowConfidenceNotice) {
      finalCards = [
        ...finalCards,
        buildConservativeRecoNoticeCard({
          ctx,
          language,
          confidence: pickConfidenceNodeForConservativeRecoFallback(baseEnvelope),
          details: ['low_medium_treatment_filtered_all'],
        }),
      ];
      noticeFallbackApplied = true;
    }
  }

  const fallbackApplied = safeRecoFallbackApplied || noticeFallbackApplied;
  const applied = filteredCount > 0 || fallbackApplied;
  if (!applied) {
    return { envelope: baseEnvelope, applied: false, filteredCount: 0, totalCount, fallbackApplied: false };
  }

  const nextEvents = Array.isArray(baseEnvelope.events) ? baseEnvelope.events.slice(0, 64) : [];
  nextEvents.push(
    makeEvent(ctx || {}, 'reco_low_medium_treatment_filtered', {
      filtered_count: filteredCount,
      total_count: totalCount,
      fallback_applied: fallbackApplied,
      safe_reco_fallback_applied: safeRecoFallbackApplied,
      notice_fallback_applied: noticeFallbackApplied,
    }),
  );

  return {
    envelope: {
      ...baseEnvelope,
      cards: finalCards,
      events: nextEvents,
    },
    applied,
    filteredCount,
    totalCount,
    fallbackApplied,
    safeRecoFallbackApplied,
    noticeFallbackApplied,
  };
}

function buildAuroraRoutineQuery({ profile, focus, constraints, lang }) {
  const skinType = profile && typeof profile.skinType === 'string' ? profile.skinType : 'unknown';
  const barrierStatus = mapBarrierStatus(profile && profile.barrierStatus);
  const concerns = mapConcerns(profile && profile.goals);
  const region = profile && typeof profile.region === 'string' && profile.region.trim() ? profile.region.trim() : 'US';
  const budgetKnown = normalizeBudgetHint(profile && profile.budgetTier) || normalizeBudgetHint(constraints && constraints.budget) || '';
  const budget = budgetKnown || 'unknown';
  const goal = typeof focus === 'string' && focus.trim()
    ? focus.trim()
    : constraints && typeof constraints.goal === 'string' && constraints.goal.trim()
      ? constraints.goal.trim()
      : 'balanced routine';
  const preference = constraints && typeof constraints.preference === 'string' && constraints.preference.trim()
    ? constraints.preference.trim()
    : 'No special preference';

  const concernsStr = concerns.length ? concerns.join(', ') : 'none';
  const reply = lang === 'CN' ? 'Chinese' : 'English';
  const budgetRule = budgetKnown
    ? 'Budget is provided; keep product picks close to this budget band.'
    : 'Budget is unknown; provide a balanced-value baseline first and do not ask budget in the first response unless user explicitly asks to optimize by budget.';

  const productsNote = profile && profile.currentRoutine ? `Current routine: ${JSON.stringify(profile.currentRoutine).slice(0, 1000)}\n` : '';

  return (
    `User profile: skin type ${skinType}; barrier status: ${barrierStatus}; concerns: ${concernsStr}; region: ${region}; budget: ${budget}.\n` +
    `Goal: ${goal}.\n` +
    `${productsNote}` +
    `Preference: ${preference}.\n` +
    `${budgetRule}\n` +
    `Please recommend a simple AM/PM skincare routine. Reply in ${reply}.`
  );
}

function buildAuroraProductRecommendationsQuery({ profile, requestText, lang }) {
  const skinType = profile && typeof profile.skinType === 'string' ? profile.skinType : 'unknown';
  const barrierStatus = mapBarrierStatus(profile && profile.barrierStatus);
  const concerns = mapConcerns(profile && profile.goals);
  const region = profile && typeof profile.region === 'string' && profile.region.trim() ? profile.region.trim() : 'US';
  const budgetKnown = normalizeBudgetHint(profile && profile.budgetTier) || '';
  const budget = budgetKnown || 'unknown';
  const concernsStr = concerns.length ? concerns.join(', ') : 'none';
  const replyLang = lang === 'CN' ? 'Chinese' : 'English';
  const req = typeof requestText === 'string' ? requestText.trim() : '';
  const budgetReasonRule = budgetKnown
    ? 'If budget is known, include one reason that references budget fit.'
    : 'If budget is unknown, do not ask budget in the first response; focus on efficacy/tolerance and balanced value.';

  return (
    `User profile: skin type ${skinType}; barrier status: ${barrierStatus}; concerns: ${concernsStr}; region: ${region}; budget: ${budget}.\n` +
    (req ? `User request: ${req}\n` : '') +
    `Task: Generate skincare product picks (NOT a full AM/PM routine).\n` +
    `Return ONLY a JSON object with keys: recommendations (array), evidence (object), confidence (0..1), missing_info (string[]), warnings (string[]).\n` +
    `recommendations: up to 5 items, ranked.\n` +
    `Each recommendation item MUST include:\n` +
    `- slot: "other"\n` +
    `- step: category label (cleanser/sunscreen/treatment/moisturizer/other)\n` +
    `- score: integer 0..100 (fit score)\n` +
    `- sku: {brand,name,display_name,sku_id,product_id,category,availability(string[]),price{usd,cny,unknown}}\n` +
    `- reasons: string[] (max 4). Reasons must be end-user readable and user-specific.\n` +
    `  - Include at least one reason that explicitly references the user's profile (skin type / sensitivity / barrier / goals).\n` +
    `  - ${budgetReasonRule}\n` +
    `  - If recent_logs were provided, include one reason that references the last 7 days trend; otherwise add warnings: "recent_logs_missing".\n` +
    `  - If profile.itinerary (upcoming plan/travel context) is available, include one reason that references it.\n` +
    `  - If upcoming plan/travel context is not available, add warnings: "itinerary_unknown" (do NOT guess).\n` +
    `- evidence_pack: {keyActives,sensitivityFlags,pairingRules,comparisonNotes,citations} (omit unknown keys; do NOT fabricate).\n` +
    `- missing_info: string[] (per-item; ONLY user-provided fields like budget_unknown)\n` +
    `- warnings: string[] (per-item; quality signals like over_budget/price_unknown/recent_logs_missing)\n` +
    `Rules:\n` +
    `- Do NOT include checkout links.\n` +
    `- Do NOT recommend the exact same sku_id/product_id twice.\n` +
    `- If unsure, use null/unknown and list missing_info/warnings (do not fabricate).\n` +
    `- All free-text strings should be in ${replyLang}.\n`
  );
}

function looksLikeRoutineRequest(message, action) {
  const text = String(message || '').trim().toLowerCase();
  const id =
    typeof action === 'string'
      ? action
      : action && typeof action === 'object'
        ? action.action_id
        : '';
  const idText = String(id || '').trim().toLowerCase();

  const routineByAction = idText.includes('routine') || idText.includes('reco_routine');
  const routineByMessage =
    Boolean(text) &&
    (text.includes('routine') ||
      /am\s*\/\s*pm/.test(text) ||
      /生成.*(早晚|am|pm).*(护肤|routine)/.test(text) ||
      /(早晚护肤|护肤方案)/.test(text));

  // Guard against stale UI action_id leakage: when user typed a non-routine message,
  // do not let a previous routine chip/action force routine routing.
  if (routineByAction && text && !routineByMessage) return false;

  if (routineByAction) return true;
  return routineByMessage;
}

function looksLikeIngredientScienceIntent(message, action) {
  const raw = String(message || '').trim();
  const text = raw.toLowerCase();
  const id =
    typeof action === 'string'
      ? action
      : action && typeof action === 'object'
        ? action.action_id
        : '';
  const idText = String(id || '').trim().toLowerCase();

  if (idText === 'chip.start.ingredients' || idText === 'chip_start_ingredients') return true;

  const en =
    /\b(ingredient|ingredients|active|actives)\b.{0,28}\b(science|evidence|mechanism|clinical|study|paper|citation|citations)\b/i.test(raw) ||
    /\b(science|evidence|mechanism|clinical|study|paper|citation|citations)\b.{0,28}\b(ingredient|ingredients|active|actives)\b/i.test(raw);
  const cn = /(成分(机理|机制|科学|证据|原理)|证据链|循证|临床证据|论文证据|问成分)/.test(raw);
  return en || cn;
}

function messageContainsSpecificIngredientScienceTarget(message) {
  const raw = String(message || '').trim();
  if (!raw) return false;
  const lower = raw.toLowerCase();
  const language = /[\u4e00-\u9fff]/.test(raw) ? 'CN' : 'EN';
  if (extractKnownActivesFromText(raw, language).length > 0) return true;
  const conceptHits = collectConceptIdsFromText({ text: raw, language, max: 24, includeSubstring: true });
  if (
    conceptHits.some((conceptId) => {
      const id = String(conceptId || '').trim().toUpperCase();
      return /(RETINO|AHA|BHA|PHA|HYDROQUINONE|BENZOYL|SALICYLIC|GLYCOLIC|LACTIC|MANDELIC|AZELAIC|TRANEXAMIC|NIACINAMIDE|VITAMIN_C|ASCORBIC|CERAMIDE|PEPTIDE|ARBUTIN|ISOTRETINOIN|EXFOLIANT|CHEMICAL_PEEL|SUNSCREEN)/.test(id);
    })
  ) {
    return true;
  }
  if (matchIngredientOntology({ text: raw, language, max: 8 }).length > 0) return true;

  const specificIngredient =
    /\b(niacinamide|retinol|retinoid|adapalene|tretinoin|vitamin\s*c|ascorbic|azelaic|salicylic|glycolic|mandelic|pha|ceramide|peptide|tranexamic|arbutin)\b/i
      .test(lower) ||
    /(烟酰胺|a醇|维a|阿达帕林|维c|维生素c|壬二酸|水杨酸|果酸|杏仁酸|神经酰胺|多肽|胜肽|传明酸|熊果苷)/.test(raw);
  if (specificIngredient) return true;

  const specificEffect =
    /\b(acne|breakout|redness|sensitive|dark spots?|hyperpigmentation|brightening|pores?|anti[-\s]?aging|wrinkles?|barrier|irritation)\b/i.test(lower) ||
    /(痘|闭口|泛红|敏感|淡斑|色沉|提亮|毛孔|抗老|细纹|屏障|刺激|刺痛|修护)/.test(raw);
  return specificEffect;
}

